> **Note:** This implementation handles standard ASCII vowels (`a, e, i, o, u`). If you need to support accented vowels (e.g., `é, ü, ñ`), you would need Unicode normalization libraries like `unicode-normalization`.

# Stack Data Structure in Rust

Here's a complete, idiomatic Rust implementation of a stack data structure with comprehensive functionality and tests.

```rust
#[derive(Debug)]
pub struct Stack<T> {
    elements: Vec<T>,
    capacity: Option<usize>,
}

#[derive(Debug, PartialEq)]
pub enum StackError {
    Overflow,
    Underflow,
    Empty,
}

impl std::fmt::Display for StackError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            StackError::Overflow => write!(f, "Stack overflow: capacity exceeded"),
            StackError::Underflow => write!(f, "Stack underflow: cannot pop from empty stack"),
            StackError::Empty => write!(f, "Stack is empty"),
        }
    }
}

impl std::error::Error for StackError {}

impl<T> Stack<T> {
    /// Creates a new unbounded stack.
    pub fn new() -> Self {
        Stack {
            elements: Vec::new(),
            capacity: None,
        }
    }

    /// Creates a new stack with a fixed capacity.
    pub fn with_capacity(capacity: usize) -> Self {
        Stack {
            elements: Vec::with_capacity(capacity),
            capacity: Some(capacity),
        }
    }

    /// Pushes an element onto the top of the stack.
    /// Returns `StackError::Overflow` if the stack is at capacity.
    pub fn push(&mut self, value: T) -> Result<(), StackError> {
        if let Some(cap) = self.capacity {
            if self.elements.len() >= cap {
                return Err(StackError::Overflow);
            }
        }
        self.elements.push(value);
        Ok(())
    }

    /// Removes and returns the top element.
    /// Returns `StackError::Underflow` if the stack is empty.
    pub fn pop(&mut self) -> Result<T, StackError> {
        self.elements.pop().ok_or(StackError::Underflow)
    }

    /// Returns a reference to the top element without removing it.
    /// Returns `StackError::Empty` if the stack is empty.
    pub fn peek(&self) -> Result<&T, StackError> {
        self.elements.last().ok_or(StackError::Empty)
    }

    /// Returns a mutable reference to the top element without removing it.
    pub fn peek_mut(&mut self) -> Result<&mut T, StackError> {
        self.elements.last_mut().ok_or(StackError::Empty)
    }

    /// Returns `true` if the stack contains no elements.
    pub fn is_empty(&self) -> bool {
        self.elements.is_empty()
    }

    /// Returns the number of elements currently in the stack.
    pub fn size(&self) -> usize {
        self.elements.len()
    }

    /// Returns the maximum capacity, if one was set.
    pub fn capacity(&self) -> Option<usize> {
        self.capacity
    }

    /// Removes all elements from the stack.
    pub fn clear(&mut self) {
        self.elements.clear();
    }

    /// Returns `true` if the stack contains the given value.
    pub fn contains(&self, value: &T) -> bool
    where
        T: PartialEq,
    {
        self.elements.contains(value)
    }

    /// Returns an iterator over the stack from top to bottom.
    pub fn iter(&self) -> impl Iterator<Item = &T> {
        self.elements.iter().rev()
    }

    /// Converts the stack into a `Vec<T>`, ordered from top to bottom.
    pub fn into_vec(self) -> Vec<T> {
        let mut v = self.elements;
        v.reverse();
        v
    }
}

impl<T> Default for Stack<T> {
    fn default() -> Self {
        Stack::new()
    }
}

impl<T: Clone> Stack<T> {
    /// Creates a stack from a slice, where the last element becomes the top.
    pub fn from_slice(slice: &[T]) -> Self {
        Stack {
            elements: slice.to_vec(),
            capacity: None,
        }
    }
}

impl<T> From<Vec<T>> for Stack<T> {
    /// Creates a stack from a `Vec<T>`.
    /// The last element of the vector becomes the top of the stack.
    fn from(vec: Vec<T>) -> Self {
        Stack {
            elements: vec,
            capacity: None,
        }
    }
}

impl<T: std::fmt::Display> std::fmt::Display for Stack<T> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Stack (top → bottom): [")?;
        let mut iter = self.elements.iter().rev().peekable();
        while let Some(item) = iter.next() {
            write!(f, "{}", item)?;
            if iter.peek().is_some() {
                write!(f, ", ")?;
            }
        }
        write!(f, "]")
    }
}

// ─── Example Applications ────────────────────────────────────────────────────

/// Checks whether the brackets in a string are balanced.
pub fn is_balanced(s: &str) -> bool {
    let mut stack = Stack::new();
    for ch in s.chars() {
        match ch {
            '(' | '[' | '{' => stack.push(ch).unwrap(),
            ')' => {
                if stack.pop() != Ok('(') {
                    return false;
                }
            }
            ']' => {
                if stack.pop() != Ok('[') {
                    return false;
                }
            }
            '}' => {
                if stack.pop() != Ok('{') {
                    return false;
                }
            }
            _ => {}
        }
    }
    stack.is_empty()
}

/// Evaluates a Reverse Polish Notation (RPN) expression.
pub fn evaluate_rpn(tokens: &[&str]) -> Result<f64, String> {
    let mut stack: Stack<f64> = Stack::new();

    for &token in tokens {
        match token {
            "+" | "-" | "*" | "/" => {
                let b = stack.pop().map_err(|e| e.to_string())?;
                let a = stack.pop().map_err(|e| e.to_string())?;
                let result = match token {
                    "+" => a + b,
                    "-" => a - b,
                    "*" => a * b,
                    "/" => {
                        if b == 0.0 {
                            return Err("Division by zero".to_string());
                        }
                        a / b
                    }
                    _ => unreachable!(),
                };
                stack.push(result).unwrap();
            }
            num => {
                let n = num.parse::<f64>().map_err(|e| e.to_string())?;
                stack.push(n).unwrap();
            }
        }
    }

    stack.pop().map_err(|e| e.to_string())
}

