Here's a complete Rust implementation with multiple approaches:

```rust
fn main() {
    // Test all implementations
    println!("=== Fibonacci Implementations ===\n");

    // Recursive (small numbers only)
    println!("Recursive:");
    for i in 0..=10 {
        print!("{} ", fib_recursive(i));
    }
    println!();

    // Iterative
    println!("\nIterative:");
    for i in 0..=10 {
        print!("{} ", fib_iterative(i));
    }
    println!();

    // Memoized
    println!("\nMemoized:");
    for i in 0..=10 {
        print!("{} ", fib_memoized(i));
    }
    println!();

    // Iterator (first 11 values)
    println!("\nIterator:");
    let fibs: Vec<u64> = FibIterator::new().take(11).collect();
    println!("{:?}", fibs);

    // Large number example
    println!("\nLarge number (n=50): {}", fib_iterative(50));
