/// Recursive approach — simple but exponential time O(2^n)
fn fib_recursive(n: u64) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => fib_recursive(n - 1) + fib_recursive(n - 2),
    }
}

/// Iterative approach — O(n) time, O(1) space (recommended)
fn fib_iterative(n: u64) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => {
            let (mut a, mut b) = (0u64, 1u64);
            for _ in 2..=n {
                (a, b) = (b, a + b);
            }
            b
        }
    }
}

/// Memoized recursive approach — O(n) time, O(n) space
fn fib_memoized(n: u64) -> u64 {
    let mut memo = vec![None; (n as usize) + 1];
    fib_memo_helper(n, &mut memo)
}

fn fib_memo_helper(n: u64, memo: &mut Vec<Option<u64>>) -> u64 {
    if let Some(val) = memo[n as usize] {
        return val;
    }
    let result = match n {
        0 => 0,
        1 => 1,
        _ => fib_memo_helper(n - 1, memo) + fib_memo_helper(n - 2, memo),
    };
    memo[n as usize] = Some(result);
    result
}

/// Fibonacci iterator — lazily generates the sequence
struct FibIterator {
    a: u64,
    b: u64,
}

impl FibIterator {
    fn new() -> Self {
        FibIterator { a: 0, b: 1 }
    }
}

impl Iterator for FibIterator {
    type Item = u64;

    fn next(&mut self) -> Option<Self::Item> {
        let next = self.a;
        (self.a, self.b) = (self.b, self.a + self.b);
        Some(next) // Infinite iterator; use .take(n) to limit
    }
}

