## How It Works

| Component | Description |
|-----------|-------------|
| `NestedList<T>` | Recursive enum: either a `Value(T)` or a `List` of more `NestedList<T>` |
| `flatten()` | Public method that returns a `Vec<T>` |
| `flatten_into()` | Private helper that appends into an existing `Vec` (avoids repeated allocations) |
| `flatten_nested()` | Convenience function for flattening a slice of `NestedList` items |

## Key Design Decisions

- **Generic over `T: Clone`** — works with any cloneable type
- **Recursive enum** — naturally models arbitrarily deep nesting
- **Helper accumulator pattern** — `flatten_into` avoids creating intermediate `Vec`s and concatenating them, which is more efficient
- **Recursive traversal** — clean and idiomatic for tree-like structures

# LRU Cache Implementation in Rust

## Overview

I'll implement an LRU (Least Recently Used) cache using a **HashMap** combined with a **doubly linked list**. The linked list maintains access order, while the HashMap provides O(1) lookups.

## Implementation

```rust
use std::collections::HashMap;
use std::hash::Hash;
use std::fmt;

/// A node in the doubly linked list
struct Node<K, V> {
    key: K,
    value: V,
    prev: Option<*mut Node<K, V>>,
    next: Option<*mut Node<K, V>>,
}

impl<K, V> Node<K, V> {
    fn new(key: K, value: V) -> Self {
        Node {
            key,
            value,
            prev: None,
            next: None,
        }
    }
}

/// LRU Cache with O(1) get and put operations
pub struct LruCache<K, V> {
    capacity: usize,
    map: HashMap<K, *mut Node<K, V>>,
    head: Option<*mut Node<K, V>>, // Most recently used
    tail: Option<*mut Node<K, V>>, // Least recently used
}

impl<K: Eq + Hash + Clone, V> LruCache<K, V> {
    /// Create a new LRU cache with the given capacity
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0, "Capacity must be greater than zero");
        LruCache {
            capacity,
            map: HashMap::with_capacity(capacity),
            head: None,
            tail: None,
        }
    }

    /// Returns the number of items currently in the cache
    pub fn len(&self) -> usize {
        self.map.len()
    }

    /// Returns true if the cache is empty
    pub fn is_empty(&self) -> bool {
        self.map.is_empty()
    }

    /// Returns the capacity of the cache
    pub fn capacity(&self) -> usize {
        self.capacity
    }

    /// Get a reference to a value by key, marking it as recently used
    pub fn get(&mut self, key: &K) -> Option<&V> {
        if let Some(&node_ptr) = self.map.get(key) {
            self.move_to_front(node_ptr);
            // SAFETY: node_ptr is valid as long as it's in the map
            Some(unsafe { &(*node_ptr).value })
        } else {
            None
        }
    }

    /// Get a mutable reference to a value by key, marking it as recently used
    pub fn get_mut(&mut self, key: &K) -> Option<&mut V> {
        if let Some(&node_ptr) = self.map.get(key) {
            self.move_to_front(node_ptr);
            // SAFETY: node_ptr is valid as long as it's in the map
            Some(unsafe { &mut (*node_ptr).value })
        } else {
            None
        }
    }

    /// Insert or update a key-value pair.
    /// Returns the old value if the key already existed.
    pub fn put(&mut self, key: K, value: V) -> Option<V> {
        if let Some(&node_ptr) = self.map.get(&key) {
            // Key exists — update value and move to front
            // SAFETY: node_ptr is valid
            let old_value = unsafe {
                let old = std::ptr::read(&(*node_ptr).value);
                std::ptr::write(&mut (*node_ptr).value, value);
                old
            };
            self.move_to_front(node_ptr);
            Some(old_value)
        } else {
            // New key — evict if at capacity
            if self.map.len() == self.capacity {
                self.evict_lru();
            }

            let node = Box::new(Node::new(key.clone(), value));
            let node_ptr = Box::into_raw(node);
            self.map.insert(key, node_ptr);
            self.push_front(node_ptr);
            None
        }
    }

    /// Remove a key from the cache, returning its value if present
    pub fn remove(&mut self, key: &K) -> Option<V> {
        if let Some(node_ptr) = self.map.remove(key) {
            self.unlink(node_ptr);
            // SAFETY: node_ptr was removed from the map; we own it now
            let node = unsafe { Box::from_raw(node_ptr) };
            Some(node.value)
        } else {
            None
        }
    }

    /// Peek at a value without updating its recency
    pub fn peek(&self, key: &K) -> Option<&V> {
        self.map
            .get(key)
            // SAFETY: node_ptr is valid as long as it's in the map
            .map(|&node_ptr| unsafe { &(*node_ptr).value })
    }

    /// Returns true if the cache contains the given key (without updating recency)
    pub fn contains(&self, key: &K) -> bool {
        self.map.contains_key(key)
    }

    /// Clear all entries from the cache
    pub fn clear(&mut self) {
        // Drop all nodes
        let mut current = self.head;
        while let Some(node_ptr) = current {
            // SAFETY: node_ptr is valid and owned by us
            let node = unsafe { Box::from_raw(node_ptr) };
            current = node.next;
            drop(node);
        }
        self.map.clear();
        self.head = None;
        self.tail = None;
    }

    /// Returns a Vec of (key, value) pairs from most to least recently used
    pub fn iter(&self) -> Vec<(&K, &V)> {
        let mut result = Vec::with_capacity(self.map.len());
        let mut current = self.head;
        while let Some(node_ptr) = current {
            // SAFETY: node_ptr is valid
            unsafe {
                result.push((&(*node_ptr).key, &(*node_ptr).value));
                current = (*node_ptr).next;
            }
        }
        result
    }

    // ── Private helpers ──────────────────────────────────────────────────────

    /// Remove the tail (LRU) node and free it
    fn evict_lru(&mut self) {
        if let Some(tail_ptr) = self.tail {
            // SAFETY: tail_ptr is valid
            let key = unsafe { (*tail_ptr).key.clone() };
            self.map.remove(&key);
            self.unlink(tail_ptr);
            // SAFETY: tail_ptr is no longer referenced
            drop(unsafe { Box::from_raw(tail_ptr) });
        }
    }

    /// Move an existing node to the front of the list
    fn move_to_front(&mut self, node_ptr: *mut Node<K, V>) {
        // Already at front
        if self.head == Some(node_ptr) {
            return;
        }
        self.unlink(node_ptr);
        self.push_front(node_ptr);
    }

    /// Insert a node at the front (most recently used end)
    fn push_front(&mut self, node_ptr: *mut Node<K, V>) {
        // SAFETY: node_ptr is valid
        unsafe {
            (*node_ptr).prev = None;
            (*node_ptr).next = self.head;

            if let Some(old_head) = self.head {
                (*old_head).prev = Some(node_ptr);
            } else {
                // List was empty
                self.tail = Some(node_ptr);
            }
        }
        self.head = Some(node_ptr);
    }

    /// Remove a node from the linked list (does NOT free it)
    fn unlink(&mut self, node_ptr: *mut Node<K, V>) {
        // SAFETY: node_ptr is valid
        unsafe {
            let prev = (*node_ptr).prev;
            let next = (*node_ptr).next;

            match prev {
                Some(p) => (*p).next = next,
                None => self.head = next, // node was head
            }

            match next {
                Some(n) => (*n).prev = prev,
                None => self.tail = prev, // node was tail
            }

            (*node_ptr).prev = None;
            (*node_ptr).next = None;
        }
    }
}

impl<K, V> Drop for LruCache<K, V> {
    fn drop(&mut self) {
        let mut current = self.head;
        while let Some(node_ptr) = current {
            // SAFETY: node_ptr is valid and owned by us
            let node = unsafe { Box::from_raw(node_ptr) };
            current = node.next;
            drop(node);
        }
    }
}

impl<K: Eq + Hash + Clone + fmt::Debug, V: fmt::Debug> fmt::Debug for LruCache<K, V> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let entries: Vec<_> = self.iter();
        f.debug_map().entries(entries).finish()
    }
}

// SAFETY: LruCache owns all of its nodes exclusively through raw pointers
// and never shares them across threads unsafely.
unsafe impl<K: Send, V: Send> Send for LruCache<K, V> {}
unsafe impl<K: Sync, V: Sync> Sync for LruCache<K, V> {}

