impl std::fmt::Display for Trie {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        let words = self.get_all_words();
        write!(f, "Trie({} words): [{}]", self.total_words, words.join(", "))
    }
}

