# Permutations in Rust

Here's a complete implementation that generates all permutations of a list using Heap's algorithm, along with a recursive approach for comparison.

## Implementation

```rust
fn permutations<T: Clone>(items: &[T]) -> Vec<Vec<T>> {
    let mut result = Vec::new();

    if items.is_empty() {
        result.push(Vec::new());
        return result;
    }

    let mut items = items.to_vec();
    heap_permutations(&mut items, items.len(), &mut result);
    result
}

/// Heap's algorithm - efficient in-place permutation generation
fn heap_permutations<T: Clone>(items: &mut Vec<T>, n: usize, result: &mut Vec<Vec<T>>) {
    if n == 1 {
        result.push(items.clone());
        return;
    }

    for i in 0..n {
        heap_permutations(items, n - 1, result);

        if n % 2 == 0 {
            items.swap(i, n - 1);
        } else {
            items.swap(0, n - 1);
        }
    }
}

/// Recursive approach using backtracking
fn permutations_recursive<T: Clone>(items: &[T]) -> Vec<Vec<T>> {
    let mut result = Vec::new();
    let mut current = Vec::new();
    let mut used = vec![false; items.len()];

    backtrack(items, &mut current, &mut used, &mut result);
    result
}

fn backtrack<T: Clone>(
    items: &[T],
    current: &mut Vec<T>,
    used: &mut Vec<bool>,
    result: &mut Vec<Vec<T>>,
) {
    if current.len() == items.len() {
        result.push(current.clone());
        return;
    }

    for i in 0..items.len() {
        if !used[i] {
            used[i] = true;
            current.push(items[i].clone());

            backtrack(items, current, used, result);

            current.pop();
            used[i] = false;
        }
    }
}

/// Iterator-based approach for lazy evaluation (memory efficient)
struct Permutations<T: Clone> {
    items: Vec<T>,
    indices: Vec<usize>,
    cycles: Vec<usize>,
    first: bool,
    n: usize,
}

impl<T: Clone> Permutations<T> {
    fn new(items: Vec<T>) -> Self {
        let n = items.len();
        let indices: Vec<usize> = (0..n).collect();
        let cycles: Vec<usize> = (1..=n).rev().collect();

        Self {
            items,
            indices,
            cycles,
            first: true,
            n,
        }
    }
}

impl<T: Clone> Iterator for Permutations<T> {
    type Item = Vec<T>;

    /// Uses Python's itertools.permutations algorithm
    fn next(&mut self) -> Option<Self::Item> {
        if self.n == 0 {
            if self.first {
                self.first = false;
                return Some(Vec::new());
            }
            return None;
        }

        if self.first {
            self.first = false;
            return Some(self.indices.iter().map(|&i| self.items[i].clone()).collect());
        }

        for i in (0..self.n).rev() {
            self.cycles[i] -= 1;

            if self.cycles[i] == 0 {
                // Rotate indices[i..] left by 1
                let removed = self.indices.remove(i);
                self.indices.push(removed);
                self.cycles[i] = self.n - i;
            } else {
                let j = self.n - self.cycles[i];
                self.indices.swap(i, j);
                return Some(self.indices.iter().map(|&idx| self.items[idx].clone()).collect());
            }
        }

        None
    }
}

fn main() {
    // --- Basic usage ---
    println!("=== Heap's Algorithm ===");
    let nums = vec![1, 2, 3];
    let perms = permutations(&nums);
    println!("Permutations of {:?} ({} total):", nums, perms.len());
    for p in &perms {
        println!("  {:?}", p);
    }

    // --- Recursive approach ---
    println!("\n=== Recursive Backtracking ===");
    let chars = vec!['a', 'b', 'c'];
    let perms = permutations_recursive(&chars);
    println!("Permutations of {:?} ({} total):", chars, perms.len());
    for p in &perms {
        println!("  {:?}", p);
    }

    // --- Iterator approach ---
    println!("\n=== Iterator (lazy) ===");
    let items = vec!["x", "y", "z"];
    let iter_perms: Vec<_> = Permutations::new(items.clone()).collect();
    println!("Permutations of {:?} ({} total):", items, iter_perms.len());
    for p in &iter_perms {
        println!("  {:?}", p);
    }

    // --- Edge cases ---
    println!("\n=== Edge Cases ===");
    let empty: Vec<i32> = vec![];
    println!("Empty slice: {:?}", permutations(&empty));

    let single = vec![42];
    println!("Single element: {:?}", permutations(&single));

    // --- Performance: count permutations of larger input ---
    println!("\n=== Performance ===");
    let large: Vec<u32> = (1..=8).collect();
    let count = Permutations::new(large.clone()).count();
    println!("Number of permutations of {:?}: {}", large, count);
}

