## Key Design Decisions

| Approach | Time | Space | Best For |
|---|---|---|---|
| **Heap's Algorithm** | O(n!) | O(n!) | Fast, all at once |
| **Backtracking** | O(n!) | O(n) stack | Educational, filtered |
| **Iterator** | O(n!) | O(n) | Lazy/large inputs |

- **Heap's algorithm** minimizes swaps (only 1 swap per permutation)
- **Backtracking** is easy to extend (e.g., skip duplicates by checking neighbors)
- **Iterator** is ideal when you don't need all permutations at once — use `.find()`, `.take(k)`, etc. without generating everything

# Dijkstra's Shortest Path Algorithm in Rust

## Implementation

```rust
use std::collections::{BinaryHeap, HashMap};
use std::cmp::Ordering;

/// Represents a weighted edge to a neighbor node
#[derive(Debug, Clone)]
struct Edge {
    to: usize,
    weight: u64,
}

/// Graph represented as an adjacency list
#[derive(Debug)]
struct Graph {
    adjacency_list: Vec<Vec<Edge>>,
    node_count: usize,
}

impl Graph {
    /// Creates a new graph with the specified number of nodes
    fn new(node_count: usize) -> Self {
        Graph {
            adjacency_list: vec![Vec::new(); node_count],
            node_count,
        }
    }

    /// Adds a directed edge from `from` to `to` with the given weight
    fn add_edge(&mut self, from: usize, to: usize, weight: u64) {
        assert!(from < self.node_count && to < self.node_count, "Node index out of bounds");
        self.adjacency_list[from].push(Edge { to, weight });
    }

    /// Adds an undirected edge between `a` and `b` with the given weight
    fn add_undirected_edge(&mut self, a: usize, b: usize, weight: u64) {
        self.add_edge(a, b, weight);
        self.add_edge(b, a, weight);
    }
}

/// State used in the priority queue
#[derive(Debug, Clone, Eq, PartialEq)]
struct State {
    cost: u64,
    node: usize,
}

/// Reverse ordering so BinaryHeap becomes a min-heap
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        other.cost.cmp(&self.cost)
            .then_with(|| self.node.cmp(&other.node))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

/// Result of running Dijkstra's algorithm
#[derive(Debug)]
struct DijkstraResult {
    /// Shortest distance from source to each node (u64::MAX if unreachable)
    distances: Vec<u64>,
    /// Previous node in the shortest path tree (None if unreachable or source)
    predecessors: Vec<Option<usize>>,
}

impl DijkstraResult {
    /// Returns the shortest distance to the target node
    fn distance_to(&self, target: usize) -> Option<u64> {
        match self.distances[target] {
            u64::MAX => None,
            d => Some(d),
        }
    }

    /// Reconstructs the shortest path from source to target
    fn path_to(&self, source: usize, target: usize) -> Option<Vec<usize>> {
        if self.distances[target] == u64::MAX {
            return None; // Target is unreachable
        }

        let mut path = Vec::new();
        let mut current = target;

        loop {
            path.push(current);
            if current == source {
                break;
            }
            match self.predecessors[current] {
                Some(prev) => current = prev,
                None => return None, // Disconnected path (shouldn't happen if dist != MAX)
            }
        }

        path.reverse();
        Some(path)
    }
}

/// Runs Dijkstra's algorithm from the given source node
///
/// # Arguments
/// * `graph` - The weighted directed graph
/// * `source` - The starting node index
///
/// # Returns
/// A `DijkstraResult` containing distances and predecessors for path reconstruction
fn dijkstra(graph: &Graph, source: usize) -> DijkstraResult {
    assert!(source < graph.node_count, "Source node out of bounds");

    let n = graph.node_count;
    let mut distances = vec![u64::MAX; n];
    let mut predecessors = vec![None; n];
    let mut heap = BinaryHeap::new();

    // Distance to source is 0
    distances[source] = 0;
    heap.push(State { cost: 0, node: source });

    while let Some(State { cost, node }) = heap.pop() {
        // Skip if we've already found a better path
        if cost > distances[node] {
            continue;
        }

        // Relax all outgoing edges
        for edge in &graph.adjacency_list[node] {
            let next_cost = match distances[node].checked_add(edge.weight) {
                Some(c) => c,
                None => continue, // Overflow protection
            };

            if next_cost < distances[edge.to] {
                distances[edge.to] = next_cost;
                predecessors[edge.to] = Some(node);
                heap.push(State { cost: next_cost, node: edge.to });
            }
        }
    }

    DijkstraResult { distances, predecessors }
}

/// Named-node variant using HashMap for more ergonomic usage
struct NamedGraph {
    graph: Graph,
    name_to_index: HashMap<String, usize>,
    index_to_name: Vec<String>,
}

impl NamedGraph {
    fn new() -> Self {
        NamedGraph {
            graph: Graph::new(0),
            name_to_index: HashMap::new(),
            index_to_name: Vec::new(),
        }
    }

    fn add_node(&mut self, name: &str) -> usize {
        if let Some(&idx) = self.name_to_index.get(name) {
            return idx;
        }
        let idx = self.index_to_name.len();
        self.name_to_index.insert(name.to_string(), idx);
        self.index_to_name.push(name.to_string());
        self.graph.adjacency_list.push(Vec::new());
        self.graph.node_count += 1;
        idx
    }

    fn add_undirected_edge(&mut self, from: &str, to: &str, weight: u64) {
        let f = self.add_node(from);
        let t = self.add_node(to);
        self.graph.add_undirected_edge(f, t, weight);
    }

    fn shortest_path(&self, from: &str, to: &str) -> Option<(u64, Vec<String>)> {
        let &src = self.name_to_index.get(from)?;
        let &dst = self.name_to_index.get(to)?;

        let result = dijkstra(&self.graph, src);

        let distance = result.distance_to(dst)?;
        let path = result.path_to(src, dst)?;
        let named_path = path.iter()
            .map(|&i| self.index_to_name[i].clone())
            .collect();

        Some((distance, named_path))
    }
}

