# Basic Regex Matcher in Rust

I'll implement a regex engine supporting these patterns:
- `.` — matches any single character
- `*` — matches zero or more of the preceding element
- `+` — matches one or more of the preceding element
- `?` — matches zero or one of the preceding element
- `^` — anchors match to the start
- `$` — anchors match to the end
- `[abc]` — character classes (with negation `[^abc]` and ranges `a-z`)
- `\d`, `\w`, `\s` — escape sequences
- `(abc)` — grouping (for quantifiers)
- `|` — alternation

```rust
use std::fmt;

// ── Token / AST ──────────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq)]
enum Atom {
    Literal(char),
    AnyChar,           // .
    Digit,             // \d
    Word,              // \w
    Whitespace,        // \s
    NonDigit,          // \D
    NonWord,           // \W
    NonWhitespace,     // \S
    Class(CharClass),  // [...]
}

#[derive(Debug, Clone, PartialEq)]
struct CharClass {
    negated: bool,
    members: Vec<ClassMember>,
}

#[derive(Debug, Clone, PartialEq)]
enum ClassMember {
    Single(char),
    Range(char, char),
}

#[derive(Debug, Clone, PartialEq)]
enum Quantifier {
    One,          // no quantifier
    ZeroOrOne,    // ?
    ZeroOrMore,   // *
    OneOrMore,    // +
}

#[derive(Debug, Clone, PartialEq)]
enum Node {
    Atom(Atom, Quantifier),
    Group(Vec<Vec<Node>>, Quantifier), // alternatives inside group
    Anchor(AnchorKind),
}

#[derive(Debug, Clone, PartialEq)]
enum AnchorKind {
    Start, // ^
    End,   // $
}

// ── Error ────────────────────────────────────────────────────────────────────

#[derive(Debug)]
pub struct RegexError(String);

impl fmt::Display for RegexError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "RegexError: {}", self.0)
    }
}

// ── Parser ───────────────────────────────────────────────────────────────────

struct Parser {
    chars: Vec<char>,
    pos: usize,
}

impl Parser {
    fn new(pattern: &str) -> Self {
        Self { chars: pattern.chars().collect(), pos: 0 }
    }

    fn peek(&self) -> Option<char> {
        self.chars.get(self.pos).copied()
    }

    fn consume(&mut self) -> Option<char> {
        let c = self.chars.get(self.pos).copied();
        if c.is_some() { self.pos += 1; }
        c
    }

    fn expect(&mut self, expected: char) -> Result<(), RegexError> {
        match self.consume() {
            Some(c) if c == expected => Ok(()),
            Some(c) => Err(RegexError(format!("expected '{}', got '{}'", expected, c))),
            None => Err(RegexError(format!("expected '{}', got EOF", expected))),
        }
    }

    /// Parse the full pattern → Vec<alternative>, where each alternative
    /// is Vec<Node> (top-level is implicitly grouped by alternation).
    fn parse(&mut self) -> Result<Vec<Vec<Node>>, RegexError> {
        let alts = self.parse_alternation()?;
        if self.pos < self.chars.len() {
            return Err(RegexError(format!(
                "unexpected character '{}' at position {}",
                self.chars[self.pos], self.pos
            )));
        }
        Ok(alts)
    }

    /// alternation ::= sequence ('|' sequence)*
    fn parse_alternation(&mut self) -> Result<Vec<Vec<Node>>, RegexError> {
        let mut alts = vec![self.parse_sequence()?];
        while self.peek() == Some('|') {
            self.consume();
            alts.push(self.parse_sequence()?);
        }
        Ok(alts)
    }

    /// sequence ::= node*  (stops at '|', ')', or EOF)
    fn parse_sequence(&mut self) -> Result<Vec<Node>, RegexError> {
        let mut nodes = Vec::new();
        loop {
            match self.peek() {
                None | Some('|') | Some(')') => break,
                _ => nodes.push(self.parse_node()?),
            }
        }
        Ok(nodes)
    }

    fn parse_node(&mut self) -> Result<Node, RegexError> {
        // Anchors have no quantifier
        if self.peek() == Some('^') {
            self.consume();
            return Ok(Node::Anchor(AnchorKind::Start));
        }
        if self.peek() == Some('$') {
            self.consume();
            return Ok(Node::Anchor(AnchorKind::End));
        }

        // Group
        if self.peek() == Some('(') {
            self.consume();
            let alts = self.parse_alternation()?;
            self.expect(')')?;
            let q = self.parse_quantifier();
            return Ok(Node::Group(alts, q));
        }

        let atom = self.parse_atom()?;
        let q = self.parse_quantifier();
        Ok(Node::Atom(atom, q))
    }

    fn parse_atom(&mut self) -> Result<Atom, RegexError> {
        match self.consume() {
            Some('.') => Ok(Atom::AnyChar),
            Some('[') => self.parse_class(),
            Some('\\') => self.parse_escape(),
            Some(c) => Ok(Atom::Literal(c)),
            None => Err(RegexError("unexpected end of pattern".into())),
        }
    }

    fn parse_escape(&mut self) -> Result<Atom, RegexError> {
        match self.consume() {
            Some('d') => Ok(Atom::Digit),
            Some('D') => Ok(Atom::NonDigit),
            Some('w') => Ok(Atom::Word),
            Some('W') => Ok(Atom::NonWord),
            Some('s') => Ok(Atom::Whitespace),
            Some('S') => Ok(Atom::NonWhitespace),
            Some(c) => Ok(Atom::Literal(c)),
            None => Err(RegexError("trailing backslash".into())),
        }
    }

    fn parse_class(&mut self) -> Result<Atom, RegexError> {
        let negated = if self.peek() == Some('^') {
            self.consume();
            true
        } else {
            false
        };

        let mut members = Vec::new();
        // First char may be ']' as a literal
        if self.peek() == Some(']') {
            members.push(ClassMember::Single(']'));
            self.consume();
        }

        loop {
            match self.peek() {
                None => return Err(RegexError("unclosed character class".into())),
                Some(']') => { self.consume(); break; }
                Some('\\') => {
                    self.consume();
                    match self.consume() {
                        Some(c) => members.push(ClassMember::Single(c)),
                        None => return Err(RegexError("trailing backslash in class".into())),
                    }
                }
                Some(c) => {
                    self.consume();
                    // Check for range (c-x)
                    if self.peek() == Some('-') {
                        // peek ahead one more
                        if self.pos + 1 < self.chars.len() && self.chars[self.pos + 1] != ']' {
                            self.consume(); // consume '-'
                            let end = self.consume().unwrap();
                            members.push(ClassMember::Range(c, end));
                        } else {
                            members.push(ClassMember::Single(c));
                        }
                    } else {
                        members.push(ClassMember::Single(c));
                    }
                }
            }
        }

        Ok(Atom::Class(CharClass { negated, members }))
    }

    fn parse_quantifier(&mut self) -> Quantifier {
        match self.peek() {
            Some('?') => { self.consume(); Quantifier::ZeroOrOne  }
            Some('*') => { self.consume(); Quantifier::ZeroOrMore }
            Some('+') => { self.consume(); Quantifier::OneOrMore  }
            _ => Quantifier::One,
        }
    }
}

// ── Compiled Regex ───────────────────────────────────────────────────────────

pub struct Regex {
    /// Top-level alternatives
    ast: Vec<Vec<Node>>,
    anchored_start: bool,
    anchored_end: bool,
}

impl Regex {
    pub fn new(pattern: &str) -> Result<Self, RegexError> {
        let mut parser = Parser::new(pattern);
        let ast = parser.parse()?;

        // Detect leading ^ / trailing $ outside groups
        let anchored_start = ast.iter().all(|seq| {
            seq.first() == Some(&Node::Anchor(AnchorKind::Start))
        });
        let anchored_end = ast.iter().all(|seq| {
            seq.last() == Some(&Node::Anchor(AnchorKind::End))
        });

        Ok(Self { ast, anchored_start, anchored_end })
    }

    // ── Public API ────────────────────────────────────────────────────────────

    /// Returns true if the pattern matches the entire string.
    pub fn is_match(&self, text: &str) -> bool {
        self.find(text).is_some()
    }

    /// Returns the byte range of the first match, if any.
    pub fn find(&self, text: &str) -> Option<(usize, usize)> {
        let chars: Vec<char> = text.chars().collect();
        let n = chars.len();

        if self.anchored_start {
            // Only try at position 0
            if let Some(end) = self.try_match_alts(&self.ast, &chars, 0) {
                if !self.anchored_end || end == n {
                    // Convert char indices to byte offsets
                    return Some(self.char_range_to_bytes(text, 0, end));
                }
            }
            return None;
        }

        for start in 0..=n {
            if let Some(end) = self.try_match_alts(&self.ast, &chars, start) {
                if !self.anchored_end || end == n {
                    return Some(self.char_range_to_bytes(text, start, end));
                }
            }
        }
        None
    }

    /// Returns all non-overlapping matches.
    pub fn find_all<'t>(&self, text: &'t str) -> Vec<&'t str> {
        let mut results = Vec::new();
        let mut start = 0;
        let chars: Vec<char> = text.chars().collect();
        let n = chars.len();

        while start <= n {
            if let Some(end) = self.try_match_alts(&self.ast, &chars, start) {
                let (bs, be) = self.char_range_to_bytes(text, start, end);
                results.push(&text[bs..be]);
                // Advance by at least 1 to avoid infinite loop on zero-width match
                start = if end > start { end } else { start + 1 };
            } else {
                start += 1;
            }
        }
        results
    }

    // ── Internal matching ─────────────────────────────────────────────────────

    /// Try to match any alternative in `alts` starting at `pos`.
    /// Returns the end position (char index) on success.
    fn try_match_alts(&self, alts: &[Vec<Node>], chars: &[char], pos: usize) -> Option<usize> {
        for seq in alts {
            if let Some(end) = self.match_sequence(seq, chars, pos) {
                return Some(end);
            }
        }
        None
    }

    fn match_sequence(&self, nodes: &[Node], chars: &[char], pos: usize) -> Option<usize> {
        self.match_nodes(nodes, 0, chars, pos)
    }

    /// Recursive match of nodes[idx..] starting at chars[pos].
    fn match_nodes(&self, nodes: &[Node], idx: usize, chars: &[char], pos: usize) -> Option<usize> {
        if idx == nodes.len() {
            return Some(pos);
        }

        let node = &nodes[idx];
        match node {
            Node::Anchor(AnchorKind::Start) => {
                if pos == 0 { self.match_nodes(nodes, idx + 1, chars, pos) } else { None }
            }
            Node::Anchor(AnchorKind::End) => {
                if pos == chars.len() { self.match_nodes(nodes, idx + 1, chars, pos) } else { None }
            }
            Node::Atom(atom, q) => self.match_atom_quant(atom, q, nodes, idx, chars, pos),
            Node::Group(alts, q) => self.match_group_quant(alts, q, nodes, idx, chars, pos),
        }
    }

    fn match_atom_quant(
        &self,
        atom: &Atom,
        q: &Quantifier,
        nodes: &[Node],
        idx: usize,
        chars: &[char],
        pos: usize,
    ) -> Option<usize> {
        match q {
            Quantifier::One => {
                let new_pos = self.match_atom(atom, chars, pos)?;
                self.match_nodes(nodes, idx + 1, chars, new_pos)
            }
            Quantifier::ZeroOrOne => {
                // Greedy: try with first, then without
                if let Some(new_pos) = self.match_atom(atom, chars, pos) {
                    if let Some(end) = self.match_nodes(nodes, idx + 1, chars, new_pos) {
                        return Some(end);
                    }
                }
                self.match_nodes(nodes, idx + 1, chars, pos)
            }
            Quantifier::ZeroOrMore => {
                // Greedy: collect all possible positions, try from longest
                let positions = self.greedy_positions(atom, chars, pos);
                for &p in positions.iter().rev() {
                    if let Some(end) = self.match_nodes(nodes, idx + 1, chars, p) {
                        return Some(end);
                    }
                }
                None
            }
            Quantifier::OneOrMore => {
                let positions = self.greedy_positions(atom, chars, pos);
                if positions.len() < 2 { return None; } // need at least one match
                for &p in positions[1..].iter().rev() {
                    if let Some(end) = self.match_nodes(nodes, idx + 1, chars, p) {
                        return Some(end);
                    }
                }
                None
            }
        }
    }

    /// Returns a list of positions [pos, pos+1, pos+2, ...] while atom matches.
    /// positions[0] = pos (0 matches), positions[k] = pos after k matches.
    fn greedy_positions(&self, atom: &Atom, chars: &[char], pos: usize) -> Vec<usize> {
        let mut positions = vec![pos];
        let mut cur = pos;
        while let Some(next) = self.match_atom(atom, chars, cur) {
            positions.push(next);
            if next == cur { break; } // safety: zero-width atom
            cur = next;
        }
        positions
    }

    fn match_group_quant(
        &self,
        alts: &[Vec<Node>],
        q: &Quantifier,
        nodes: &[Node],
        idx: usize,
        chars: &[char],
        pos: usize,
    ) -> Option<usize> {
        match q {
            Quantifier::One => {
                let new_pos = self.try_match_alts(alts, chars, pos)?;
                self.match_nodes(nodes, idx + 1, chars, new_pos)
            }
            Quantifier::ZeroOrOne => {
                if let Some(new_pos) = self.try_match_alts(alts, chars, pos) {
                    if let Some(end) = self.match_nodes(nodes, idx + 1, chars, new_pos) {
                        return Some(end);
                    }
                }
                self.match_nodes(nodes, idx + 1, chars, pos)
            }
            Quantifier::ZeroOrMore => {
                let positions = self.greedy_group_positions(alts, chars, pos);
                for &p in positions.iter().rev() {
                    if let Some(end) = self.match_nodes(nodes, idx + 1, chars, p) {
                        return Some(end);
                    }
                }
                None
            }
            Quantifier::OneOrMore => {
                let positions = self.greedy_group_positions(alts, chars, pos);
                if positions.len() < 2 { return None; }
                for &p in positions[1..].iter().rev() {
                    if let Some(end) = self.match_nodes(nodes, idx + 1, chars, p) {
                        return Some(end);
                    }
                }
                None
            }
        }
    }

    fn greedy_group_positions(&self, alts: &[Vec<Node>], chars: &[char], pos: usize) -> Vec<usize> {
        let mut positions = vec![pos];
        let mut cur = pos;
        while let Some(next) = self.try_match_alts(alts, chars, cur) {
            positions.push(next);
            if next == cur { break; }
            cur = next;
        }
        positions
    }

    /// Try to match a single atom at chars[pos]. Returns new position or None.
    fn match_atom(&self, atom: &Atom, chars: &[char], pos: usize) -> Option<usize> {
        let c = *chars.get(pos)?;
        let matched = match atom {
            Atom::AnyChar       => true,
            Atom::Literal(lit)  => c == *lit,
            Atom::Digit         => c.is_ascii_digit(),
            Atom::NonDigit      => !c.is_ascii_digit(),
            Atom::Word          => c.is_alphanumeric() || c == '_',
            Atom::NonWord       => !(c.is_alphanumeric() || c == '_'),
            Atom::Whitespace    => c.is_whitespace(),
            Atom::NonWhitespace => !c.is_whitespace(),
            Atom::Class(cc)     => self.match_class(cc, c),
        };
        if matched { Some(pos + 1) } else { None }
    }

    fn match_class(&self, cc: &CharClass, c: char) -> bool {
        let hit = cc.members.iter().any(|m| match m {
            ClassMember::Single(x) => c == *x,
            ClassMember::Range(lo, hi) => c >= *lo && c <= *hi,
        });
        if cc.negated { !hit } else { hit }
    }

    // ── Utility ───────────────────────────────────────────────────────────────

    fn char_range_to_bytes(&self, text: &str, cstart: usize, cend: usize) -> (usize, usize) {
        let mut byte_start = 0;
        let mut byte_end = 0;
        let mut ci = 0;
        for (bi, _c) in text.char_indices() {
            if ci == cstart { byte_start = bi; }
            if ci == cend   { byte_end = bi; break; }
            ci += 1;
        }
        if cend == ci { byte_end = text.len(); } // end of string
        (byte_start, byte_end)
    }
}

