## How it works

### Architecture

```
Pattern string
     │
     ▼
  Parser  ──────────────────────► AST (Vec<Vec<Node>>)
  (recursive descent)                    │
                                         ▼
                                   Regex::find()
                                   (backtracking NFA simulation)
                                         │
                                         ▼
                                   match position
```

### Key design decisions

| Decision | Rationale |
|---|---|
| **Recursive descent parser** | Clean, easy to extend |
| **AST → direct interpretation** | Simpler than compiling to bytecode for a "basic" engine |
| **Greedy backtracking** | Matches PCRE semantics; collect all positions then try from longest |
| **Char-indexed internally** | Correct Unicode handling; convert to byte offsets at the boundary |
| **`Vec<Vec<Node>>` for alternation** | Top-level and groups share the same representation |

### Supported syntax

| Syntax | Meaning |
|---|---|
| `abc` | Literal characters |
| `.` | Any character |
| `*` `+` `?` | Greedy quantifiers |
| `^` `$` | Start / end anchors |
| `[abc]` `[a-z]` `[^abc]` | Character classes |
| `\d` `\D` `\w` `\W` `\s` `\S` | Escape sequences |
| `(...)` | Grouping (with quantifiers) |
| `\|` | Alternation |

# Longest Common Subsequence in Rust

## Implementation

```rust
fn longest_common_subsequence(s1: &str, s2: &str) -> String {
    let s1: Vec<char> = s1.chars().collect();
    let s2: Vec<char> = s2.chars().collect();
    let m = s1.len();
    let n = s2.len();

    // Build the DP table
    let mut dp = vec![vec![0usize; n + 1]; m + 1];

    for i in 1..=m {
        for j in 1..=n {
            if s1[i - 1] == s2[j - 1] {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = dp[i - 1][j].max(dp[i][j - 1]);
            }
        }
    }

    // Backtrack to find the actual LCS string
    let mut lcs = Vec::new();
    let mut i = m;
    let mut j = n;

    while i > 0 && j > 0 {
        if s1[i - 1] == s2[j - 1] {
            lcs.push(s1[i - 1]);
            i -= 1;
            j -= 1;
        } else if dp[i - 1][j] > dp[i][j - 1] {
            i -= 1;
        } else {
            j -= 1;
        }
    }

    lcs.iter().rev().collect()
}

fn lcs_length(s1: &str, s2: &str) -> usize {
    let s1: Vec<char> = s1.chars().collect();
    let s2: Vec<char> = s2.chars().collect();
    let m = s1.len();
    let n = s2.len();

    // Space-optimized version using two rows
    let mut prev = vec![0usize; n + 1];
    let mut curr = vec![0usize; n + 1];

    for i in 1..=m {
        for j in 1..=n {
            if s1[i - 1] == s2[j - 1] {
                curr[j] = prev[j - 1] + 1;
            } else {
                curr[j] = prev[j].max(curr[j - 1]);
            }
        }
        std::mem::swap(&mut prev, &mut curr);
        curr.fill(0);
    }

    prev[n]
}

fn all_lcs(s1: &str, s2: &str) -> Vec<String> {
    let s1: Vec<char> = s1.chars().collect();
    let s2: Vec<char> = s2.chars().collect();
    let m = s1.len();
    let n = s2.len();

    // Build the DP table
    let mut dp = vec![vec![0usize; n + 1]; m + 1];

    for i in 1..=m {
        for j in 1..=n {
            if s1[i - 1] == s2[j - 1] {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = dp[i - 1][j].max(dp[i][j - 1]);
            }
        }
    }

    // Recursive backtracking to find all LCS strings
    fn backtrack(
        s1: &[char],
        s2: &[char],
        dp: &Vec<Vec<usize>>,
        i: usize,
        j: usize,
    ) -> Vec<String> {
        if i == 0 || j == 0 {
            return vec![String::new()];
        }

        if s1[i - 1] == s2[j - 1] {
            backtrack(s1, s2, dp, i - 1, j - 1)
                .into_iter()
                .map(|mut s| {
                    s.push(s1[i - 1]);
                    s
                })
                .collect()
        } else {
            let mut result = Vec::new();

            if dp[i - 1][j] >= dp[i][j - 1] {
                result.extend(backtrack(s1, s2, dp, i - 1, j));
            }
            if dp[i][j - 1] >= dp[i - 1][j] {
                result.extend(backtrack(s1, s2, dp, i, j - 1));
            }

            // Deduplicate results
            result.sort_unstable();
            result.dedup();
            result
        }
    }

    backtrack(&s1, &s2, &dp, m, n)
}

fn print_dp_table(s1: &str, s2: &str) {
    let s1: Vec<char> = s1.chars().collect();
    let s2: Vec<char> = s2.chars().collect();
    let m = s1.len();
    let n = s2.len();

    let mut dp = vec![vec![0usize; n + 1]; m + 1];

    for i in 1..=m {
        for j in 1..=n {
            if s1[i - 1] == s2[j - 1] {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = dp[i - 1][j].max(dp[i][j - 1]);
            }
        }
    }

    // Print header
    print!("    ");
    print!("  Ø ");
    for c in &s2 {
        print!("  {} ", c);
    }
    println!();

    // Print rows
    for i in 0..=m {
        if i == 0 {
            print!("Ø   ");
        } else {
            print!("{}   ", s1[i - 1]);
        }
        for j in 0..=n {
            print!("{:3} ", dp[i][j]);
        }
        println!();
    }
}

fn main() {
    println!("=== Longest Common Subsequence ===\n");

    // Basic example
    let s1 = "ABCBDAB";
    let s2 = "BDCAB";
    let lcs = longest_common_subsequence(s1, s2);
    println!("Example 1:");
    println!("  S1: {}", s1);
    println!("  S2: {}", s2);
    println!("  LCS: \"{}\" (length: {})", lcs, lcs.len());
    println!("  Length (optimized): {}", lcs_length(s1, s2));

    println!();
    println!("  DP Table:");
    print_dp_table(s1, s2);

    println!();
    println!("  All LCS variants:");
    for variant in all_lcs(s1, s2) {
        println!("    \"{}\"", variant);
    }

    // Additional examples
    println!("\n{}", "=".repeat(40));

    let test_cases = vec![
        ("AGGTAB", "GXTXAYB"),
        ("ABCDEF", "ABCDEF"),
        ("ABCDEF", "GHIJKL"),
        ("", "ABC"),
        ("A", "A"),
        ("XMJYAUZ", "MZJAWXU"),
    ];

    for (s1, s2) in test_cases {
        let lcs = longest_common_subsequence(s1, s2);
        println!(
            "\n  S1: {:10}  S2: {:10}  LCS: {:10}  Length: {}",
            format!("\"{}\"", s1),
            format!("\"{}\"", s2),
            format!("\"{}\"", lcs),
            lcs.len()
        );
    }
}

