/// RequestVote RPC - sent by candidates to gather votes
#[derive(Debug, Clone)]
pub struct RequestVote {
    /// Candidate's term
    pub term: u64,
    /// Candidate requesting vote
    pub candidate_id: usize,
    /// Index of candidate's last log entry (simplified: always 0)
    pub last_log_index: u64,
    /// Term of candidate's last log entry (simplified: always 0)
    pub last_log_term: u64,
}

/// Response to RequestVote RPC
#[derive(Debug, Clone)]
pub struct RequestVoteResponse {
    /// Current term, for candidate to update itself
    pub term: u64,
    /// True means candidate received vote
    pub vote_granted: bool,
    /// ID of the voter
    pub voter_id: usize,
}

/// AppendEntries RPC - used as heartbeat (no log entries in this implementation)
#[derive(Debug, Clone)]
pub struct AppendEntries {
    /// Leader's term
    pub term: u64,
    /// Leader sending the heartbeat
    pub leader_id: usize,
}

/// Response to AppendEntries RPC
#[derive(Debug, Clone)]
pub struct AppendEntriesResponse {
    /// Current term for leader to update itself
    pub term: u64,
    /// True if follower contained entry matching prevLogIndex and prevLogTerm
    pub success: bool,
    /// Responder ID
    pub responder_id: usize,
}

/// All message types exchanged between nodes
#[derive(Debug, Clone)]
pub enum Message {
    RequestVote(RequestVote),
    RequestVoteResponse(RequestVoteResponse),
    AppendEntries(AppendEntries),
    AppendEntriesResponse(AppendEntriesResponse),
    /// Internal signal to trigger an election timeout
    ElectionTimeout,
    /// Internal signal to send heartbeats
    HeartbeatTimeout,
}
```

### `src/raft/node.rs`

```rust
use super::messages::*;
use super::state::{NodeState, PersistentState, VolatileState};
use rand::Rng;
use std::time::{Duration, Instant};
use tokio::sync::mpsc;
use tracing::{debug, info, warn};

/// Election timeout range in milliseconds
const ELECTION_TIMEOUT_MIN_MS: u64 = 150;
const ELECTION_TIMEOUT_MAX_MS: u64 = 300;
/// Heartbeat interval in milliseconds
const HEARTBEAT_INTERVAL_MS: u64 = 50;

pub struct RaftNode {
    /// This node's unique ID
    pub id: usize,
    /// Total number of nodes in the cluster
    pub cluster_size: usize,
    /// Persistent state (survives crashes)
    pub persistent: PersistentState,
    /// Volatile state
    pub volatile: VolatileState,
    /// Channel to receive messages
    pub rx: mpsc::Receiver<(usize, Message)>,
    /// Channels to send messages to other nodes
    pub peers: Vec<mpsc::Sender<(usize, Message)>>,
    /// Election timeout deadline
    pub election_deadline: Instant,
    /// Last heartbeat sent time
    pub last_heartbeat: Instant,
}

impl RaftNode {
    pub fn new(
        id: usize,
        cluster_size: usize,
        rx: mpsc::Receiver<(usize, Message)>,
        peers: Vec<mpsc::Sender<(usize, Message)>>,
    ) -> Self {
        let election_deadline = Self::random_election_deadline();
        Self {
            id,
            cluster_size,
            persistent: PersistentState::new(),
            volatile: VolatileState::new(),
            rx,
            peers,
            election_deadline,
            last_heartbeat: Instant::now(),
        }
    }

    fn random_election_deadline() -> Instant {
        let mut rng = rand::thread_rng();
        let timeout_ms = rng.gen_range(ELECTION_TIMEOUT_MIN_MS..=ELECTION_TIMEOUT_MAX_MS);
        Instant::now() + Duration::from_millis(timeout_ms)
    }

    fn reset_election_timer(&mut self) {
        self.election_deadline = Self::random_election_deadline();
    }

    fn majority(&self) -> usize {
        self.cluster_size / 2 + 1
    }

    /// Send a message to a specific peer
    async fn send_to(&self, peer_id: usize, msg: Message) {
        if peer_id < self.peers.len() {
            if let Err(e) = self.peers[peer_id].send((self.id, msg)).await {
                warn!("Node {}: Failed to send to peer {}: {}", self.id, peer_id, e);
            }
        }
    }

    /// Broadcast a message to all peers
    async fn broadcast(&self, msg: Message) {
        for (idx, peer) in self.peers.iter().enumerate() {
            if idx != self.id {
                if let Err(e) = peer.send((self.id, msg.clone())).await {
                    warn!("Node {}: Failed to broadcast to peer {}: {}", self.id, idx, e);
                }
            }
        }
    }

    /// Transition to follower state, updating term if needed
    fn become_follower(&mut self, term: u64) {
        if term > self.persistent.current_term {
            self.persistent.current_term = term;
            self.persistent.voted_for = None;
        }
        let prev_role = self.volatile.role.clone();
        self.volatile.role = NodeState::Follower;
        self.volatile.votes_received = 0;

        if prev_role != NodeState::Follower {
            info!(
                "Node {}: {} -> Follower (term {})",
                self.id, prev_role, self.persistent.current_term
            );
        }
        self.reset_election_timer();
    }

    /// Start a new election
    async fn start_election(&mut self) {
        self.persistent.current_term += 1;
        self.volatile.role = NodeState::Candidate;
        self.volatile.votes_received = 1; // Vote for self
        self.volatile.current_leader = None;
        self.persistent.voted_for = Some(self.id);
        self.reset_election_timer();

        info!(
            "Node {}: Starting election for term {}",
            self.id, self.persistent.current_term
        );

        let request = Message::RequestVote(RequestVote {
            term: self.persistent.current_term,
            candidate_id: self.id,
            last_log_index: 0,
            last_log_term: 0,
        });

        self.broadcast(request).await;
    }

    /// Transition to leader state
    async fn become_leader(&mut self) {
        self.volatile.role = NodeState::Leader;
        self.volatile.current_leader = Some(self.id);

        info!(
            "Node {}: Became LEADER for term {}! (received {}/{} votes)",
            self.id,
            self.persistent.current_term,
            self.volatile.votes_received,
            self.cluster_size,
        );

        // Immediately send heartbeats
        self.send_heartbeats().await;
    }

    /// Send heartbeats to all followers
    async fn send_heartbeats(&mut self) {
        debug!("Node {}: Sending heartbeats (term {})", self.id, self.persistent.current_term);
        let heartbeat = Message::AppendEntries(AppendEntries {
            term: self.persistent.current_term,
            leader_id: self.id,
        });
        self.broadcast(heartbeat).await;
        self.last_heartbeat = Instant::now();
    }

    /// Handle an incoming RequestVote RPC
    async fn handle_request_vote(&mut self, from: usize, req: RequestVote) {
        // If we see a higher term, revert to follower
        if req.term > self.persistent.current_term {
            self.become_follower(req.term);
        }

        let vote_granted = if req.term < self.persistent.current_term {
            // Candidate's term is stale
            false
        } else if let Some(voted_for) = self.persistent.voted_for {
            // Already voted for someone in this term
            voted_for == req.candidate_id
        } else {
            // Haven't voted yet this term; grant vote
            // (In full Raft, we'd also check log completeness here)
            true
        };

        if vote_granted {
            self.persistent.voted_for = Some(req.candidate_id);
            self.reset_election_timer();
            debug!(
                "Node {}: Granting vote to {} for term {}",
                self.id, req.candidate_id, req.term
            );
        } else {
            debug!(
                "Node {}: Denying vote to {} for term {} (voted_for={:?}, current_term={})",
                self.id, req.candidate_id, req.term,
                self.persistent.voted_for, self.persistent.current_term
            );
        }

        let response = Message::RequestVoteResponse(RequestVoteResponse {
            term: self.persistent.current_term,
            vote_granted,
            voter_id: self.id,
        });

        self.send_to(from, response).await;
    }

    /// Handle a RequestVote response
    async fn handle_request_vote_response(&mut self, resp: RequestVoteResponse) {
        // Ignore if we're no longer a candidate
        if self.volatile.role != NodeState::Candidate {
            return;
        }

        // If we see a higher term, step down
        if resp.term > self.persistent.current_term {
            self.become_follower(resp.term);
            return;
        }

        // Ignore stale responses
        if resp.term < self.persistent.current_term {
            return;
        }

        if resp.vote_granted {
            self.volatile.votes_received += 1;
            info!(
                "Node {}: Received vote from {} ({}/{} votes) in term {}",
                self.id,
                resp.voter_id,
                self.volatile.votes_received,
                self.cluster_size,
                self.persistent.current_term
            );

            if self.volatile.votes_received >= self.majority() {
                self.become_leader().await;
            }
        }
    }

    /// Handle an incoming AppendEntries (heartbeat) RPC
    async fn handle_append_entries(&mut self, from: usize, req: AppendEntries) {
        // If we see a higher term, revert to follower
        if req.term > self.persistent.current_term {
            self.become_follower(req.term);
        }

        let success = if req.term < self.persistent.current_term {
            // Leader's term is stale
            false
        } else {
            // Valid heartbeat from current leader
            if self.volatile.role == NodeState::Candidate {
                // A leader exists; step down
                self.become_follower(req.term);
            }
            self.volatile.current_leader = Some(from);
            self.reset_election_timer();
            true
        };

        if success {
            debug!(
                "Node {}: Accepted heartbeat from leader {} (term {})",
                self.id, req.leader_id, req.term
            );
        }

        let response = Message::AppendEntriesResponse(AppendEntriesResponse {
            term: self.persistent.current_term,
            success,
            responder_id: self.id,
        });

        self.send_to(from, response).await;
    }

    /// Handle an AppendEntries response (leader only)
    async fn handle_append_entries_response(&mut self, resp: AppendEntriesResponse) {
        // Step down if we see a higher term
        if resp.term > self.persistent.current_term {
            self.become_follower(resp.term);
        }
    }

    /// Main event loop for this node
    pub async fn run(&mut self) {
        info!("Node {}: Starting as Follower (term 0)", self.id);

        loop {
            let now = Instant::now();
            let heartbeat_due = self.volatile.role == NodeState::Leader
                && now.duration_since(self.last_heartbeat)
                    >= Duration::from_millis(HEARTBEAT_INTERVAL_MS);

            // Calculate how long to wait for the next event
            let wait_duration = if self.volatile.role == NodeState::Leader {
                // Leaders wait for heartbeat interval
                let elapsed = now.duration_since(self.last_heartbeat);
                Duration::from_millis(HEARTBEAT_INTERVAL_MS)
                    .saturating_sub(elapsed)
            } else {
                // Followers/candidates wait for election timeout
                self.election_deadline.saturating_duration_since(now)
            };

            if heartbeat_due {
                self.send_heartbeats().await;
                continue;
            }

            // Wait for either a message or a timeout
            let result = tokio::time::timeout(wait_duration, self.rx.recv()).await;

            match result {
                // Timeout occurred
                Err(_) => {
                    match self.volatile.role {
                        NodeState::Leader => {
                            self.send_heartbeats().await;
                        }
                        NodeState::Follower | NodeState::Candidate => {
                            // Election timeout: start a new election
                            self.start_election().await;
                        }
                    }
                }
                // Message received
                Ok(Some((from, msg))) => {
                    self.handle_message(from, msg).await;
                }
                // Channel closed: shutdown
                Ok(None) => {
                    info!("Node {}: Channel closed, shutting down", self.id);
                    break;
                }
            }
        }
    }

    async fn handle_message(&mut self, from: usize, msg: Message) {
        match msg {
            Message::RequestVote(req) => {
                self.handle_request_vote(from, req).await;
            }
            Message::RequestVoteResponse(resp) => {
                self.handle_request_vote_response(resp).await;
            }
            Message::AppendEntries(req) => {
                self.handle_append_entries(from, req).await;
            }
            Message::AppendEntriesResponse(resp) => {
                self.handle_append_entries_response(resp).await;
            }
            Message::ElectionTimeout => {
                self.start_election().await;
            }
            Message::HeartbeatTimeout => {
                if self.volatile.role == NodeState::Leader {
                    self.send_heartbeats().await;
                }
            }
        }
    }
}
```

### `src/raft/cluster.rs`

```rust
use super::messages::Message;
use super::node::RaftNode;
use std::time::Duration;
use tokio::sync::mpsc;
use tokio::task::JoinHandle;
use tracing::info;

const CHANNEL_BUFFER: usize = 128;

pub struct RaftCluster {
    node_count: usize,
    /// Senders for each node (index = node ID)
    senders: Vec<mpsc::Sender<(usize, Message)>>,
    /// Node task handles
    handles: Vec<JoinHandle<()>>,
}

impl RaftCluster {
    pub fn new(node_count: usize) -> Self {
        // Create channels for all nodes first
        let mut senders = Vec::with_capacity(node_count);
        let mut receivers = Vec::with_capacity(node_count);

        for _ in 0..node_count {
            let (tx, rx) = mpsc::channel::<(usize, Message)>(CHANNEL_BUFFER);
            senders.push(tx);
            receivers.push(rx);
        }

        // Spawn each node's task
        let mut handles = Vec::with_capacity(node_count);

        for (id, rx) in receivers.into_iter().enumerate() {
            let peers = senders.clone();
            let cluster_size = node_count;

            let handle = tokio::spawn(async move {
                let mut node = RaftNode::new(id, cluster_size, rx, peers);
                node.run().await;
            });

            handles.push(handle);
        }

        Self {
            node_count,
            senders,
            handles,
        }
    }

    /// Run the cluster for the given number of seconds, then print final state
    pub async fn run(&mut self, duration_secs: u64) {
        info!(
            "Cluster running with {} nodes for {} seconds...",
            self.node_count, duration_secs
        );

        tokio::time::sleep(Duration::from_secs(duration_secs)).await;

        info!("Cluster simulation complete. Shutting down.");

        // Drop senders to signal nodes to stop
        for sender in self.senders.drain(..) {
            drop(sender);
        }

        // Wait for all nodes to finish
        for handle in self.handles.drain(..) {
            let _ = handle.await;
        }

        info!("All nodes stopped.");
    }
}
