## How It Works

| Phase | Description |
|---|---|
| **Divide** | Recursively sort the left and right halves independently |
| **Odd-even merge** | Merge by recursively merging even-indexed and odd-indexed elements |
| **Reconcile** | Swap adjacent interleaved pairs to produce the final sorted order |

### Key Properties

- **Complexity**: O(n log²n) comparisons, O(log²n) parallel depth
- **Oblivious**: The comparator positions are data-independent (ideal for hardware/GPU)
- **Generic**: Works on any type implementing `Ord`
- **Handles non-power-of-two** sizes correctly via the recursive structure

# Persistent Red-Black Tree in Rust

A persistent (immutable/functional) red-black tree where every operation creates new nodes along the modified path while sharing unchanged subtrees.

## Implementation

```rust
use std::sync::Arc;
use std::fmt;

/// Node color in the red-black tree
#[derive(Clone, Debug, PartialEq)]
enum Color {
    Red,
    Black,
}

/// A persistent red-black tree node stored behind Arc for structural sharing
#[derive(Clone, Debug)]
enum Tree<K: Clone + Ord, V: Clone> {
    Leaf,
    Node {
        color: Color,
        left: Arc<Tree<K, V>>,
        key: K,
        value: V,
        right: Arc<Tree<K, V>>,
    },
}

impl<K: Clone + Ord, V: Clone> Tree<K, V> {
    fn node(color: Color, left: Arc<Tree<K, V>>, key: K, value: V, right: Arc<Tree<K, V>>) -> Arc<Tree<K, V>> {
        Arc::new(Tree::Node { color, left, key, value, right })
    }

    fn leaf() -> Arc<Tree<K, V>> {
        Arc::new(Tree::Leaf)
    }

    fn is_red(t: &Arc<Tree<K, V>>) -> bool {
        matches!(t.as_ref(), Tree::Node { color: Color::Red, .. })
    }

    /// Okasaki-style balance: fixes red-red violations after insertion
    ///
    /// There are four cases where a black node has a red child with a red grandchild.
    /// All four are transformed into the same balanced form.
    fn balance(color: Color, left: Arc<Tree<K, V>>, key: K, value: V, right: Arc<Tree<K, V>>) -> Arc<Tree<K, V>> {
        // Case 1: black(red(red(a,x,b),y,c),z,d)
        if color == Color::Black {
            if let Tree::Node { color: Color::Red, left: ll, key: lk, value: lv, right: lr } = left.as_ref() {
                if let Tree::Node { color: Color::Red, left: lll, key: llk, value: llv, right: llr } = ll.as_ref() {
                    return Tree::node(
                        Color::Red,
                        Tree::node(Color::Black, lll.clone(), llk.clone(), llv.clone(), llr.clone()),
                        lk.clone(), lv.clone(),
                        Tree::node(Color::Black, lr.clone(), key, value, right),
                    );
                }
                // Case 2: black(red(a,x,red(b,y,c)),z,d)
                if let Tree::Node { color: Color::Red, left: lrl, key: lrk, value: lrv, right: lrr } = lr.as_ref() {
                    return Tree::node(
                        Color::Red,
                        Tree::node(Color::Black, ll.clone(), lk.clone(), lv.clone(), lrl.clone()),
                        lrk.clone(), lrv.clone(),
                        Tree::node(Color::Black, lrr.clone(), key, value, right),
                    );
                }
            }
            // Case 3: black(a,x,red(red(b,y,c),z,d))
            if let Tree::Node { color: Color::Red, left: rl, key: rk, value: rv, right: rr } = right.as_ref() {
                if let Tree::Node { color: Color::Red, left: rll, key: rlk, value: rlv, right: rlr } = rl.as_ref() {
                    return Tree::node(
                        Color::Red,
                        Tree::node(Color::Black, left, key, value, rll.clone()),
                        rlk.clone(), rlv.clone(),
                        Tree::node(Color::Black, rlr.clone(), rk.clone(), rv.clone(), rr.clone()),
                    );
                }
                // Case 4: black(a,x,red(b,y,red(c,z,d)))
                if let Tree::Node { color: Color::Red, left: rrl, key: rrk, value: rrv, right: rrr } = rr.as_ref() {
                    return Tree::node(
                        Color::Red,
                        Tree::node(Color::Black, left, key, value, rl.clone()),
                        rk.clone(), rv.clone(),
                        Tree::node(Color::Black, rrl.clone(), rrk.clone(), rrv.clone(), rrr.clone()),
                    );
                }
            }
        }
        // No rebalancing needed
        Tree::node(color, left, key, value, right)
    }

    /// Insert a key-value pair, returning the (possibly new) root Arc
    fn insert_inner(tree: &Arc<Tree<K, V>>, key: K, value: V) -> Arc<Tree<K, V>> {
        match tree.as_ref() {
            Tree::Leaf => Tree::node(Color::Red, Tree::leaf(), key, value, Tree::leaf()),
            Tree::Node { color, left, key: k, value: v, right } => {
                match key.cmp(k) {
                    std::cmp::Ordering::Less => {
                        Tree::balance(
                            color.clone(),
                            Tree::insert_inner(left, key, value),
                            k.clone(), v.clone(),
                            right.clone(),
                        )
                    }
                    std::cmp::Ordering::Greater => {
                        Tree::balance(
                            color.clone(),
                            left.clone(),
                            k.clone(), v.clone(),
                            Tree::insert_inner(right, key, value),
                        )
                    }
                    std::cmp::Ordering::Equal => {
                        // Replace value, keep structure/color
                        Tree::node(color.clone(), left.clone(), key, value, right.clone())
                    }
                }
            }
        }
    }

    fn get_inner(tree: &Arc<Tree<K, V>>, key: &K) -> Option<V> {
        match tree.as_ref() {
            Tree::Leaf => None,
            Tree::Node { left, key: k, value, right, .. } => {
                match key.cmp(k) {
                    std::cmp::Ordering::Less    => Tree::get_inner(left, key),
                    std::cmp::Ordering::Greater => Tree::get_inner(right, key),
                    std::cmp::Ordering::Equal   => Some(value.clone()),
                }
            }
        }
    }

    fn contains_inner(tree: &Arc<Tree<K, V>>, key: &K) -> bool {
        Tree::get_inner(tree, key).is_some()
    }

    /// Collect all key-value pairs in sorted order
    fn to_sorted_vec_inner(tree: &Arc<Tree<K, V>>, acc: &mut Vec<(K, V)>) {
        if let Tree::Node { left, key, value, right, .. } = tree.as_ref() {
            Tree::to_sorted_vec_inner(left, acc);
            acc.push((key.clone(), value.clone()));
            Tree::to_sorted_vec_inner(right, acc);
        }
    }

    /// Count nodes
    fn len_inner(tree: &Arc<Tree<K, V>>) -> usize {
        match tree.as_ref() {
            Tree::Leaf => 0,
            Tree::Node { left, right, .. } => 1 + Tree::len_inner(left) + Tree::len_inner(right),
        }
    }

    /// Verify red-black invariants (for testing)
    /// Returns black-height if valid, or None if invalid
    fn check_invariants(tree: &Arc<Tree<K, V>>) -> Option<usize> {
        match tree.as_ref() {
            Tree::Leaf => Some(1), // Leaf counts as black
            Tree::Node { color, left, right, .. } => {
                // Red nodes must have black children
                if *color == Color::Red {
                    if Tree::is_red(left) || Tree::is_red(right) {
                        return None; // Red-red violation
                    }
                }
                let lbh = Tree::check_invariants(left)?;
                let rbh = Tree::check_invariants(right)?;
                if lbh != rbh {
                    return None; // Black-height mismatch
                }
                Some(lbh + if *color == Color::Black { 1 } else { 0 })
            }
        }
    }
}

/// Public persistent red-black tree map
#[derive(Clone, Debug)]
pub struct PersistentMap<K: Clone + Ord, V: Clone> {
    root: Arc<Tree<K, V>>,
    size: usize,
}

impl<K: Clone + Ord, V: Clone> PersistentMap<K, V> {
    /// Create an empty map
    pub fn new() -> Self {
        PersistentMap {
            root: Tree::leaf(),
            size: 0,
        }
    }

    /// Insert or update a key, returning a new map (O(log n))
    pub fn insert(&self, key: K, value: V) -> Self {
        let already_exists = Tree::contains_inner(&self.root, &key);
        let new_root = Tree::insert_inner(&self.root, key, value);
        // Root must always be black
        let new_root = match new_root.as_ref() {
            Tree::Node { color: Color::Red, left, key: k, value: v, right } => {
                Tree::node(Color::Black, left.clone(), k.clone(), v.clone(), right.clone())
            }
            _ => new_root,
        };
        PersistentMap {
            root: new_root,
            size: if already_exists { self.size } else { self.size + 1 },
        }
    }

    /// Look up a key (O(log n))
    pub fn get(&self, key: &K) -> Option<V> {
        Tree::get_inner(&self.root, key)
    }

    /// Check if a key exists (O(log n))
    pub fn contains_key(&self, key: &K) -> bool {
        Tree::contains_inner(&self.root, key)
    }

    /// Number of entries
    pub fn len(&self) -> usize {
        self.size
    }

    /// True if empty
    pub fn is_empty(&self) -> bool {
        self.size == 0
    }

    /// Return all key-value pairs in sorted order
    pub fn to_sorted_vec(&self) -> Vec<(K, V)> {
        let mut result = Vec::with_capacity(self.size);
        Tree::to_sorted_vec_inner(&self.root, &mut result);
        result
    }

    /// Verify red-black invariants — useful for testing
    pub fn is_valid(&self) -> bool {
        // Root must be black
        if Tree::is_red(&self.root) {
            return false;
        }
        Tree::check_invariants(&self.root).is_some()
    }
}

impl<K: Clone + Ord, V: Clone> Default for PersistentMap<K, V> {
    fn default() -> Self {
        Self::new()
    }
}

impl<K: Clone + Ord + fmt::Display, V: Clone + fmt::Display> fmt::Display for PersistentMap<K, V> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{{")?;
        let pairs = self.to_sorted_vec();
        for (i, (k, v)) in pairs.iter().enumerate() {
            if i > 0 { write!(f, ", ")?; }
            write!(f, "{}: {}", k, v)?;
        }
        write!(f, "}}")
    }
}

// ─── Persistent Set built on top of PersistentMap ───────────────────────────

#[derive(Clone, Debug, Default)]
pub struct PersistentSet<K: Clone + Ord> {
    map: PersistentMap<K, ()>,
}

impl<K: Clone + Ord> PersistentSet<K> {
    pub fn new() -> Self {
        PersistentSet { map: PersistentMap::new() }
    }

    pub fn insert(&self, key: K) -> Self {
        PersistentSet { map: self.map.insert(key, ()) }
    }

    pub fn contains(&self, key: &K) -> bool {
        self.map.contains_key(key)
    }

    pub fn len(&self) -> usize {
        self.map.len()
    }

    pub fn is_empty(&self) -> bool {
        self.map.is_empty()
    }

    pub fn to_sorted_vec(&self) -> Vec<K> {
        self.map.to_sorted_vec().into_iter().map(|(k, _)| k).collect()
    }

    pub fn is_valid(&self) -> bool {
        self.map.is_valid()
    }
}

