    #[test]
    fn test_reachable_chain_survives() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate_root();
        let child = gc.allocate();
        let grandchild = gc.allocate();

        gc.set_field(child, "next", make_ref(grandchild));
        gc.set_field(root, "child", make_ref(child));

        gc.collect();

        assert!(gc.get_object(root).is_some());
        assert!(gc.get_object(child).is_some());
        assert!(gc.get_object(grandchild).is_some());
        assert_eq!(gc.heap_size(), 3);
    }

    #[test]
    fn test_cycle_collected_without_root() {
        let mut gc = TriColorGc::new();
        let a = gc.allocate();
        let b = gc.allocate();
        // a -> b -> a  (cycle, no root)
        gc.set_field(a, "next", make_ref(b));
        gc.set_field(b, "next", make_ref(a));

        gc.collect();
        assert_eq!(gc.heap_size(), 0, "cyclic garbage must be collected");
    }

    #[test]
    fn test_cycle_survives_when_rooted() {
        let mut gc = TriColorGc::new();
        let a = gc.allocate_root();
        let b = gc.allocate();
        gc.set_field(a, "next", make_ref(b));
        gc.set_field(b, "next", make_ref(a));

        gc.collect();
        assert_eq!(gc.heap_size(), 2);
    }

    #[test]
    fn test_remove_root_allows_collection() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate_root();
        gc.collect();
        assert_eq!(gc.heap_size(), 1);

        gc.remove_root(root);
        gc.collect();
        assert_eq!(gc.heap_size(), 0);
    }

    #[test]
    fn test_multiple_roots() {
        let mut gc = TriColorGc::new();
        let r1 = gc.allocate_root();
        let r2 = gc.allocate_root();
        let shared = gc.allocate();

        gc.set_field(r1, "shared", make_ref(shared));
        gc.set_field(r2, "shared", make_ref(shared));

        let dangling = gc.allocate(); // nobody points here
        let _ = dangling;

        gc.collect();
        assert_eq!(gc.heap_size(), 3); // r1, r2, shared
        assert!(gc.get_object(shared).is_some());
    }

    // ----------------------------------------------------------
    // Incremental GC
    // ----------------------------------------------------------

    #[test]
    fn test_incremental_basic() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate_root();
        let child = gc.allocate();
        gc.set_field(root, "c", make_ref(child));
        let _dangling = gc.allocate();

        gc.incremental_start();
        loop {
            if gc.incremental_step(1) {
                break;
            }
        }
        gc.incremental_finish();

        assert!(gc.get_object(root).is_some());
        assert!(gc.get_object(child).is_some());
        assert_eq!(gc.heap_size(), 2);
    }

    #[test]
    fn test_incremental_collect_unreachable() {
        let mut gc = TriColorGc::new();
        let _root = gc.allocate_root();
        let _d1 = gc.allocate();
        let _d2 = gc.allocate();

        gc.incremental_start();
        while !gc.incremental_step(1) {}
        gc.incremental_finish();

        assert_eq!(gc.heap_size(), 1);
    }

    // ----------------------------------------------------------
    // Write barrier
    // ----------------------------------------------------------

    #[test]
    fn test_write_barrier_reshades_white_to_gray() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate_root();
        let white_obj = gc.allocate();

        // Start incremental cycle — root goes Gray
        gc.incremental_start();
        // Step once: root -> Black
        gc.incremental_step(1);

        // Now root is Black.  Write a reference from root to white_obj.
        // The write barrier should reshade white_obj gray.
        let event = gc.set_field(root, "new_ref", make_ref(white_obj));
        assert!(
            event.is_some(),
            "write barrier must fire for black->white pointer"
        );

        // Complete the cycle
        while !gc.incremental_step(1) {}
        gc.incremental_finish();

        // white_obj must have been rescued by the write barrier
        assert!(gc.get_object(white_obj).is_some());
    }

    // ----------------------------------------------------------
    // Value types
    // ----------------------------------------------------------

    #[test]
    fn test_array_value_references_traced() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate_root();
        let a = gc.allocate();
        let b = gc.allocate();

        // Store an array containing two references inside root
        gc.set_field(
            root,
            "arr",
            Value::Array(vec![make_ref(a), make_ref(b), Value::Integer(42)]),
        );

        let dangling = gc.allocate();
        let _ = dangling;

        gc.collect();

        assert!(gc.get_object(a).is_some());
        assert!(gc.get_object(b).is_some());
        assert_eq!(gc.heap_size(), 3);
    }

    #[test]
    fn test_primitive_fields_do_not_affect_reachability() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate_root();
        gc.set_field(root, "x", Value::Integer(100));
        gc.set_field(root, "s", Value::String("hello".into()));
        gc.set_field(root, "b", Value::Boolean(true));

        let orphan = gc.allocate();
        let _ = orphan;

        gc.collect();
        assert_eq!(gc.heap_size(), 1);
    }

    // ----------------------------------------------------------
    // Stats
    // ----------------------------------------------------------

    #[test]
    fn test_stats_tracking() {
        let mut gc = TriColorGc::new();
        let _r = gc.allocate_root();
        let _d = gc.allocate();
        gc.collect();

        assert_eq!(gc.stats.collections_run, 1);
        assert_eq!(gc.stats.objects_allocated, 2);
        assert_eq!(gc.stats.objects_collected, 1);
        assert_eq!(gc.stats.objects_survived, 1);
    }

    #[test]
    fn test_empty_heap_collection() {
        let mut gc = TriColorGc::new();
        gc.collect(); // must not panic
        assert_eq!(gc.stats.objects_collected, 0);
    }

    #[test]
    fn test_multiple_collections() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate_root();

        for i in 0..5 {
            let tmp = gc.allocate();
            gc.set_field(root, format!("t{}", i), make_ref(tmp));
            gc.collect();
        }

        // After each collect the tmp object is still referenced by root
        assert!(gc.heap_size() >= 1);
        assert_eq!(gc.stats.collections_run, 5);
    }
}

