// Demo main
// ============================================================

fn main() {
    println!("╔══════════════════════════════════════════╗");
    println!("║     Tri-Color Garbage Collector Demo     ║");
    println!("╚══════════════════════════════════════════╝");

    // ── Demo 1: Stop-the-world ─────────────────────────────
    println!("\n▶ Demo 1: Stop-the-world collection");

    let mut gc = TriColorGc::new();

    // Build a small object graph
    let root = gc.allocate_root();
    let child1 = gc.allocate();
    let child2 = gc.allocate();
    let grandchild = gc.allocate();
    let orphan = gc.allocate(); // nothing points here

    gc.set_field(root, "name", Value::String("root".into()));
    gc.set_field(root, "left", Value::Reference(child1));
    gc.set_field(root, "right", Value::Reference(child2));
    gc.set_field(child1, "data", Value::Integer(42));
    gc.set_field(child1, "child", Value::Reference(grandchild));
    gc.set_field(child2, "data", Value::Float(3.14));
    gc.set_field(grandchild, "leaf", Value::Boolean(true));
    gc.set_field(orphan, "lost", Value::String("I will be collected".into()));

    println!("\nBefore GC:");
    gc.print_heap();

    gc.collect();

    println!("After GC:");
    gc.print_heap();

    // ── Demo 2: Cyclic garbage ─────────────────────────────
    println!("\n▶ Demo 2: Cyclic garbage collection");

    let mut gc2 = TriColorGc::new();
    let root2 = gc2.allocate_root();
    let cycle_a = gc2.allocate();
    let cycle_b = gc2.allocate();

    // root -> cycle_a -> cycle_b -> cycle_a  (cycle with no path from root)
    gc2.set_field(cycle_a, "next", Value::Reference(cycle_b));
    gc2.set_field(cycle_b, "next", Value::Reference(cycle_a));
    // Note: root2 does NOT point to cycle_a

    println!("Heap before GC (cycle_a and cycle_b unreachable):");
    gc2.print_heap();

    gc2.collect();

    println!("Heap after GC:");
    gc2.print_heap();
    assert_eq!(gc2.heap_size(), 1);
    println!("✓ Cyclic garbage correctly collected");

    // ── Demo 3: Incremental GC ─────────────────────────────
    println!("\n▶ Demo 3: Incremental (step-by-step) GC");

    let mut gc3 = TriColorGc::new();
    let root3 = gc3.allocate_root();
    let a = gc3.allocate();
    let b = gc3.allocate();
    let c = gc3.allocate(); // unreachable
    let _ = c;

    gc3.set_field(root3, "a", Value::Reference(a));
    gc3.set_field(a, "b", Value::Reference(b));

    gc3.incremental_start();

    let mut step = 0;
    loop {
        println!("  Step {}:", step);
        gc3.print_colors();
        step += 1;
        if gc3.incremental_step(1) {
            break;
        }
    }
    println!("  Marking complete after {} steps", step);
    gc3.incremental_finish();

    println!("After incremental GC:");
    gc3.print_heap();

    // ── Demo 4: Write barrier ──────────────────────────────
    println!("\n▶ Demo 4: Write barrier during incremental GC");

    let mut gc4 = TriColorGc::new();
    let root4 = gc4.allocate_root();
    let late_obj = gc4.allocate(); // will be introduced mid-cycle

    gc4.incremental_start();
    // Step enough to make root4 black
    gc4.incremental_step(1);
    println!("  root4 is now Black");

    println!(
        "  Writing reference from Black root4 to White late_obj {}",
        late_obj
    );
    let event = gc4.set_field(root4, "late", Value::Reference(late_obj));
    println!("  Write barrier event: {:?}", event);

    while !gc4.incremental_step(1) {}
    gc4.incremental_finish();

    assert!(gc4.get_object(late_obj).is_some(), "late_obj must survive");
    println!("✓ late_obj survived thanks to the write barrier");

    // ── Summary ────────────────────────────────────────────
    println!("\n══════════ Final Statistics ══════════");
    println!("GC1: {}", gc.stats);
    println!("GC2: {}", gc2.stats);
    println!("GC3: {}", gc3.stats);
    println!("GC4: {}", gc4.stats);
}
```

## How It Works

### Algorithm Phases

| Phase | Action |
|-------|--------|
| **Reset** | All heap objects colored **White** |
| **Mark roots** | Root set objects colored **Gray**, added to worklist |
| **Propagate** | Pop Gray → color children Gray → color self **Black** |
| **Sweep** | Delete all remaining **White** objects |

### Key Design Decisions

#### Tri-Color Invariant
> *No **Black** object may point directly to a **White** object.*

This invariant ensures that white objects reachable from black objects are not incorrectly collected.

#### Write Barrier (Dijkstra style)
When a **black → white** pointer is created during an incremental cycle, the white target is immediately reshaded **gray** and added to the worklist, preserving the invariant.

#### Incremental vs Stop-the-World
- **STW** (`collect`): Runs all three phases atomically
- **Incremental**: `incremental_start` → repeated `incremental_step(n)` → `incremental_finish`
- New allocations during incremental GC are born **Black** (floating garbage is acceptable; it is collected next cycle)

### Running

```bash
cargo run      # Runs the demo
cargo test     # Runs all 15 tests
```

# SQL SELECT Parser in Rust

Here's a complete implementation of a basic SQL SELECT parser that handles common SELECT statement syntax.

## Supported Syntax

```sql
SELECT [DISTINCT] <columns> FROM <table>
  [JOIN <table> ON <condition>]
  [WHERE <condition>]
  [GROUP BY <columns>]
  [HAVING <condition>]
  [ORDER BY <column> [ASC|DESC]]
  [LIMIT <n>]
```

## Implementation

```rust
#[derive(Debug, Clone, PartialEq)]
pub enum Token {
    Keyword(String),
    Identifier(String),
    StringLiteral(String),
    NumberLiteral(String),
    Operator(String),
    Comma,
    LeftParen,
    RightParen,
    Dot,
    Star,
    Semicolon,
    EOF,
}

// ── Lexer ────────────────────────────────────────────────────────────────────

pub struct Lexer {
    input: Vec<char>,
    pos: usize,
}

const KEYWORDS: &[&str] = &[
    "SELECT", "FROM", "WHERE", "JOIN", "INNER", "LEFT", "RIGHT", "FULL",
    "OUTER", "ON", "GROUP", "BY", "ORDER", "HAVING", "LIMIT", "OFFSET",
    "AND", "OR", "NOT", "IN", "LIKE", "BETWEEN", "IS", "NULL", "ASC",
    "DESC", "DISTINCT", "AS", "CROSS",
];

impl Lexer {
    pub fn new(input: &str) -> Self {
        Lexer { input: input.chars().collect(), pos: 0 }
    }

    fn peek(&self) -> Option<char> {
        self.input.get(self.pos).copied()
    }

    fn advance(&mut self) -> Option<char> {
        let ch = self.input.get(self.pos).copied();
        self.pos += 1;
        ch
    }

    fn skip_whitespace(&mut self) {
        while self.peek().map_or(false, |c| c.is_whitespace()) {
            self.advance();
        }
    }

    fn read_word(&mut self) -> String {
        let mut word = String::new();
        while self.peek().map_or(false, |c| c.is_alphanumeric() || c == '_') {
            word.push(self.advance().unwrap());
        }
        word
    }

    fn read_string(&mut self) -> Result<String, String> {
        // consume opening quote
        self.advance();
        let mut s = String::new();
        loop {
            match self.advance() {
                Some('\'') => break,
                Some(c) => s.push(c),
                None => return Err("Unterminated string literal".into()),
            }
        }
        Ok(s)
    }

    fn read_number(&mut self) -> String {
        let mut n = String::new();
        while self.peek().map_or(false, |c| c.is_ascii_digit() || c == '.') {
            n.push(self.advance().unwrap());
        }
        n
    }

    pub fn tokenize(&mut self) -> Result<Vec<Token>, String> {
        let mut tokens = Vec::new();
        loop {
            self.skip_whitespace();
            match self.peek() {
                None => { tokens.push(Token::EOF); break; }
                Some('\'') => tokens.push(Token::StringLiteral(self.read_string()?)),
                Some(',') => { self.advance(); tokens.push(Token::Comma); }
                Some('(') => { self.advance(); tokens.push(Token::LeftParen); }
                Some(')') => { self.advance(); tokens.push(Token::RightParen); }
                Some('.') => { self.advance(); tokens.push(Token::Dot); }
                Some('*') => { self.advance(); tokens.push(Token::Star); }
                Some(';') => { self.advance(); tokens.push(Token::Semicolon); }
                Some('!') | Some('<') | Some('>') | Some('=') => {
                    tokens.push(Token::Operator(self.read_operator()));
                }
                Some(c) if c.is_alphabetic() || c == '_' => {
                    let word = self.read_word();
                    let upper = word.to_uppercase();
                    if KEYWORDS.contains(&upper.as_str()) {
                        tokens.push(Token::Keyword(upper));
                    } else {
                        tokens.push(Token::Identifier(word));
                    }
                }
                Some(c) if c.is_ascii_digit() => {
                    tokens.push(Token::NumberLiteral(self.read_number()));
                }
                Some(c) => return Err(format!("Unexpected character: '{c}'")),
            }
        }
        Ok(tokens)
    }

    fn read_operator(&mut self) -> String {
        let mut op = String::new();
        op.push(self.advance().unwrap());
        if matches!(self.peek(), Some('=') | Some('>')) {
            op.push(self.advance().unwrap());
        }
        op
    }
}

// ── AST ──────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq)]
pub enum Expr {
    Identifier(String),
    QualifiedIdentifier(String, String), // table.column
    StringLiteral(String),
    NumberLiteral(String),
    Wildcard,                             // *
    QualifiedWildcard(String),            // table.*
    FunctionCall { name: String, args: Vec<Expr> },
    BinaryOp { left: Box<Expr>, op: String, right: Box<Expr> },
    UnaryOp { op: String, expr: Box<Expr> },
    IsNull { expr: Box<Expr>, negated: bool },
    Between { expr: Box<Expr>, low: Box<Expr>, high: Box<Expr>, negated: bool },
    InList { expr: Box<Expr>, list: Vec<Expr>, negated: bool },
    Like { expr: Box<Expr>, pattern: Box<Expr>, negated: bool },
    Aliased { expr: Box<Expr>, alias: String },
}

#[derive(Debug, Clone, PartialEq)]
pub enum JoinType {
    Inner,
    Left,
    Right,
    Full,
    Cross,
}

#[derive(Debug, Clone, PartialEq)]
pub struct Join {
    pub join_type: JoinType,
    pub table: String,
    pub alias: Option<String>,
    pub on: Option<Expr>,
}

#[derive(Debug, Clone, PartialEq)]
pub enum OrderDirection {
    Asc,
    Desc,
}

#[derive(Debug, Clone, PartialEq)]
pub struct OrderByClause {
    pub expr: Expr,
    pub direction: OrderDirection,
}

#[derive(Debug, Clone, PartialEq)]
pub struct SelectStatement {
    pub distinct: bool,
    pub columns: Vec<Expr>,
    pub from: Option<String>,
    pub from_alias: Option<String>,
    pub joins: Vec<Join>,
    pub where_clause: Option<Expr>,
    pub group_by: Vec<Expr>,
    pub having: Option<Expr>,
    pub order_by: Vec<OrderByClause>,
    pub limit: Option<u64>,
    pub offset: Option<u64>,
}

// ── Parser ───────────────────────────────────────────────────────────────────

pub struct Parser {
    tokens: Vec<Token>,
    pos: usize,
}

impl Parser {
    pub fn new(tokens: Vec<Token>) -> Self {
        Parser { tokens, pos: 0 }
    }

    // ── Token navigation ─────────────────────────────────────────────────────

    fn peek(&self) -> &Token {
        self.tokens.get(self.pos).unwrap_or(&Token::EOF)
    }

    fn advance(&mut self) -> &Token {
        let tok = self.tokens.get(self.pos).unwrap_or(&Token::EOF);
        self.pos += 1;
        tok
    }

    fn expect_keyword(&mut self, kw: &str) -> Result<(), String> {
        match self.peek() {
            Token::Keyword(k) if k == kw => { self.advance(); Ok(()) }
            other => Err(format!("Expected keyword '{kw}', got {other:?}")),
        }
    }

    fn eat_keyword(&mut self, kw: &str) -> bool {
        match self.peek() {
            Token::Keyword(k) if k == kw => { self.advance(); true }
            _ => false,
        }
    }

    fn expect_identifier(&mut self) -> Result<String, String> {
        match self.advance().clone() {
            Token::Identifier(name) => Ok(name),
            other => Err(format!("Expected identifier, got {other:?}")),
        }
    }

    fn peek_keyword(&self, kw: &str) -> bool {
        matches!(self.peek(), Token::Keyword(k) if k == kw)
    }

    fn is_clause_start(&self) -> bool {
        matches!(
            self.peek(),
            Token::Keyword(k) if matches!(
                k.as_str(),
                "FROM" | "WHERE" | "GROUP" | "ORDER" | "HAVING" |
                "LIMIT" | "OFFSET" | "JOIN" | "INNER" | "LEFT" |
                "RIGHT" | "FULL" | "CROSS" | "ON"
            )
        )
    }

    // ── Top-level ─────────────────────────────────────────────────────────────

    pub fn parse_select(&mut self) -> Result<SelectStatement, String> {
        self.expect_keyword("SELECT")?;

        let distinct = self.eat_keyword("DISTINCT");
        let columns = self.parse_select_columns()?;

        let (from, from_alias) = if self.eat_keyword("FROM") {
            let table = self.expect_identifier()?;
            let alias = self.parse_optional_alias();
            (Some(table), alias)
        } else {
            (None, None)
        };

        let joins = self.parse_joins()?;

        let where_clause = if self.eat_keyword("WHERE") {
            Some(self.parse_expr(0)?)
        } else {
            None
        };

        let group_by = if self.peek_keyword("GROUP") {
            self.advance(); // GROUP
            self.expect_keyword("BY")?;
            self.parse_expr_list()?
        } else {
            vec![]
        };

        let having = if self.eat_keyword("HAVING") {
            Some(self.parse_expr(0)?)
        } else {
            None
        };

        let order_by = if self.peek_keyword("ORDER") {
            self.advance(); // ORDER
            self.expect_keyword("BY")?;
            self.parse_order_by()?
        } else {
            vec![]
        };

        let limit = if self.eat_keyword("LIMIT") {
            Some(self.parse_u64()?)
        } else {
            None
        };

        let offset = if self.eat_keyword("OFFSET") {
            Some(self.parse_u64()?)
        } else {
            None
        };

        // optional trailing semicolon
        if matches!(self.peek(), Token::Semicolon) { self.advance(); }

        Ok(SelectStatement {
            distinct,
            columns,
            from,
            from_alias,
            joins,
            where_clause,
            group_by,
            having,
            order_by,
            limit,
            offset,
        })
    }

    // ── SELECT columns ────────────────────────────────────────────────────────

    fn parse_select_columns(&mut self) -> Result<Vec<Expr>, String> {
        let mut cols = vec![self.parse_select_expr()?];
        while matches!(self.peek(), Token::Comma) {
            self.advance();
            cols.push(self.parse_select_expr()?);
        }
        Ok(cols)
    }

    /// Like parse_expr but also handles trailing AS alias
    fn parse_select_expr(&mut self) -> Result<Expr, String> {
        let expr = self.parse_expr(0)?;
        let alias = self.parse_optional_alias();
        Ok(match alias {
            Some(a) => Expr::Aliased { expr: Box::new(expr), alias: a },
            None => expr,
        })
    }

    fn parse_optional_alias(&mut self) -> Option<String> {
        // explicit AS
        if self.eat_keyword("AS") {
            return match self.advance().clone() {
                Token::Identifier(a) => Some(a),
                _ => None,
            };
        }
        // implicit alias: next token is a plain identifier not followed by a clause start
        if let Token::Identifier(_) = self.peek() {
            if !self.is_clause_start() {
                if let Token::Identifier(a) = self.advance().clone() {
                    return Some(a);
                }
            }
        }
        None
    }

    // ── Expression parsing (Pratt / precedence climbing) ─────────────────────

    fn parse_expr(&mut self, min_prec: u8) -> Result<Expr, String> {
        let mut lhs = self.parse_unary()?;

        loop {
            // postfix IS [NOT] NULL
            if self.peek_keyword("IS") {
                self.advance();
                let negated = self.eat_keyword("NOT");
                self.expect_keyword("NULL")?;
                lhs = Expr::IsNull { expr: Box::new(lhs), negated };
                continue;
            }

            // postfix [NOT] BETWEEN
            let negated_between = self.eat_keyword("NOT");
            if self.peek_keyword("BETWEEN") {
                self.advance();
                let low = self.parse_expr(0)?;
                self.expect_keyword("AND")?;
                let high = self.parse_expr(0)?;
                lhs = Expr::Between {
                    expr: Box::new(lhs),
                    low: Box::new(low),
                    high: Box::new(high),
                    negated: negated_between,
                };
                continue;
            }

            // postfix [NOT] IN (...)
            if self.peek_keyword("IN") {
                self.advance();
                let list = self.parse_paren_expr_list()?;
                lhs = Expr::InList { expr: Box::new(lhs), list, negated: negated_between };
                continue;
            }

            // postfix [NOT] LIKE
            if self.peek_keyword("LIKE") {
                self.advance();
                let pattern = self.parse_unary()?;
                lhs = Expr::Like {
                    expr: Box::new(lhs),
                    pattern: Box::new(pattern),
                    negated: negated_between,
                };
                continue;
            }

            // if we consumed NOT but didn't match BETWEEN/IN/LIKE, that's an error
            if negated_between {
                return Err("Expected BETWEEN, IN, or LIKE after NOT".into());
            }

            // binary infix operators
            let (op, prec, right_assoc) = match self.peek_infix_op() {
                Some(t) => t,
                None => break,
            };
            if prec < min_prec { break; }

            self.advance(); // consume operator token

            // handle two-token operators: NOT IN, NOT LIKE are handled above;
            // here we only hit single-token ops
            let next_prec = if right_assoc { prec } else { prec + 1 };
            let rhs = self.parse_expr(next_prec)?;
            lhs = Expr::BinaryOp { left: Box::new(lhs), op, right: Box::new(rhs) };
        }

        Ok(lhs)
    }

    /// Returns (operator_string, precedence, right_associative)
    fn peek_infix_op(&self) -> Option<(String, u8, bool)> {
        match self.peek() {
            Token::Keyword(k) => match k.as_str() {
                "OR"  => Some(("OR".into(),  1, false)),
                "AND" => Some(("AND".into(), 2, false)),
                _ => None,
            },
            Token::Operator(op) => {
                let prec = match op.as_str() {
                    "=" | "!=" | "<>" => 3,
                    "<" | "<=" | ">" | ">=" => 4,
                    _ => return None,
                };
                Some((op.clone(), prec, false))
            }
            _ => None,
        }
    }

    fn parse_unary(&mut self) -> Result<Expr, String> {
        if self.eat_keyword("NOT") {
            let expr = self.parse_unary()?;
            return Ok(Expr::UnaryOp { op: "NOT".into(), expr: Box::new(expr) });
        }
        self.parse_primary()
    }

    fn parse_primary(&mut self) -> Result<Expr, String> {
        match self.peek().clone() {
            Token::Star => {
                self.advance();
                Ok(Expr::Wildcard)
            }
            Token::NumberLiteral(n) => {
                self.advance();
                Ok(Expr::NumberLiteral(n))
            }
            Token::StringLiteral(s) => {
                self.advance();
                Ok(Expr::StringLiteral(s))
            }
            Token::Keyword(ref k) if k == "NULL" => {
                self.advance();
                Ok(Expr::Identifier("NULL".into()))
            }
            Token::LeftParen => {
                self.advance();
                let expr = self.parse_expr(0)?;
                match self.advance().clone() {
                    Token::RightParen => Ok(expr),
                    other => Err(format!("Expected ')', got {other:?}")),
                }
            }
            Token::Identifier(_) => self.parse_identifier_or_call(),
            other => Err(format!("Unexpected token in expression: {other:?}")),
        }
    }

    fn parse_identifier_or_call(&mut self) -> Result<Expr, String> {
        let name = self.expect_identifier()?;

        // qualified: name.something or name.*
        if matches!(self.peek(), Token::Dot) {
            self.advance();
            return match self.peek().clone() {
                Token::Star => {
                    self.advance();
                    Ok(Expr::QualifiedWildcard(name))
                }
                Token::Identifier(_) => {
                    let col = self.expect_identifier()?;
                    // could be a function call like schema.func(...)
                    if matches!(self.peek(), Token::LeftParen) {
                        let args = self.parse_paren_expr_list()?;
                        Ok(Expr::FunctionCall { name: format!("{name}.{col}"), args })
                    } else {
                        Ok(Expr::QualifiedIdentifier(name, col))
                    }
                }
                other => Err(format!("Expected column name or * after '.', got {other:?}")),
            };
        }

        // function call
        if matches!(self.peek(), Token::LeftParen) {
            let args = self.parse_paren_expr_list()?;
            return Ok(Expr::FunctionCall { name, args });
        }

        Ok(Expr::Identifier(name))
    }

    // ── List helpers ──────────────────────────────────────────────────────────

    fn parse_expr_list(&mut self) -> Result<Vec<Expr>, String> {
        let mut list = vec![self.parse_expr(0)?];
        while matches!(self.peek(), Token::Comma) {
            self.advance();
            list.push(self.parse_expr(0)?);
        }
        Ok(list)
    }

    fn parse_paren_expr_list(&mut self) -> Result<Vec<Expr>, String> {
        match self.advance().clone() {
            Token::LeftParen => {}
            other => return Err(format!("Expected '(', got {other:?}")),
        }
        if matches!(self.peek(), Token::RightParen) {
            self.advance();
            return Ok(vec![]);
        }
        let list = self.parse_expr_list()?;
        match self.advance().clone() {
            Token::RightParen => Ok(list),
            other => Err(format!("Expected ')', got {other:?}")),
        }
    }

    // ── JOIN ──────────────────────────────────────────────────────────────────

    fn parse_joins(&mut self) -> Result<Vec<Join>, String> {
        let mut joins = vec![];
        loop {
            let join_type = match self.peek().clone() {
                Token::Keyword(ref k) => match k.as_str() {
                    "JOIN"  => { self.advance(); JoinType::Inner }
                    "INNER" => { self.advance(); self.expect_keyword("JOIN")?; JoinType::Inner }
                    "CROSS" => { self.advance(); self.expect_keyword("JOIN")?; JoinType::Cross }
                    "LEFT"  => {
                        self.advance();
                        self.eat_keyword("OUTER");
                        self.expect_keyword("JOIN")?;
                        JoinType::Left
                    }
                    "RIGHT" => {
                        self.advance();
                        self.eat_keyword("OUTER");
                        self.expect_keyword("JOIN")?;
                        JoinType::Right
                    }
                    "FULL"  => {
                        self.advance();
                        self.eat_keyword("OUTER");
                        self.expect_keyword("JOIN")?;
                        JoinType::Full
                    }
                    _ => break,
                },
                _ => break,
            };

            let table = self.expect_identifier()?;
            let alias = self.parse_optional_alias();

            let on = if self.eat_keyword("ON") {
                Some(self.parse_expr(0)?)
            } else {
                None
            };

            joins.push(Join { join_type, table, alias, on });
        }
        Ok(joins)
    }

    // ── ORDER BY ──────────────────────────────────────────────────────────────

    fn parse_order_by(&mut self) -> Result<Vec<OrderByClause>, String> {
        let mut clauses = vec![self.parse_order_item()?];
        while matches!(self.peek(), Token::Comma) {
            self.advance();
            clauses.push(self.parse_order_item()?);
        }
        Ok(clauses)
    }

    fn parse_order_item(&mut self) -> Result<OrderByClause, String> {
        let expr = self.parse_expr(0)?;
        let direction = if self.eat_keyword("DESC") {
            OrderDirection::Desc
        } else {
            self.eat_keyword("ASC");
            OrderDirection::Asc
        };
        Ok(OrderByClause { expr, direction })
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    fn parse_u64(&mut self) -> Result<u64, String> {
        match self.advance().clone() {
            Token::NumberLiteral(n) => n.parse::<u64>().map_err(|e| e.to_string()),
            other => Err(format!("Expected number, got {other:?}")),
        }
    }
}

// ── Public entry point ────────────────────────────────────────────────────────

pub fn parse_sql(input: &str) -> Result<SelectStatement, String> {
    let tokens = Lexer::new(input).tokenize()?;
    Parser::new(tokens).parse_select()
}

