fn run_classic_example() {
    println!("╔══════════════════════════════════════════╗");
    println!("║  Classic Three-Process Lamport Example   ║");
    println!("╚══════════════════════════════════════════╝\n");

    let mut net = Network::new();
    net.add_process(1);
    net.add_process(2);
    net.add_process(3);

    // P1 does some local work then sends to P2
    net.local_event(1, "init");
    net.local_event(1, "compute A");
    net.send_message(1, 2, "data-A");

    // P2 receives, does local work, then sends to P3
    net.local_event(2, "init");
    // (receive happens inside send_message above)
    net.local_event(2, "process data-A");
    net.send_message(2, 3, "data-B");

    // P3 has already started independently
    net.local_event(3, "init");
    net.local_event(3, "independent work");
    // (receive happens inside send_message above)
    net.local_event(3, "final computation");

    // P1 also sends directly to P3
    net.send_message(1, 3, "data-C");
    net.local_event(3, "merge results");

    // Print per-process histories
    for id in [1, 2, 3] {
        net.print_process_history(id);
    }
    println!();

    // Build and print the global log
    net.build_global_log();
    net.print_global_log();
}

fn run_happens_before_demo() {
    println!("\n╔══════════════════════════════════════════╗");
    println!("║       Happens-Before Relationship        ║");
    println!("╚══════════════════════════════════════════╝\n");

    let e1 = TimestampedEvent::new(1, 1, EventKind::Local("A".into()));
    let e2 = TimestampedEvent::new(3, 1, EventKind::Local("B".into()));
    let e3 = TimestampedEvent::new(3, 2, EventKind::Local("C".into()));
    let e4 = TimestampedEvent::new(5, 2, EventKind::Local("D".into()));

    let pairs = [(&e1, &e2), (&e2, &e3), (&e1, &e4), (&e3, &e2)];
    for (a, b) in &pairs {
        println!(
            "  {} → {} : happens_before={}, concurrent={}",
            a, b,
            happens_before(a, b),
            concurrent(a, b)
        );
    }
}

fn run_concurrent_writes_demo() {
    println!("\n╔══════════════════════════════════════════╗");
    println!("║    Concurrent Writes (no causality link) ║");
    println!("╚══════════════════════════════════════════╝\n");

    let mut net = Network::new();
    net.add_process(10);
    net.add_process(20);
    net.add_process(30);

    // All three processes write independently with no messages exchanged.
    net.local_event(10, "write X=1");
    net.local_event(20, "write X=2");
    net.local_event(30, "write X=3");

    net.local_event(10, "write Y=10");
    net.local_event(20, "write Y=20");

    net.build_global_log();
    net.print_global_log();

    // Show that the writes are concurrent.
    let ev10 = &net.processes[&10].history[0];
    let ev20 = &net.processes[&20].history[0];
    println!("\n  Are P10's first write and P20's first write concurrent? {}",
        concurrent(ev10, ev20));
}

fn run_mutex_example() {
    println!("\n╔══════════════════════════════════════════╗");
    println!("║   Distributed Mutex via Lamport Ordering ║");
    println!("╚══════════════════════════════════════════╝\n");

    // In Lamport's mutex algorithm processes broadcast REQUEST, REPLY, RELEASE.
    // Here we simply simulate the timestamp ordering that the algorithm relies on.
    let mut net = Network::new();
    net.add_process(1);
    net.add_process(2);
    net.add_process(3);

    // P1 requests the lock
    net.local_event(1, "REQUEST lock");
    let ts1_req = net.processes[&1].clock.current_time();

    // P2 requests the lock slightly later
    net.local_event(2, "REQUEST lock");
    let ts2_req = net.processes[&2].clock.current_time();

    // Broadcast: P1 notifies P2 and P3
    net.send_message(1, 2, "REQUEST");
    net.send_message(1, 3, "REQUEST");

    // P2 and P3 reply to P1
    net.send_message(2, 1, "REPLY");
    net.send_message(3, 1, "REPLY");

    // P1 enters critical section (lower timestamp wins)
    net.local_event(1, "ENTER critical section");
    net.local_event(1, "RELEASE lock");

    // Broadcast release
    net.send_message(1, 2, "RELEASE");
    net.send_message(1, 3, "RELEASE");

    // Now P2 can enter (it had the next lowest request timestamp)
    net.local_event(2, "ENTER critical section");
    net.local_event(2, "RELEASE lock");

    println!("  P1 requested at T={}, P2 requested at T={}", ts1_req, ts2_req);
    println!("  P1 wins because T(P1) < T(P2)\n");

    net.build_global_log();
    net.print_global_log();
}

fn main() {
    run_classic_example();
    run_happens_before_demo();
    run_concurrent_writes_demo();
    run_mutex_example();
}

