fn main() {
    let mut sl: SkipList<i32, &str> = SkipList::new();

    println!("=== Skip List Demo ===\n");

    // Insert elements
    let entries = [(5, "five"), (3, "three"), (7, "seven"),
                   (1, "one"),  (4, "four"), (6, "six"), (2, "two")];

    for (k, v) in &entries {
        sl.insert(*k, *v);
        println!("Inserted ({}, {})", k, v);
    }

    println!("\n{}", sl);

    // Look up values
    println!("--- Lookups ---");
    for k in [1, 4, 7, 9] {
        match sl.get(&k) {
            Some(v) => println!("get({}) = {}", k, v),
            None    => println!("get({}) = not found", k),
        }
    }

    // Update a value
    println!("\n--- Update key 3 ---");
    sl.insert(3, "THREE (updated)");
    println!("get(3) = {:?}", sl.get(&3));

    // Remove elements
    println!("\n--- Removals ---");
    for k in [1, 4, 9] {
        println!("remove({}) = {:?}", k, sl.remove(&k));
    }

    println!("\nAfter removals:\n{}", sl);

    // Iterate in sorted order
    println!("--- Sorted iteration ---");
    for (k, v) in sl.iter() {
        println!("  {} => {}", k, v);
