### Key Insights

1. **Row constraint is implicit** — we place exactly one queen per row
2. **Column check**: `prev_col == col`
3. **Diagonal check**: `|row_diff| == |col_diff|` — queens on same diagonal have equal row and column distances
4. **Backtracking**: if no valid column exists in a row, recursion unwinds and tries the next column in the previous row

# Rust Statistical Operations: Single Expression Chain

## Complete Implementation

```rust
fn main() {
    let data = vec![3.0_f64, 1.0, 4.0, 1.0, 5.0, 9.0, 2.0, 6.0, 5.0, 3.0, 5.0];

    // Single expression chain that sorts, reverses, computes median and std dev
    let (sorted_reversed, median, std_dev) = {
        let mut v = data.clone();
        v.sort_by(|a, b| a.partial_cmp(b).unwrap());
        v.reverse();
        let n = v.len() as f64;
        let median = if v.len() % 2 == 0 {
            (v[v.len() / 2 - 1] + v[v.len() / 2]) / 2.0
        } else {
            v[v.len() / 2]
        };
        let mean = v.iter().sum::<f64>() / n;
        let std_dev = (v.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / n).sqrt();
        (v, median, std_dev)
    };

    println!("Sorted (descending): {:?}", sorted_reversed);
    println!("Median:              {:.4}", median);
    println!("Std Deviation:       {:.4}", std_dev);
}
```

## Advanced Version: Functional Iterator Chain

```rust
fn compute_stats(data: &[f64]) -> (Vec<f64>, f64, f64) {
    // Pure functional approach using iterator adaptors
    let sorted_reversed: Vec<f64> = {
        let mut v = data.to_vec();
        v.sort_unstable_by(|a, b| b.partial_cmp(a).unwrap()); // Sort descending directly
        v
    };

    let (median, std_dev) = sorted_reversed
        .iter()
        .copied()
        .collect::<Vec<f64>>()
        .windows(sorted_reversed.len()) // Single window = whole slice
        .next()
        .map(|slice| {
            let n = slice.len();
            let mean: f64 = slice.iter().sum::<f64>() / n as f64;

            let median = if n % 2 == 0 {
                (slice[n / 2 - 1] + slice[n / 2]) / 2.0
            } else {
                slice[n / 2]
            };

            let variance: f64 = slice.iter()
                .map(|&x| (x - mean).powi(2))
                .sum::<f64>() / n as f64;

            (median, variance.sqrt())
        })
        .unwrap_or((0.0, 0.0));

    (sorted_reversed, median, std_dev)
}

fn main() {
    let datasets = vec![
        vec![3.0_f64, 1.0, 4.0, 1.0, 5.0, 9.0, 2.0, 6.0, 5.0, 3.0, 5.0],
        vec![10.0, 20.0, 30.0, 40.0, 50.0],
        vec![7.0, 7.0, 7.0, 7.0], // All same values
        vec![1.0, 100.0],          // Two elements (even length)
    ];

    for (i, data) in datasets.iter().enumerate() {
        println!("\n--- Dataset {} ---", i + 1);
        println!("Original:            {:?}", data);

        let (sorted_rev, median, std_dev) = compute_stats(data);

        println!("Sorted (descending): {:?}", sorted_rev);
        println!("Median:              {:.4}", median);
        println!("Std Deviation:       {:.4}", std_dev);
        println!("Mean:                {:.4}", sorted_rev.iter().sum::<f64>() / sorted_rev.len() as f64);
    }
}
```

