# Stack Data Structure in Rust

## Implementation

```rust
#[derive(Debug)]
pub struct Stack<T> {
    elements: Vec<T>,
    capacity: Option<usize>,
}

#[derive(Debug, PartialEq)]
pub enum StackError {
    Overflow,
    Underflow,
    Empty,
}

impl std::fmt::Display for StackError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            StackError::Overflow => write!(f, "Stack overflow: capacity exceeded"),
            StackError::Underflow => write!(f, "Stack underflow: cannot pop from empty stack"),
            StackError::Empty => write!(f, "Stack is empty"),
        }
    }
}

impl std::error::Error for StackError {}

impl<T> Stack<T> {
    /// Creates a new unbounded stack
    pub fn new() -> Self {
        Stack {
            elements: Vec::new(),
            capacity: None,
        }
    }

    /// Creates a new stack with a fixed capacity
    pub fn with_capacity(capacity: usize) -> Self {
        Stack {
            elements: Vec::with_capacity(capacity),
            capacity: Some(capacity),
        }
    }

    /// Pushes an element onto the top of the stack
    pub fn push(&mut self, item: T) -> Result<(), StackError> {
        if let Some(cap) = self.capacity {
            if self.elements.len() >= cap {
                return Err(StackError::Overflow);
            }
        }
        self.elements.push(item);
        Ok(())
    }

    /// Removes and returns the top element from the stack
    pub fn pop(&mut self) -> Result<T, StackError> {
        self.elements.pop().ok_or(StackError::Underflow)
    }

    /// Returns a reference to the top element without removing it
    pub fn peek(&self) -> Result<&T, StackError> {
        self.elements.last().ok_or(StackError::Empty)
    }

    /// Returns a mutable reference to the top element
    pub fn peek_mut(&mut self) -> Result<&mut T, StackError> {
        self.elements.last_mut().ok_or(StackError::Empty)
    }

    /// Returns true if the stack is empty
    pub fn is_empty(&self) -> bool {
        self.elements.is_empty()
    }

    /// Returns the number of elements in the stack
    pub fn size(&self) -> usize {
        self.elements.len()
    }

    /// Returns the optional capacity of the stack
    pub fn capacity(&self) -> Option<usize> {
        self.capacity
    }

    /// Clears all elements from the stack
    pub fn clear(&mut self) {
        self.elements.clear();
    }

    /// Returns an iterator over the stack from top to bottom
    pub fn iter(&self) -> impl Iterator<Item = &T> {
        self.elements.iter().rev()
    }
}

impl<T: Clone> Stack<T> {
    /// Returns a Vec of all elements from top to bottom
    pub fn to_vec(&self) -> Vec<T> {
        self.elements.iter().rev().cloned().collect()
    }
}

impl<T: std::fmt::Display> Stack<T> {
    /// Prints all elements from top to bottom
    pub fn display(&self) {
        print!("Stack (top→bottom): [");
        let mut iter = self.elements.iter().rev().peekable();
        while let Some(item) = iter.next() {
            if iter.peek().is_some() {
                print!("{}, ", item);
            } else {
                print!("{}", item);
            }
        }
        println!("]");
    }
}

impl<T> Default for Stack<T> {
    fn default() -> Self {
        Stack::new()
    }
}

// Allow creating a stack from an iterator
impl<T> FromIterator<T> for Stack<T> {
    fn from_iter<I: IntoIterator<Item = T>>(iter: I) -> Self {
        Stack {
            elements: Vec::from_iter(iter),
            capacity: None,
        }
    }
}

fn main() {
    println!("=== Basic Stack Operations ===");
    let mut stack: Stack<i32> = Stack::new();

    // Push elements
    for i in 1..=5 {
        stack.push(i).unwrap();
        println!("Pushed: {}", i);
    }

    stack.display();
    println!("Size: {}", stack.size());

    // Peek at top
    match stack.peek() {
        Ok(top) => println!("Top element: {}", top),
        Err(e) => println!("Error: {}", e),
    }

    // Pop elements
    println!("\n=== Popping Elements ===");
    while !stack.is_empty() {
        match stack.pop() {
            Ok(val) => println!("Popped: {}", val),
            Err(e) => println!("Error: {}", e),
        }
    }

    // Underflow error
    println!("\n=== Error Handling ===");
    match stack.pop() {
        Ok(val) => println!("Popped: {}", val),
        Err(e) => println!("Error caught: {}", e),
    }

    // Bounded stack
    println!("\n=== Bounded Stack (capacity: 3) ===");
    let mut bounded: Stack<&str> = Stack::with_capacity(3);
    bounded.push("first").unwrap();
    bounded.push("second").unwrap();
    bounded.push("third").unwrap();
    bounded.display();

    match bounded.push("fourth") {
        Ok(_) => println!("Pushed fourth"),
        Err(e) => println!("Error caught: {}", e),
    }

    // Stack from iterator
    println!("\n=== Stack from Iterator ===");
    let mut iter_stack: Stack<i32> = (1..=5).collect();
    iter_stack.display();
    println!("As Vec (top→bottom): {:?}", iter_stack.to_vec());

    // Practical example: balanced parentheses checker
    println!("\n=== Balanced Parentheses Checker ===");
    let test_cases = vec!["(())", "({[]})", "(()", "([)]", ""];
    for case in test_cases {
        println!("\"{}\" → {}", case, is_balanced(case));
    }
}

/// Example use case: Check if parentheses are balanced
fn is_balanced(s: &str) -> bool {
    let mut stack: Stack<char> = Stack::new();

    for ch in s.chars() {
        match ch {
            '(' | '[' | '{' => stack.push(ch).unwrap(),
            ')' | ']' | '}' => {
                let expected = match ch {
                    ')' => '(',
                    ']' => '[',
                    '}' => '{',
                    _ => unreachable!(),
                };
                match stack.pop() {
                    Ok(top) if top == expected => {}
                    _ => return false,
                }
            }
            _ => {}
        }
    }

    stack.is_empty()
}

