// --- 1. Recursive (simple but slow, O(2^n) time) ---
fn fibonacci_recursive(n: u64) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => fibonacci_recursive(n - 1) + fibonacci_recursive(n - 2),
    }
}

// --- 2. Iterative (fast, O(n) time, O(1) space) ---
fn fibonacci_iterative(n: u64) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => {
            let (mut prev, mut curr) = (0u64, 1u64);
            for _ in 2..=n {
                (prev, curr) = (curr, prev + curr);
            }
            curr
        }
    }
}

// --- 3. Memoized / Top-Down (O(n) time, O(n) space) ---
fn fibonacci_memoized(n: u64) -> u64 {
    let mut memo = vec![None; (n as usize) + 1];
    fib_memo_helper(n, &mut memo)
}

fn fib_memo_helper(n: u64, memo: &mut Vec<Option<u64>>) -> u64 {
    if let Some(val) = memo[n as usize] {
        return val;
    }
    let result = match n {
        0 => 0,
        1 => 1,
        _ => fib_memo_helper(n - 1, memo) + fib_memo_helper(n - 2, memo),
    };
    memo[n as usize] = Some(result);
    result
}

// --- 4. Iterator (lazy, infinite sequence) ---
struct FibIterator {
    prev: u64,
    curr: u64,
}

impl FibIterator {
    fn new() -> Self {
        FibIterator { prev: 0, curr: 1 }
    }
}

impl Iterator for FibIterator {
    type Item = u64;

    fn next(&mut self) -> Option<Self::Item> {
        let next_val = self.prev;
        (self.prev, self.curr) = (self.curr, self.prev + self.curr);
        Some(next_val)
    }
}
