# LRU Cache Implementation in Rust

## Overview

This implementation uses a **HashMap** for O(1) key lookups combined with a **doubly linked list** to maintain access order. The most recently used item is at the front, and the least recently used is at the back.

```rust
use std::collections::HashMap;
use std::hash::Hash;
use std::fmt::Debug;

/// A node in the doubly linked list
struct Node<K, V> {
    key: K,
    value: V,
    prev: Option<usize>,
    next: Option<usize>,
}

/// LRU Cache using a HashMap + doubly linked list via index-based arena
pub struct LruCache<K, V> {
    capacity: usize,
    map: HashMap<K, usize>,   // key -> node index in arena
    arena: Vec<Node<K, V>>,   // node storage
    free_list: Vec<usize>,    // recycled node indices
    head: Option<usize>,      // most recently used
    tail: Option<usize>,      // least recently used
}

impl<K, V> LruCache<K, V>
where
    K: Eq + Hash + Clone + Debug,
    V: Debug,
{
    /// Create a new LRU cache with the given capacity.
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0, "Capacity must be greater than zero");
        LruCache {
            capacity,
            map: HashMap::with_capacity(capacity),
            arena: Vec::with_capacity(capacity),
            free_list: Vec::new(),
            head: None,
            tail: None,
        }
    }

    /// Returns the number of items currently in the cache.
    pub fn len(&self) -> usize {
        self.map.len()
    }

    /// Returns true if the cache is empty.
    pub fn is_empty(&self) -> bool {
        self.map.is_empty()
    }

    /// Get the value associated with a key (marks it as recently used).
    pub fn get(&mut self, key: &K) -> Option<&V> {
        let idx = *self.map.get(key)?;
        self.move_to_front(idx);
        Some(&self.arena[idx].value)
    }

    /// Get a mutable reference to the value associated with a key.
    pub fn get_mut(&mut self, key: &K) -> Option<&mut V> {
        let idx = *self.map.get(key)?;
        self.move_to_front(idx);
        Some(&mut self.arena[idx].value)
    }

    /// Peek at a value without marking it as recently used.
    pub fn peek(&self, key: &K) -> Option<&V> {
        let idx = *self.map.get(key)?;
        Some(&self.arena[idx].value)
    }

    /// Insert a key-value pair. If the key exists, update its value.
    /// If at capacity, evict the least recently used entry.
    /// Returns the evicted key-value pair, if any.
    pub fn put(&mut self, key: K, value: V) -> Option<(K, V)> {
        // Key already exists: update value and move to front
        if let Some(&idx) = self.map.get(&key) {
            self.arena[idx].value = value;
            self.move_to_front(idx);
            return None;
        }

        let mut evicted = None;

        // Evict LRU entry if at capacity
        if self.map.len() == self.capacity {
            evicted = self.evict_lru();
        }

        // Allocate a node index
        let idx = if let Some(free_idx) = self.free_list.pop() {
            self.arena[free_idx] = Node { key: key.clone(), value, prev: None, next: None };
            free_idx
        } else {
            self.arena.push(Node { key: key.clone(), value, prev: None, next: None });
            self.arena.len() - 1
        };

        self.map.insert(key, idx);
        self.push_front(idx);

        evicted
    }

    /// Remove a key from the cache, returning its value if present.
    pub fn remove(&mut self, key: &K) -> Option<V> {
        let idx = self.map.remove(key)?;
        self.unlink(idx);
        self.free_list.push(idx);

        // We need to extract the value; swap with a dummy isn't possible,
        // so we rely on the fact that the slot is logically freed.
        // SAFETY: We've removed the key from the map, so this slot won't be accessed again
        // until reused (at which point it's overwritten in put()).
        let value = unsafe {
            std::ptr::read(&self.arena[idx].value)
        };

        // Prevent double-drop: we overwrite with a copy of the key placeholder.
        // Since we're managing memory manually via the arena/free_list,
        // we must ensure the old value isn't dropped again.
        std::mem::forget(unsafe { std::ptr::read(&self.arena[idx].value) });

        Some(value)
    }

    /// Check if the cache contains a key (without affecting order).
    pub fn contains_key(&self, key: &K) -> bool {
        self.map.contains_key(key)
    }

    /// Returns the cache capacity.
    pub fn capacity(&self) -> usize {
        self.capacity
    }

    /// Clear all entries from the cache.
    pub fn clear(&mut self) {
        self.map.clear();
        self.arena.clear();
        self.free_list.clear();
        self.head = None;
        self.tail = None;
    }

    /// Returns an iterator over (key, value) pairs from MRU to LRU order.
    pub fn iter(&self) -> LruIterator<K, V> {
        LruIterator {
            arena: &self.arena,
            current: self.head,
        }
    }

    // ---- Private helpers ----

    /// Evict the least recently used node (tail).
    fn evict_lru(&mut self) -> Option<(K, V)> {
        let tail_idx = self.tail?;
        let key = self.arena[tail_idx].key.clone();
        self.map.remove(&key);
        self.unlink(tail_idx);
        self.free_list.push(tail_idx);

        // Extract key and value from arena slot
        let k = unsafe { std::ptr::read(&self.arena[tail_idx].key) };
        let v = unsafe { std::ptr::read(&self.arena[tail_idx].value) };

        // Prevent double-drop for the cloned key we already dropped via map.remove
        // The arena slot will be overwritten on next use
        std::mem::forget(unsafe { std::ptr::read(&self.arena[tail_idx].key) });
        std::mem::forget(unsafe { std::ptr::read(&self.arena[tail_idx].value) });

        Some((k, v))
    }

    /// Move an existing node to the front of the list.
    fn move_to_front(&mut self, idx: usize) {
        if self.head == Some(idx) {
            return; // Already at front
        }
        self.unlink(idx);
        self.push_front(idx);
    }

    /// Insert a node at the front (MRU position).
    fn push_front(&mut self, idx: usize) {
        self.arena[idx].prev = None;
        self.arena[idx].next = self.head;

        if let Some(old_head) = self.head {
            self.arena[old_head].prev = Some(idx);
        }

        self.head = Some(idx);

        if self.tail.is_none() {
            self.tail = Some(idx);
        }
    }

    /// Remove a node from the linked list (without freeing it).
    fn unlink(&mut self, idx: usize) {
        let prev = self.arena[idx].prev;
        let next = self.arena[idx].next;

        match prev {
            Some(p) => self.arena[p].next = next,
            None => self.head = next, // idx was head
        }
        match next {
            Some(n) => self.arena[n].prev = prev,
            None => self.tail = prev, // idx was tail
        }

        self.arena[idx].prev = None;
        self.arena[idx].next = None;
    }
}

// ---- Iterator ----

pub struct LruIterator<'a, K, V> {
    arena: &'a Vec<Node<K, V>>,
    current: Option<usize>,
}

impl<'a, K, V> Iterator for LruIterator<'a, K, V> {
    type Item = (&'a K, &'a V);

    fn next(&mut self) -> Option<Self::Item> {
        let idx = self.current?;
        let node = &self.arena[idx];
        self.current = node.next;
        Some((&node.key, &node.value))
    }
}

// ---- Display ----

impl<K: Eq + Hash + Clone + Debug, V: Debug> std::fmt::Display for LruCache<K, V> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "LruCache(cap={}) [", self.capacity)?;
        for (i, (k, v)) in self.iter().enumerate() {
            if i > 0 { write!(f, ", ")?; }
            write!(f, "{:?}:{:?}", k, v)?;
        }
        write!(f, "] (MRU→LRU)")
    }
}

// ---- Tests ----

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic_put_get() {
        let mut cache = LruCache::new(3);
        cache.put("a", 1);
        cache.put("b", 2);
        cache.put("c", 3);

        assert_eq!(cache.get(&"a"), Some(&1));
        assert_eq!(cache.get(&"b"), Some(&2));
        assert_eq!(cache.get(&"c"), Some(&3));
        assert_eq!(cache.len(), 3);
    }

    #[test]
    fn test_eviction() {
        let mut cache = LruCache::new(3);
        cache.put(1, "one");
        cache.put(2, "two");
        cache.put(3, "three");

        // Access 1 and 2, making 3 the LRU
        cache.get(&1);
        cache.get(&2);

        // Insert 4: should evict 3
        let evicted = cache.put(4, "four");
        assert_eq!(evicted, Some((3, "three")));
        assert_eq!(cache.get(&3), None);
        assert_eq!(cache.get(&4), Some(&"four"));
    }

    #[test]
    fn test_update_existing_key() {
        let mut cache = LruCache::new(3);
