## Comparison of Approaches

| Approach | Time | Space | Best For |
|---|---|---|---|
| **Recursive** | O(n · n!) | O(n · n!) | Clarity, small inputs |
| **Heap's Algorithm** | O(n!) | O(n · n!) | Speed, iterative style |
| **Iterator** | O(n!) | O(n) per item | Large inputs, lazy evaluation |

The **iterator approach** is most memory-efficient when you don't need all permutations at once — it generates each one on demand using Python's `itertools.permutations` algorithm adapted to Rust.

# Dijkstra's Shortest Path Algorithm in Rust

## Implementation

```rust
use std::collections::{BinaryHeap, HashMap};
use std::cmp::Ordering;

/// Represents an edge in the graph
#[derive(Debug, Clone)]
struct Edge {
    to: usize,
    weight: u64,
}

/// Graph represented as an adjacency list
#[derive(Debug)]
struct Graph {
    vertices: usize,
    adjacency: Vec<Vec<Edge>>,
}

impl Graph {
    /// Creates a new graph with `vertices` nodes
    fn new(vertices: usize) -> Self {
        Graph {
            vertices,
            adjacency: vec![Vec::new(); vertices],
        }
    }

    /// Adds a directed edge from `from` to `to` with the given `weight`
    fn add_edge(&mut self, from: usize, to: usize, weight: u64) {
        assert!(from < self.vertices && to < self.vertices, "Vertex index out of bounds");
        self.adjacency[from].push(Edge { to, weight });
    }

    /// Adds an undirected edge between `a` and `b` with the given `weight`
    fn add_undirected_edge(&mut self, a: usize, b: usize, weight: u64) {
        self.add_edge(a, b, weight);
        self.add_edge(b, a, weight);
    }

    /// Runs Dijkstra's algorithm from `source` and returns:
    /// - A vector of shortest distances from `source` to each vertex
    /// - A vector of predecessors for path reconstruction (None if no predecessor)
    fn dijkstra(&self, source: usize) -> (Vec<u64>, Vec<Option<usize>>) {
        assert!(source < self.vertices, "Source vertex out of bounds");

        const INF: u64 = u64::MAX;

        let mut dist = vec![INF; self.vertices];
        let mut prev: Vec<Option<usize>> = vec![None; self.vertices];
        let mut heap = BinaryHeap::new();

        dist[source] = 0;
        heap.push(State { cost: 0, vertex: source });

        while let Some(State { cost, vertex }) = heap.pop() {
            // Skip outdated entries
            if cost > dist[vertex] {
                continue;
            }

            for edge in &self.adjacency[vertex] {
                let next_cost = match dist[vertex].checked_add(edge.weight) {
                    Some(c) => c,
                    None => continue, // Overflow protection
                };

                if next_cost < dist[edge.to] {
                    dist[edge.to] = next_cost;
                    prev[edge.to] = Some(vertex);
                    heap.push(State { cost: next_cost, vertex: edge.to });
                }
            }
        }

        (dist, prev)
    }

    /// Reconstructs the shortest path from `source` to `target`
    fn shortest_path(&self, source: usize, target: usize) -> Option<(u64, Vec<usize>)> {
        let (dist, prev) = self.dijkstra(source);

        if dist[target] == u64::MAX {
            return None; // No path exists
        }

        // Reconstruct path by following predecessors
        let mut path = Vec::new();
        let mut current = target;

        loop {
            path.push(current);
            match prev[current] {
                Some(predecessor) => current = predecessor,
                None => break,
            }
        }

        path.reverse();

        // Ensure path starts at source
        if path[0] != source {
            return None;
        }

        Some((dist[target], path))
    }

    /// Returns all shortest distances from source using named vertices
    fn dijkstra_named(
        &self,
        source: usize,
        names: &HashMap<usize, &str>,
    ) -> Vec<(String, u64)> {
        let (dist, _) = self.dijkstra(source);

        dist.iter()
            .enumerate()
            .map(|(v, &d)| {
                let name = names.get(&v).map_or(v.to_string(), |s| s.to_string());
                let distance = if d == u64::MAX {
                    u64::MAX
                } else {
                    d
                };
                (name, distance)
            })
            .collect()
    }
}

/// State used in the priority queue (min-heap via reversed ordering)
#[derive(Debug, Clone, Eq, PartialEq)]
struct State {
    cost: u64,
    vertex: usize,
}

/// Reverse ordering to make BinaryHeap a min-heap
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        other.cost.cmp(&self.cost)
            .then_with(|| self.vertex.cmp(&other.vertex))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

