    fn close_unblocks_pop() {
        let q = queue::<i32>(4);
        let q2 = q.clone();
        let handle = thread::spawn(move || q2.pop());
        thread::sleep(Duration::from_millis(20));
        q.close();
        assert_eq!(handle.join().unwrap(), Err(QueueError::Disconnected));
    }

    #[test]
    fn close_unblocks_push() {
        let q = queue(1);
        q.push(1).unwrap(); // fill it
        let q2 = q.clone();
        let handle = thread::spawn(move || q2.push(2));
        thread::sleep(Duration::from_millis(20));
        q.close();
        assert_eq!(handle.join().unwrap(), Err(QueueError::Disconnected));
    }

    #[test]
    fn drain_after_close() {
        let q = queue(4);
        q.push(1).unwrap();
        q.push(2).unwrap();
        q.close();
        // Existing items can still be popped.
        assert_eq!(q.pop().unwrap(), 1);
        assert_eq!(q.pop().unwrap(), 2);
        // Now empty + closed → error.
        assert_eq!(q.pop().unwrap_err(), QueueError::Disconnected);
    }

    // ── Concurrent stress ────────────────────────────────────────────────

    #[test]
    fn mpmc_stress() {
        const PRODUCERS: usize = 4;
        const CONSUMERS: usize = 4;
        const ITEMS_PER_PRODUCER: usize = 1_000;
        const TOTAL: usize = PRODUCERS * ITEMS_PER_PRODUCER;

        let q: BoundedBlockingQueue<usize> = BoundedBlockingQueue::new(16);

        // Spawn producers.
        let producers: Vec<_> = (0..PRODUCERS)
            .map(|_| {
                let q = q.clone();
                thread::spawn(move || {
                    for i in 0..ITEMS_PER_PRODUCER {
                        q.push(i).unwrap();
                    }
                })
            })
            .collect();

        // Spawn consumers; each returns a count of items received.
        let consumers: Vec<_> = (0..CONSUMERS)
            .map(|_| {
                let q = q.clone();
                thread::spawn(move || {
                    let mut count = 0usize;
                    loop {
                        match q.pop() {
                            Ok(_) => count += 1,
                            Err(QueueError::Disconnected) => break,
                            Err(e) => panic!("unexpected error: {e}"),
                        }
                    }
                    count
                })
            })
            .collect();

        // Wait for all producers, then close.
        for p in producers {
            p.join().unwrap();
        }
        q.close();

        // All items must be accounted for.
        let total_consumed: usize = consumers.into_iter().map(|c| c.join().unwrap()).sum();
        assert_eq!(total_consumed, TOTAL);
    }
}

fn main() {
    let q: BoundedBlockingQueue<i32> = BoundedBlockingQueue::new(4);

    // Producer thread
    let q_prod = q.clone();
    let producer = std::thread::spawn(move || {
        for i in 0..8 {
            println!("Pushing {i}");
            q_prod.push(i).unwrap();
        }
        q_prod.close();
        println!("Producer done, queue closed.");
    });

    // Consumer (main thread)
    loop {
        match q.pop() {
            Ok(v) => println!("  Popped {v}"),
            Err(QueueError::Disconnected) => {
                println!("Queue closed and empty — consumer exiting.");
                break;
            }
            Err(e) => eprintln!("Error: {e}"),
        }
    }

    producer.join().unwrap();
}
