## Key Design Decisions

| Decision | Rationale |
|----------|-----------|
| `Mutex<Inner>` + two `Condvar`s | Classic monitor pattern; `not_full` and `not_empty` avoid spurious wakeups on the wrong condition |
| `Arc<Shared>` behind a `Clone`able handle | No separate `Sender`/`Receiver` split; any clone can produce or consume |
| `VecDeque` as the buffer | O(1) push-back / pop-front, pre-allocated to `capacity` |
| Drain-on-close semantics | Consumers can flush remaining items after close; only the *empty+closed* case errors |
| `wait_timeout` for timed variants | Delegates deadline tracking to the OS; no busy-polling |

## Closing Semantics

```
Producer closes queue
        │
        ▼
  closed = true; notify_all()
        │
   ┌────┴─────┐
   │          │
pop()      push()
   │          │
items left? → Yes → return Ok(item)
           → No  → return Err(Disconnected)
```

# Arithmetic Expression Evaluator in Rust

This implementation supports:
- Basic operators: `+`, `-`, `*`, `/`, `%`
- Exponentiation: `^`
- Unary minus: `-3`
- Parentheses: `(2 + 3) * 4`
- Floating-point numbers
- Proper operator precedence

## Implementation

```rust
use std::fmt;
use std::io::{self, BufRead, Write};
use std::iter::Peekable;
use std::str::Chars;

// ─── Token ────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Star,
    Slash,
    Percent,
    Caret,
    LParen,
    RParen,
    Eof,
}

impl fmt::Display for Token {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Token::Number(n) => write!(f, "{}", n),
            Token::Plus => write!(f, "+"),
            Token::Minus => write!(f, "-"),
            Token::Star => write!(f, "*"),
            Token::Slash => write!(f, "/"),
            Token::Percent => write!(f, "%"),
            Token::Caret => write!(f, "^"),
            Token::LParen => write!(f, "("),
            Token::RParen => write!(f, ")"),
            Token::Eof => write!(f, "<EOF>"),
        }
    }
}

// ─── Error ────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone)]
enum EvalError {
    UnexpectedChar(char),
    UnexpectedToken(Token),
    UnmatchedParen,
    DivisionByZero,
    EmptyExpression,
}

impl fmt::Display for EvalError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            EvalError::UnexpectedChar(c) => write!(f, "Unexpected character: '{}'", c),
            EvalError::UnexpectedToken(t) => write!(f, "Unexpected token: '{}'", t),
            EvalError::UnmatchedParen => write!(f, "Unmatched parenthesis"),
            EvalError::DivisionByZero => write!(f, "Division by zero"),
            EvalError::EmptyExpression => write!(f, "Empty expression"),
        }
    }
}

// ─── Lexer ────────────────────────────────────────────────────────────────────

struct Lexer<'a> {
    chars: Peekable<Chars<'a>>,
}

impl<'a> Lexer<'a> {
    fn new(input: &'a str) -> Self {
        Lexer {
            chars: input.chars().peekable(),
        }
    }

    fn skip_whitespace(&mut self) {
        while self.chars.peek().map_or(false, |c| c.is_ascii_whitespace()) {
            self.chars.next();
        }
    }

    fn read_number(&mut self, first: char) -> Result<Token, EvalError> {
        let mut s = String::from(first);

        // Integer part
        while self.chars.peek().map_or(false, |c| c.is_ascii_digit()) {
            s.push(self.chars.next().unwrap());
        }

        // Decimal part
        if self.chars.peek() == Some(&'.') {
            s.push(self.chars.next().unwrap()); // consume '.'
            while self.chars.peek().map_or(false, |c| c.is_ascii_digit()) {
                s.push(self.chars.next().unwrap());
            }
        }

        // Scientific notation
        if self.chars.peek().map_or(false, |c| *c == 'e' || *c == 'E') {
            s.push(self.chars.next().unwrap()); // consume 'e'/'E'
            if self.chars.peek().map_or(false, |c| *c == '+' || *c == '-') {
                s.push(self.chars.next().unwrap());
            }
            while self.chars.peek().map_or(false, |c| c.is_ascii_digit()) {
                s.push(self.chars.next().unwrap());
            }
        }

        s.parse::<f64>()
            .map(Token::Number)
            .map_err(|_| EvalError::UnexpectedChar(first))
    }

    fn next_token(&mut self) -> Result<Token, EvalError> {
        self.skip_whitespace();

        match self.chars.next() {
            None => Ok(Token::Eof),
            Some(c) => match c {
                '+' => Ok(Token::Plus),
                '-' => Ok(Token::Minus),
                '*' => Ok(Token::Star),
                '/' => Ok(Token::Slash),
                '%' => Ok(Token::Percent),
                '^' => Ok(Token::Caret),
                '(' => Ok(Token::LParen),
                ')' => Ok(Token::RParen),
                '0'..='9' | '.' => self.read_number(c),
                other => Err(EvalError::UnexpectedChar(other)),
            },
        }
    }

    /// Tokenise the entire input at once.
    fn tokenize(mut self) -> Result<Vec<Token>, EvalError> {
        let mut tokens = Vec::new();
        loop {
            let tok = self.next_token()?;
            let done = tok == Token::Eof;
            tokens.push(tok);
            if done {
                break;
            }
        }
        Ok(tokens)
    }
}

// ─── Parser / Evaluator ───────────────────────────────────────────────────────
//
// Grammar (highest precedence at the bottom):
//
//   expr        → addition
//   addition    → multiplication ( ('+' | '-') multiplication )*
//   multiplication → unary ( ('*' | '/' | '%') unary )*
//   unary       → '-' unary | exponent
//   exponent    → primary ('^' unary)*      ← right-associative
//   primary     → NUMBER | '(' expr ')'

struct Parser {
    tokens: Vec<Token>,
    pos: usize,
}

impl Parser {
    fn new(tokens: Vec<Token>) -> Self {
        Parser { tokens, pos: 0 }
    }

    // ── Helpers ──────────────────────────────────────────────────────────────

    fn peek(&self) -> &Token {
        &self.tokens[self.pos]
    }

    fn advance(&mut self) -> &Token {
        let tok = &self.tokens[self.pos];
        if self.pos + 1 < self.tokens.len() {
            self.pos += 1;
        }
        tok
    }

    fn expect(&mut self, expected: &Token) -> Result<(), EvalError> {
        let tok = self.advance().clone();
        if &tok == expected {
            Ok(())
        } else {
            Err(EvalError::UnexpectedToken(tok))
        }
    }

    // ── Grammar rules ────────────────────────────────────────────────────────

    fn parse_expr(&mut self) -> Result<f64, EvalError> {
        let result = self.parse_addition()?;

        // After a complete expression only EOF or ')' should follow.
        match self.peek() {
            Token::Eof | Token::RParen => {}
            other => return Err(EvalError::UnexpectedToken(other.clone())),
        }

        Ok(result)
    }

    fn parse_addition(&mut self) -> Result<f64, EvalError> {
        let mut left = self.parse_multiplication()?;

        loop {
            match self.peek() {
                Token::Plus => {
                    self.advance();
                    left += self.parse_multiplication()?;
                }
                Token::Minus => {
                    self.advance();
                    left -= self.parse_multiplication()?;
                }
                _ => break,
            }
        }

        Ok(left)
    }

    fn parse_multiplication(&mut self) -> Result<f64, EvalError> {
        let mut left = self.parse_unary()?;

        loop {
            match self.peek() {
                Token::Star => {
                    self.advance();
                    left *= self.parse_unary()?;
                }
                Token::Slash => {
                    self.advance();
                    let right = self.parse_unary()?;
                    if right == 0.0 {
                        return Err(EvalError::DivisionByZero);
                    }
                    left /= right;
                }
                Token::Percent => {
                    self.advance();
                    let right = self.parse_unary()?;
                    if right == 0.0 {
                        return Err(EvalError::DivisionByZero);
                    }
                    left %= right;
                }
                _ => break,
            }
        }

        Ok(left)
    }

    fn parse_unary(&mut self) -> Result<f64, EvalError> {
        if let Token::Minus = self.peek() {
            self.advance();
            let val = self.parse_unary()?; // allow chaining: --3 == 3
            return Ok(-val);
        }
        // Optional unary '+' (no-op)
        if let Token::Plus = self.peek() {
            self.advance();
            return self.parse_unary();
        }
        self.parse_exponent()
    }

    fn parse_exponent(&mut self) -> Result<f64, EvalError> {
        let base = self.parse_primary()?;

        if let Token::Caret = self.peek() {
            self.advance();
            // Right-associative: recurse into parse_unary so that
            // `-2^2` is `-(2^2)` and `2^-2` is `2^(-2)`.
            let exp = self.parse_unary()?;
            return Ok(base.powf(exp));
        }

        Ok(base)
    }

    fn parse_primary(&mut self) -> Result<f64, EvalError> {
        let tok = self.advance().clone();

        match tok {
            Token::Number(n) => Ok(n),
            Token::LParen => {
                let val = self.parse_addition()?;
                match self.peek() {
                    Token::RParen => {
                        self.advance();
                        Ok(val)
                    }
                    _ => Err(EvalError::UnmatchedParen),
                }
            }
            Token::Eof => Err(EvalError::EmptyExpression),
            other => Err(EvalError::UnexpectedToken(other)),
        }
    }
}

// ─── Public entry point ───────────────────────────────────────────────────────

fn evaluate(input: &str) -> Result<f64, EvalError> {
    let input = input.trim();
    if input.is_empty() {
        return Err(EvalError::EmptyExpression);
    }

    let tokens = Lexer::new(input).tokenize()?;
    let mut parser = Parser::new(tokens);
    let result = parser.parse_expr()?;
    Ok(result)
}

// ─── Tests ────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    fn eval(s: &str) -> f64 {
        evaluate(s).unwrap()
    }

    fn nearly_eq(a: f64, b: f64) -> bool {
        (a - b).abs() < 1e-9
    }

    #[test]
    fn test_literals() {
        assert!(nearly_eq(eval("42"), 42.0));
        assert!(nearly_eq(eval("3.14"), 3.14));
        assert!(nearly_eq(eval("1e3"), 1000.0));
        assert!(nearly_eq(eval("2.5e-1"), 0.25));
    }

    #[test]
    fn test_basic_ops() {
        assert!(nearly_eq(eval("1 + 2"), 3.0));
        assert!(nearly_eq(eval("10 - 4"), 6.0));
        assert!(nearly_eq(eval("3 * 4"), 12.0));
        assert!(nearly_eq(eval("9 / 2"), 4.5));
        assert!(nearly_eq(eval("10 % 3"), 1.0));
    }

    #[test]
    fn test_precedence() {
        assert!(nearly_eq(eval("2 + 3 * 4"), 14.0));
        assert!(nearly_eq(eval("10 - 2 * 3"), 4.0));
        assert!(nearly_eq(eval("8 / 2 + 1"), 5.0));
    }

    #[test]
    fn test_parentheses() {
        assert!(nearly_eq(eval("(2 + 3) * 4"), 20.0));
        assert!(nearly_eq(eval("(10 - 2) * (3 + 1)"), 32.0));
        assert!(nearly_eq(eval("((2 + 3))"), 5.0));
    }

    #[test]
    fn test_unary() {
        assert!(nearly_eq(eval("-3"), -3.0));
        assert!(nearly_eq(eval("--3"), 3.0));
        assert!(nearly_eq(eval("-3 + 5"), 2.0));
        assert!(nearly_eq(eval("-(3 + 2)"), -5.0));
        assert!(nearly_eq(eval("+5"), 5.0));
    }

    #[test]
    fn test_exponentiation() {
        assert!(nearly_eq(eval("2^10"), 1024.0));
        assert!(nearly_eq(eval("2^3^2"), 512.0)); // right-associative: 2^(3^2)
        assert!(nearly_eq(eval("4^0.5"), 2.0));
        assert!(nearly_eq(eval("2^-2"), 0.25));
    }

    #[test]
    fn test_complex() {
        assert!(nearly_eq(eval("(1 + 2) * (3 + 4) / 7"), 3.0));
        assert!(nearly_eq(eval("2 + 3 * 4 - 5 / 5"), 13.0));
        assert!(nearly_eq(eval("-2^2"), -4.0)); // -(2^2), not (-2)^2
    }

    #[test]
    fn test_errors() {
        assert!(matches!(evaluate(""), Err(EvalError::EmptyExpression)));
        assert!(matches!(evaluate("1 / 0"), Err(EvalError::DivisionByZero)));
        assert!(matches!(evaluate("(1 + 2"), Err(EvalError::UnmatchedParen)));
        assert!(matches!(evaluate("1 + $ 2"), Err(EvalError::UnexpectedChar('$'))));
