## How It Works

### Architecture

```
Input string
     │
     ▼
  Lexer          → Vec<Token>
     │
     ▼
  Parser         (recursive descent)
     │
     ▼
  f64 result
```

### Operator Precedence (low → high)

| Level | Operators | Associativity |
|-------|-----------|---------------|
| 1 | `+` `-` | Left |
| 2 | `*` `/` `%` | Left |
| 3 | unary `-` `+` | Right |
| 4 | `^` | Right |
| 5 | `()` literals | — |

### Key Design Decisions

- **`-2^2 = -4`** — unary minus binds *less tightly* than `^`, matching mathematical convention
- **`2^3^2 = 512`** — exponentiation is right-associative (`2^(3^2)`)
- **`--3 = 3`** — chained unary minus via recursion
- **Scientific notation** — `1.5e-3` is handled in the lexer
- **Division by zero** — detected at runtime and returns a typed error

### Example Session

```
> 2 + 3 * 4
= 14
> (2 + 3) * 4
= 20
> 2^10
= 1024
> -2^2
= -4
> 1.5e2 / 3
= 50
> 10 % 3
= 1
```

# Basic Regex Matcher in Rust

This implementation supports the following patterns:
- `.` — matches any single character
- `*` — matches zero or more of the preceding element
- `+` — matches one or more of the preceding element
- `?` — matches zero or one of the preceding element
- `^` — anchors match to start of string
- `$` — anchors match to end of string
- `[abc]` — character classes (with `^` for negation, `-` for ranges)
- `\d`, `\w`, `\s` — escape sequences
- `|` — alternation
- `(...)` — grouping

---

```rust
#[derive(Debug, Clone, PartialEq)]
enum Token {
    Literal(char),
    AnyChar,          // .
    CharClass(Vec<CharRange>, bool), // [ranges], negated
    Anchor(AnchorKind),
}

#[derive(Debug, Clone, PartialEq)]
enum AnchorKind {
    Start,
    End,
}

#[derive(Debug, Clone, PartialEq)]
struct CharRange {
    start: char,
    end: char,
}

impl CharRange {
    fn single(c: char) -> Self {
        CharRange { start: c, end: c }
    }
    fn range(start: char, end: char) -> Self {
        CharRange { start, end }
    }
    fn matches(&self, c: char) -> bool {
        c >= self.start && c <= self.end
    }
}

#[derive(Debug, Clone)]
enum Quantifier {
    One,
    ZeroOrMore,
    OneOrMore,
    ZeroOrOne,
}

#[derive(Debug, Clone)]
enum Node {
    Token(Token, Quantifier),
    Group(Vec<Vec<Node>>, Quantifier), // alternation branches
}

// ─── Lexer / Parser ───────────────────────────────────────────────────────────

struct Parser {
    chars: Vec<char>,
    pos: usize,
}

impl Parser {
    fn new(pattern: &str) -> Self {
        Parser {
            chars: pattern.chars().collect(),
            pos: 0,
        }
    }

    fn peek(&self) -> Option<char> {
        self.chars.get(self.pos).copied()
    }

    fn advance(&mut self) -> Option<char> {
        let c = self.chars.get(self.pos).copied();
        if c.is_some() {
            self.pos += 1;
        }
        c
    }

    /// Parse the whole pattern as alternation at top level.
    fn parse(&mut self) -> Vec<Vec<Node>> {
        self.parse_alternation(false)
    }

    /// Parse alternation branches until `)` or end-of-input.
    fn parse_alternation(&mut self, inside_group: bool) -> Vec<Vec<Node>> {
        let mut branches: Vec<Vec<Node>> = Vec::new();
        let mut current: Vec<Node> = Vec::new();

        loop {
            match self.peek() {
                None => break,
                Some(')') if inside_group => break,
                Some('|') => {
                    self.advance();
                    branches.push(current);
                    current = Vec::new();
                }
                _ => {
                    if let Some(node) = self.parse_node() {
                        current.push(node);
                    }
                }
            }
        }
        branches.push(current);
        branches
    }

    fn parse_node(&mut self) -> Option<Node> {
        let token = match self.peek()? {
            '^' => {
                self.advance();
                // ^ only acts as anchor at position; no quantifier
                return Some(Node::Token(Token::Anchor(AnchorKind::Start), Quantifier::One));
            }
            '$' => {
                self.advance();
                return Some(Node::Token(Token::Anchor(AnchorKind::End), Quantifier::One));
            }
            '(' => {
                self.advance();
                let branches = self.parse_alternation(true);
                if self.peek() == Some(')') {
                    self.advance();
                }
                let q = self.parse_quantifier();
                return Some(Node::Group(branches, q));
            }
            '[' => {
                self.advance();
                let (ranges, negated) = self.parse_char_class();
                Token::CharClass(ranges, negated)
            }
            '\\' => {
                self.advance();
                self.parse_escape()
            }
            '.' => {
                self.advance();
                Token::AnyChar
            }
            c => {
                self.advance();
                Token::Literal(c)
            }
        };

        let q = self.parse_quantifier();
        Some(Node::Token(token, q))
    }

    fn parse_quantifier(&mut self) -> Quantifier {
        match self.peek() {
            Some('*') => { self.advance(); Quantifier::ZeroOrMore }
            Some('+') => { self.advance(); Quantifier::OneOrMore }
            Some('?') => { self.advance(); Quantifier::ZeroOrOne }
            _ => Quantifier::One,
        }
    }

    fn parse_escape(&mut self) -> Token {
        match self.advance() {
            Some('d') => Token::CharClass(vec![CharRange::range('0', '9')], false),
            Some('D') => Token::CharClass(vec![CharRange::range('0', '9')], true),
            Some('w') => Token::CharClass(vec![
                CharRange::range('a', 'z'),
                CharRange::range('A', 'Z'),
                CharRange::range('0', '9'),
                CharRange::single('_'),
            ], false),
            Some('W') => Token::CharClass(vec![
                CharRange::range('a', 'z'),
                CharRange::range('A', 'Z'),
                CharRange::range('0', '9'),
                CharRange::single('_'),
            ], true),
            Some('s') => Token::CharClass(vec![
                CharRange::single(' '),
                CharRange::single('\t'),
                CharRange::single('\n'),
                CharRange::single('\r'),
            ], false),
            Some('S') => Token::CharClass(vec![
                CharRange::single(' '),
                CharRange::single('\t'),
                CharRange::single('\n'),
                CharRange::single('\r'),
            ], true),
            Some('n') => Token::Literal('\n'),
            Some('t') => Token::Literal('\t'),
            Some(c)   => Token::Literal(c),
            None      => Token::Literal('\\'),
        }
    }

    /// Parse `[...]` after the opening `[` has been consumed.
    fn parse_char_class(&mut self) -> (Vec<CharRange>, bool) {
        let negated = if self.peek() == Some('^') {
            self.advance();
            true
        } else {
            false
        };

        let mut ranges: Vec<CharRange> = Vec::new();

        loop {
            match self.peek() {
                None | Some(']') => { self.advance(); break; }
                Some('\\') => {
                    self.advance();
                    let tok = self.parse_escape();
                    if let Token::CharClass(r, _) = tok {
                        ranges.extend(r);
                    } else if let Token::Literal(c) = tok {
                        ranges.push(self.maybe_range(c));
                    }
                }
                Some(c) => {
                    self.advance();
                    ranges.push(self.maybe_range(c));
                }
            }
        }

        (ranges, negated)
    }

    /// After consuming `c`, check whether `-X` follows to form a range.
    fn maybe_range(&mut self, start: char) -> CharRange {
        if self.peek() == Some('-') {
            // peek ahead to see if there is a range end (not `]`)
            if self.chars.get(self.pos + 1).copied().map_or(false, |nc| nc != ']') {
                self.advance(); // consume '-'
                if let Some(end) = self.advance() {
                    return CharRange::range(start, end);
                }
            }
        }
        CharRange::single(start)
    }
}

// ─── Matcher ──────────────────────────────────────────────────────────────────

pub struct Regex {
    /// Top-level alternation
    branches: Vec<Vec<Node>>,
    anchored_start: bool,
}

impl Regex {
    pub fn new(pattern: &str) -> Self {
        // Strip a leading ^ so we know the whole match must start at position 0
        let (pattern, anchored_start) = if pattern.starts_with('^') {
            (&pattern[1..], true)
        } else {
            (pattern, false)
        };

        let mut parser = Parser::new(pattern);
        let branches = parser.parse();
        Regex { branches, anchored_start }
    }

    /// Returns true if the pattern matches anywhere in `text`.
    pub fn is_match(&self, text: &str) -> bool {
        self.find(text).is_some()
    }

    /// Returns the byte-index span `(start, end)` of the first match, or None.
    pub fn find(&self, text: &str) -> Option<(usize, usize)> {
        let chars: Vec<char> = text.chars().collect();

        if self.anchored_start {
            for branch in &self.branches {
                if let Some(end) = match_nodes(branch, &chars, 0) {
                    let byte_start = char_idx_to_byte(text, 0);
                    let byte_end   = char_idx_to_byte(text, end);
                    return Some((byte_start, byte_end));
                }
            }
            return None;
        }

        for start in 0..=chars.len() {
            for branch in &self.branches {
                if let Some(end) = match_nodes(branch, &chars, start) {
                    let byte_start = char_idx_to_byte(text, start);
                    let byte_end   = char_idx_to_byte(text, end);
                    return Some((byte_start, byte_end));
                }
            }
        }
        None
    }

    /// Returns all non-overlapping matches as `(start, end)` byte spans.
    pub fn find_all(&self, text: &str) -> Vec<(usize, usize)> {
        let chars: Vec<char> = text.chars().collect();
        let mut results = Vec::new();
        let mut char_pos = 0;

        while char_pos <= chars.len() {
            let mut found = false;
            for branch in &self.branches {
                if let Some(end) = match_nodes(branch, &chars, char_pos) {
                    let byte_start = char_idx_to_byte(text, char_pos);
                    let byte_end   = char_idx_to_byte(text, end);
                    results.push((byte_start, byte_end));
                    // Advance past this match (at least 1 to avoid infinite loop)
                    char_pos = if end > char_pos { end } else { char_pos + 1 };
                    found = true;
                    break;
                }
            }
            if !found {
                char_pos += 1;
            }
        }
        results
    }
}

fn char_idx_to_byte(text: &str, char_idx: usize) -> usize {
    text.char_indices()
        .nth(char_idx)
        .map(|(b, _)| b)
        .unwrap_or(text.len())
}

// ─── Core recursive matching ──────────────────────────────────────────────────

/// Try to match `nodes` against `chars[pos..]`.
/// Returns the new char position on success, or None on failure.
fn match_nodes(nodes: &[Node], chars: &[char], pos: usize) -> Option<usize> {
    if nodes.is_empty() {
        return Some(pos);
    }

    let (first, rest) = (&nodes[0], &nodes[1..]);

    match first {
        Node::Token(tok, quant) => match_token_quantifier(tok, quant, rest, chars, pos),
        Node::Group(branches, quant) => match_group_quantifier(branches, quant, rest, chars, pos),
    }
}

fn token_matches_char(tok: &Token, chars: &[char], pos: usize) -> bool {
    match chars.get(pos) {
        None => false,
        Some(&c) => match tok {
            Token::Literal(l)           => c == *l,
            Token::AnyChar              => c != '\n', // classic . behaviour
            Token::CharClass(ranges, neg) => {
                let hit = ranges.iter().any(|r| r.matches(c));
                if *neg { !hit } else { hit }
            }
            Token::Anchor(_)            => false, // anchors don't consume chars
        },
    }
}

fn match_token_quantifier(
    tok: &Token,
    quant: &Quantifier,
    rest: &[Node],
    chars: &[char],
    pos: usize,
) -> Option<usize> {
    // Handle anchors specially — they don't consume input.
    if let Token::Anchor(kind) = tok {
        let ok = match kind {
            AnchorKind::Start => pos == 0,
            AnchorKind::End   => pos == chars.len(),
        };
        return if ok { match_nodes(rest, chars, pos) } else { None };
    }

    match quant {
        Quantifier::One => {
            if token_matches_char(tok, chars, pos) {
                match_nodes(rest, chars, pos + 1)
            } else {
                None
            }
        }
        Quantifier::ZeroOrOne => {
            // Greedy: try consuming first.
            if token_matches_char(tok, chars, pos) {
                if let Some(end) = match_nodes(rest, chars, pos + 1) {
                    return Some(end);
                }
            }
            match_nodes(rest, chars, pos)
        }
        Quantifier::ZeroOrMore => {
            // Collect all positions where the token matches consecutively.
            greedy_repeat(|p| token_matches_char(tok, chars, p), rest, chars, pos)
        }
        Quantifier::OneOrMore => {
            if !token_matches_char(tok, chars, pos) {
                return None;
            }
            greedy_repeat(|p| token_matches_char(tok, chars, p), rest, chars, pos)
        }
    }
}

/// Greedy repetition helper: advance `pos` while `pred` holds, then try
/// to match `rest` from the furthest position backwards (greedy with backtrack).
fn greedy_repeat<F>(pred: F, rest: &[Node], chars: &[char], pos: usize) -> Option<usize>
where
    F: Fn(usize) -> bool,
{
    let mut end = pos;
    while end < chars.len() && pred(end) {
        end += 1;
    }
    // Try from longest match down to zero-width match.
    while end >= pos {
        if let Some(r) = match_nodes(rest, chars, end) {
            return Some(r);
        }
        if end == pos { break; }
        end -= 1;
    }
    None
}

fn match_group_quantifier(
    branches: &[Vec<Node>],
    quant: &Quantifier,
    rest: &[Node],
    chars: &[char],
    pos: usize,
) -> Option<usize> {
    /// Try matching any branch at `pos`; return new position or None.
    let try_branch = |p: usize| -> Option<usize> {
        for branch in branches {
            if let Some(end) = match_nodes(branch, chars, p) {
                return Some(end);
            }
        }
        None
    };

    match quant {
        Quantifier::One => {
            let end = try_branch(pos)?;
            match_nodes(rest, chars, end)
        }
        Quantifier::ZeroOrOne => {
            if let Some(end) = try_branch(pos) {
                if let Some(r) = match_nodes(rest, chars, end) {
                    return Some(r);
                }
            }
            match_nodes(rest, chars, pos)
        }
        Quantifier::ZeroOrMore | Quantifier::OneOrMore => {
            if matches!(quant, Quantifier::OneOrMore) && try_branch(pos).is_none() {
                return None;
            }
            // Collect positions of each successive group match.
            let mut positions = vec![pos];
            let mut cur = pos;
            while let Some(next) = try_branch(cur) {
                if next == cur { break; } // zero-width match guard
                positions.push(next);
                cur = next;
            }
            // Greedy: try from longest down.
            for &p in positions.iter().rev() {
                if let Some(r) = match_nodes(rest, chars, p) {
                    return Some(r);
                }
            }
            None
        }
    }
}

