    ];

    for (s1, s2) in &test_cases {
        let lcs = longest_common_subsequence(s1, s2);
        let length = lcs_length(s1, s2);

        println!("String 1  : \"{}\"", s1);
        println!("String 2  : \"{}\"", s2);
