use std::fmt;

/// Messages exchanged between Raft nodes
#[derive(Debug, Clone)]
pub enum Message {
    /// Candidate requests votes from peers
    RequestVote {
        term: u64,
        candidate_id: u64,
        last_log_index: u64,
        last_log_term: u64,
    },
    /// Peer responds to a vote request
    RequestVoteResponse {
        term: u64,
        vote_granted: bool,
        voter_id: u64,
    },
    /// Leader sends heartbeats / log replication (simplified)
    AppendEntries {
        term: u64,
        leader_id: u64,
        prev_log_index: u64,
        prev_log_term: u64,
    },
    /// Follower responds to AppendEntries
    AppendEntriesResponse {
        term: u64,
        success: bool,
        follower_id: u64,
    },
}

impl fmt::Display for Message {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Message::RequestVote { term, candidate_id, .. } =>
                write!(f, "RequestVote(term={}, candidate={})", term, candidate_id),
            Message::RequestVoteResponse { term, vote_granted, voter_id } =>
                write!(f, "RequestVoteResponse(term={}, granted={}, voter={})", term, vote_granted, voter_id),
            Message::AppendEntries { term, leader_id, .. } =>
                write!(f, "AppendEntries(term={}, leader={})", term, leader_id),
            Message::AppendEntriesResponse { term, success, follower_id } =>
                write!(f, "AppendEntriesResponse(term={}, success={}, follower={})", term, success, follower_id),
        }
    }
}

/// Envelope wraps a message with routing information
#[derive(Debug, Clone)]
pub struct Envelope {
    pub from: u64,
    pub to: u64,
    pub message: Message,
}
