```rust
use std::collections::{HashMap, HashSet};
use std::time::Duration;
use rand::Rng;
use tokio::sync::mpsc;
use tokio::time::{sleep, Instant, timeout};
use tracing::{debug, info, warn};

use crate::message::{Envelope, Message};
use crate::network::NodeSender;

// ──────────────────────────────────────────────
// Constants
// ──────────────────────────────────────────────

/// Minimum election timeout (ms)
const ELECTION_TIMEOUT_MIN_MS: u64 = 150;
/// Maximum election timeout (ms)
const ELECTION_TIMEOUT_MAX_MS: u64 = 300;
/// Heartbeat interval (ms)  – must be << election timeout
const HEARTBEAT_INTERVAL_MS: u64 = 50;

// ──────────────────────────────────────────────
// State machine
// ──────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Role {
    Follower,
    Candidate,
    Leader,
}

impl std::fmt::Display for Role {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Role::Follower  => write!(f, "Follower"),
            Role::Candidate => write!(f, "Candidate"),
            Role::Leader    => write!(f, "Leader"),
        }
    }
}

// ──────────────────────────────────────────────
// Persistent state (simplified – in-memory)
// ──────────────────────────────────────────────

struct PersistentState {
    /// Latest term this node has seen
    current_term: u64,
    /// CandidateId this node voted for in `current_term`, if any
    voted_for: Option<u64>,
}

impl PersistentState {
    fn new() -> Self {
        Self { current_term: 0, voted_for: None }
    }
}

// ──────────────────────────────────────────────
// Node
// ──────────────────────────────────────────────

pub struct Node {
    /// Unique node identifier
    pub id: u64,
    /// All peer node IDs
    peers: Vec<u64>,
    /// Senders keyed by node id
    senders: HashMap<u64, NodeSender>,
    /// Inbound message channel
    receiver: mpsc::Receiver<Envelope>,

    // --- Raft state ---
    persistent: PersistentState,
    role: Role,

    // --- Volatile leader state ---
    /// Votes received in current election
    votes_received: HashSet<u64>,

    // --- Volatile state ---
    /// Who we believe is the current leader
    current_leader: Option<u64>,
    /// Timestamp of last heartbeat received (followers/candidates use this)
    last_heartbeat: Instant,
}

impl Node {
    pub fn new(
        id: u64,
        peers: Vec<u64>,
        senders: HashMap<u64, NodeSender>,
        receiver: mpsc::Receiver<Envelope>,
    ) -> Self {
        Self {
            id,
            peers,
            senders,
            receiver,
            persistent: PersistentState::new(),
            role: Role::Follower,
            votes_received: HashSet::new(),
            current_leader: None,
            last_heartbeat: Instant::now(),
        }
    }

    // ── Public entry-point ───────────────────────

    pub async fn run(mut self) {
        info!("[Node {}] started as Follower", self.id);
        loop {
            match self.role {
                Role::Follower  => self.run_follower().await,
                Role::Candidate => self.run_candidate().await,
                Role::Leader    => self.run_leader().await,
            }
        }
    }

    // ── Role loops ───────────────────────────────

    /// Follower loop: wait for heartbeat; if timeout, become candidate.
    async fn run_follower(&mut self) {
        let election_timeout = random_election_timeout();
        debug!(
            "[Node {}] Follower | term={} | timeout={:?}",
            self.id, self.persistent.current_term, election_timeout
        );

        loop {
            let deadline = self.last_heartbeat + election_timeout;
            let remaining = deadline.saturating_duration_since(Instant::now());

            match timeout(remaining, self.receiver.recv()).await {
                // Received a message before timeout
                Ok(Some(envelope)) => {
                    let became_candidate = self.handle_message_as_follower(envelope).await;
                    if became_candidate {
                        return; // transition handled inside
                    }
                    // Check if we should still wait – update deadline if heartbeat was recent
                    if self.last_heartbeat.elapsed() < election_timeout {
                        continue; // still fresh, keep waiting
                    }
                }
                // Timeout expired → start election
                Ok(None) | Err(_) => {
                    warn!(
                        "[Node {}] Election timeout! Becoming Candidate (term {}→{})",
                        self.id,
                        self.persistent.current_term,
                        self.persistent.current_term + 1
                    );
                    self.become_candidate();
                    return;
                }
            }

            // Re-check timeout after processing a message
            if Instant::now() >= deadline {
                warn!(
                    "[Node {}] Election timeout after message. Becoming Candidate (term {}→{})",
                    self.id,
                    self.persistent.current_term,
                    self.persistent.current_term + 1
                );
                self.become_candidate();
                return;
            }
        }
    }

    /// Candidate loop: broadcast RequestVote, collect votes, win or retry.
    async fn run_candidate(&mut self) {
        let election_timeout = random_election_timeout();
        debug!(
            "[Node {}] Candidate | term={} | timeout={:?}",
            self.id, self.persistent.current_term, election_timeout
        );

        // Broadcast vote requests immediately
        self.broadcast_request_vote().await;

        let deadline = Instant::now() + election_timeout;

        loop {
            let remaining = deadline.saturating_duration_since(Instant::now());
            if remaining.is_zero() {
                // Split vote / no quorum – start new election
                warn!(
                    "[Node {}] Election timeout as Candidate. Restarting election (term {}→{})",
                    self.id,
                    self.persistent.current_term,
                    self.persistent.current_term + 1
                );
                self.become_candidate(); // increments term, resets votes
                return;
            }

            match timeout(remaining, self.receiver.recv()).await {
                Ok(Some(envelope)) => {
                    let transition = self.handle_message_as_candidate(envelope).await;
                    match transition {
                        CandidateTransition::BecameLeader  => return,
                        CandidateTransition::BecameFollower => return,
                        CandidateTransition::Stay           => {}
                    }
                }
                Ok(None) | Err(_) => {
                    warn!("[Node {}] Candidate timeout – restarting election", self.id);
                    self.become_candidate();
                    return;
                }
            }
        }
    }

    /// Leader loop: send heartbeats, handle responses.
    async fn run_leader(&mut self) {
        info!("[Node {}] *** LEADER *** term={}", self.id, self.persistent.current_term);
        let heartbeat_interval = Duration::from_millis(HEARTBEAT_INTERVAL_MS);

        loop {
            // Send heartbeats to all peers
            self.broadcast_append_entries().await;

            let deadline = Instant::now() + heartbeat_interval;
            loop {
                let remaining = deadline.saturating_duration_since(Instant::now());
                if remaining.is_zero() { break; }

                match timeout(remaining, self.receiver.recv()).await {
                    Ok(Some(envelope)) => {
                        let stepped_down = self.handle_message_as_leader(envelope).await;
                        if stepped_down {
                            return; // became follower
                        }
                    }
                    Ok(None)  => return, // channel closed
                    Err(_)    => break,  // interval elapsed, send next heartbeat
                }
            }
        }
    }

    // ── State transitions ─────────────────────────

    fn become_candidate(&mut self) {
        self.persistent.current_term += 1;
        self.persistent.voted_for = Some(self.id); // vote for self
        self.role = Role::Candidate;
        self.votes_received.clear();
        self.votes_received.insert(self.id); // count self-vote
        self.current_leader = None;
        info!(
            "[Node {}] Became Candidate | term={}",
            self.id, self.persistent.current_term
        );
    }

    fn become_leader(&mut self) {
        self.role = Role::Leader;
        self.current_leader = Some(self.id);
        info!(
            "[Node {}] *** Became LEADER *** | term={} | votes={}/{}",
            self.id,
            self.persistent.current_term,
            self.votes_received.len(),
            self.quorum()
        );
    }

    fn become_follower(&mut self, new_term: u64, leader_hint: Option<u64>) {
        let old_role = self.role.clone();
        self.persistent.current_term = new_term;
        self.persistent.voted_for = None;
        self.role = Role::Follower;
        self.current_leader = leader_hint;
        self.last_heartbeat = Instant::now();
        info!(
            "[Node {}] Stepped down: {} → Follower | term={}",
            self.id, old_role, new_term
        );
    }

    // ── Message handlers ──────────────────────────

    /// Returns true if the node transitioned away from Follower.
    async fn handle_message_as_follower(&mut self, envelope: Envelope) -> bool {
        debug!("[Node {}] Follower recv: {}", self.id, envelope.message);
        match envelope.message {
            Message::RequestVote { term, candidate_id, last_log_index, last_log_term } => {
                self.handle_request_vote(term, candidate_id, last_log_index, last_log_term).await;
                false
            }
            Message::AppendEntries { term, leader_id, prev_log_index, prev_log_term } => {
                self.handle_append_entries_follower(term, leader_id, prev_log_index, prev_log_term).await;
                false
            }
            // Followers ignore these (stale messages possible)
            Message::RequestVoteResponse { .. } | Message::AppendEntriesResponse { .. } => false,
        }
    }

    /// Returns the transition the candidate should take.
    async fn handle_message_as_candidate(&mut self, envelope: Envelope) -> CandidateTransition {
        debug!("[Node {}] Candidate recv: {}", self.id, envelope.message);
        match envelope.message {
            Message::RequestVoteResponse { term, vote_granted, voter_id } => {
                if term > self.persistent.current_term {
                    // Higher term discovered → step down
                    self.become_follower(term, None);
                    return CandidateTransition::BecameFollower;
                }
                if term == self.persistent.current_term && vote_granted {
                    self.votes_received.insert(voter_id);
                    info!(
                        "[Node {}] Vote from {} | votes={}/{}",
                        self.id, voter_id,
                        self.votes_received.len(),
                        self.quorum()
                    );
                    if self.votes_received.len() >= self.quorum() {
                        self.become_leader();
                        return CandidateTransition::BecameLeader;
                    }
                }
                CandidateTransition::Stay
            }
            Message::AppendEntries { term, leader_id, prev_log_index, prev_log_term } => {
                // Another leader exists – step down if their term is ≥ ours
                if term >= self.persistent.current_term {
                    self.become_follower(term, Some(leader_id));
                    // Still need to ack the heartbeat
                    self.send_append_entries_response(leader_id, true).await;
                    return CandidateTransition::BecameFollower;
                }
                let _ = (prev_log_index, prev_log_term);
                CandidateTransition::Stay
            }
            Message::RequestVote { term, candidate_id, last_log_index, last_log_term } => {
                if term > self.persistent.current_term {
                    self.become_follower(term, None);
                    self.handle_request_vote(term, candidate_id, last_log_index, last_log_term).await;
                    return CandidateTransition::BecameFollower;
                }
                // Deny – already voted for ourselves this term
                self.send(candidate_id, Message::RequestVoteResponse {
                    term: self.persistent.current_term,
                    vote_granted: false,
                    voter_id: self.id,
                }).await;
                CandidateTransition::Stay
            }
            Message::AppendEntriesResponse { .. } => CandidateTransition::Stay,
        }
    }

    /// Returns true if the leader stepped down.
    async fn handle_message_as_leader(&mut self, envelope: Envelope) -> bool {
        debug!("[Node {}] Leader recv: {}", self.id, envelope.message);
        match envelope.message {
            Message::RequestVote { term, candidate_id, .. } => {
                if term > self.persistent.current_term {
                    self.become_follower(term, None);
                    // Grant vote – already stepped down
                    self.send(candidate_id, Message::RequestVoteResponse {
                        term: self.persistent.current_term,
                        vote_granted: true,
                        voter_id: self.id,
                    }).await;
                    return true;
                }
                // Deny vote – we're still leader in this term
                self.send(candidate_id, Message::RequestVoteResponse {
                    term: self.persistent.current_term,
                    vote_granted: false,
                    voter_id: self.id,
                }).await;
                false
            }
            Message::AppendEntries { term, leader_id, .. } => {
                if term > self.persistent.current_term {
                    self.become_follower(term, Some(leader_id));
                    return true;
                }
                false
            }
            Message::AppendEntriesResponse { term, .. } => {
                if term > self.persistent.current_term {
                    self.become_follower(term, None);
                    return true;
                }
                false
            }
            Message::RequestVoteResponse { term, .. } => {
                if term > self.persistent.current_term {
                    self.become_follower(term, None);
                    return true;
                }
                false
            }
        }
    }

    // ── Raft-specific helpers ─────────────────────

    /// Handle an incoming RequestVote RPC.
    async fn handle_request_vote(
        &mut self,
        term: u64,
        candidate_id: u64,
        _last_log_index: u64,
        _last_log_term: u64,
    ) {
        // If candidate's term is higher, update our term and reset vote
        if term > self.persistent.current_term {
            self.persistent.current_term = term;
            self.persistent.voted_for = None;
            self.role = Role::Follower;
        }

        let vote_granted = if term < self.persistent.current_term {
            false
        } else {
            // Grant if we haven't voted yet (or already voted for this candidate)
            let can_vote = self.persistent.voted_for.is_none()
                || self.persistent.voted_for == Some(candidate_id);
            // NOTE: Log-completeness check omitted for clarity
            can_vote
        };

        if vote_granted {
            self.persistent.voted_for = Some(candidate_id);
            self.last_heartbeat = Instant::now(); // reset election timer
            info!(
                "[Node {}] Granting vote to {} for term {}",
                self.id, candidate_id, term
            );
        } else {
            debug!(
                "[Node {}] Denying vote to {} for term {} (voted_for={:?})",
                self.id, candidate_id, term, self.persistent.voted_for
            );
        }

        self.send(candidate_id, Message::RequestVoteResponse {
            term: self.persistent.current_term,
            vote_granted,
            voter_id: self.id,
        }).await;
    }

    /// Handle an AppendEntries (heartbeat) as a follower.
    async fn handle_append_entries_follower(
        &mut self,
        term: u64,
        leader_id: u64,
        _prev_log_index: u64,
        _prev_log_term: u64,
    ) {
        if term < self.persistent.current_term {
            // Stale leader
            self.send_append_entries_response(leader_id, false).await;
            return;
        }
        // Valid heartbeat – reset timer & update state
        if term > self.persistent.current_term {
            self.persistent.current_term = term;
            self.persistent.voted_for = None;
        }
        self.current_leader = Some(leader_id);
        self.last_heartbeat = Instant::now();
        debug!(
            "[Node {}] Heartbeat from leader {} | term={}",
            self.id, leader_id, term
        );
        self.send_append_entries_response(leader_id, true).await;
    }

    // ── Broadcasting helpers ──────────────────────

    async fn broadcast_request_vote(&mut self) {
        let msg = Message::RequestVote {
            term: self.persistent.current_term,
            candidate_id: self.id,
            last_log_index: 0,
            last_log_term: 0,
        };
        for &peer in &self.peers.clone() {
            self.send(peer, msg.clone()).await;
        }
    }

    async fn broadcast_append_entries(&mut self) {
        let msg = Message::AppendEntries {
            term: self.persistent.current_term,
            leader_id: self.id,
            prev_log_index: 0,
            prev_log_term: 0,
        };
        for &peer in &self.peers.clone() {
            self.send(peer, msg.clone()).await;
        }
    }

    async fn send_append_entries_response(&mut self, to: u64, success: bool) {
        self.send(to, Message::AppendEntriesResponse {
            term: self.persistent.current_term,
            success,
            follower_id: self.id,
        }).await;
    }

    /// Send a message to `to` node.
    async fn send(&self, to: u64, message: Message) {
        if let Some(sender) = self.senders.get(&to) {
            let envelope = Envelope { from: self.id, to, message };
            if let Err(e) = sender.send(envelope).await {
                warn!("[Node {}] Failed to send to {}: {}", self.id, to, e);
            }
        } else {
            warn!("[Node {}] No channel for node {}", self.id, to);
        }
    }

    // ── Utilities ────────────────────────────────

    /// Majority quorum size
    fn quorum(&self) -> usize {
        (self.peers.len() + 1) / 2 + 1
    }
}

// ── Helpers ──────────────────────────────────────

/// Returns a random election timeout in [ELECTION_TIMEOUT_MIN_MS, ELECTION_TIMEOUT_MAX_MS]
fn random_election_timeout() -> Duration {
    let ms = rand::thread_rng()
        .gen_range(ELECTION_TIMEOUT_MIN_MS..=ELECTION_TIMEOUT_MAX_MS);
    Duration::from_millis(ms)
}

enum CandidateTransition {
    BecameLeader,
    BecameFollower,
    Stay,
}
```

