use tokio::time::{sleep, Duration};
use tracing::info;
use tracing_subscriber::{EnvFilter, fmt};

use network::Network;
use node::Node;

#[tokio::main]
async fn main() {
    // ── Tracing setup ────────────────────────────
    fmt()
        .with_env_filter(
            EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| EnvFilter::new("info")),
        )
        .with_target(false)
        .with_thread_ids(false)
        .init();

    info!("=== Raft Leader Election Demo ===");
    info!("Cluster size: 5 nodes");
    info!("Election timeout: 150–300 ms | Heartbeat: 50 ms");
    info!("Running for 5 seconds...");
    info!("================================================");

    let node_ids: Vec<u64> = (1..=5).collect();

    // ── Build network ────────────────────────────
    let mut network = Network::new();
    let mut receivers = HashMap::new();

    for &id in &node_ids {
        let rx = network.register(id);
        receivers.insert(id, rx);
    }

    let senders = network.get_senders();

    // ── Spawn nodes ──────────────────────────────
    for &id in &node_ids {
        let peers: Vec<u64> = node_ids.iter().cloned().filter(|&p| p != id).collect();
        let rx = receivers.remove(&id).unwrap();
        let node = Node::new(id, peers, senders.clone(), rx);

        tokio::spawn(async move {
            node.run().await;
        });
    }

    // Let the cluster elect a leader and send heartbeats for 5 seconds
    sleep(Duration::from_secs(5)).await;

    info!("================================================");
    info!("Demo complete.");
}
