## Key Design Decisions

| Decision | Rationale |
|---|---|
| **Power-of-2 requirement** | Batcher's algorithm is a sorting *network* — the comparison pattern is fixed and requires 2ⁿ inputs |
| **Auto-padding in `Vec` variant** | Convenience wrapper that pads to next power of 2, then truncates |
| **`compare_and_swap` abstraction** | Mirrors actual hardware sorting network terminology |
| **`generate_network`** | Separates the network structure for visualization or parallel scheduling |
| **Trait bounds `T: Ord`** | Works on any totally-ordered type without requiring `Copy` |

## Complexity

- **Time (sequential):** O(n log²n) comparisons  
- **Depth (parallel):** O(log²n) — all comparators within a stage are independent  
- **Space:** O(log²n) stack depth due to recursion

# Persistent Red-Black Tree in Rust

A persistent (functional) red-black tree where every operation produces a new version while sharing structure with previous versions.

## Implementation

```rust
use std::sync::Arc;
use std::fmt::Debug;

// ── Color ─────────────────────────────────────────────────────────────────────

#[derive(Clone, Debug, PartialEq)]
enum Color {
    Red,
    Black,
}

// ── Node ──────────────────────────────────────────────────────────────────────

/// An inner node; stored behind Arc for O(1) clone / structural sharing.
#[derive(Clone, Debug)]
struct Node<K, V> {
    color:  Color,
    key:    K,
    value:  V,
    left:   Tree<K, V>,
    right:  Tree<K, V>,
}

// ── Tree ──────────────────────────────────────────────────────────────────────

/// A persistent red-black tree.
/// `None` represents the empty (black) leaf.
#[derive(Clone, Debug)]
pub struct Tree<K, V>(Option<Arc<Node<K, V>>>);

impl<K, V> Default for Tree<K, V> {
    fn default() -> Self { Tree(None) }
}

// ── helpers ───────────────────────────────────────────────────────────────────

impl<K: Clone, V: Clone> Tree<K, V> {
    fn color(&self) -> Color {
        match &self.0 {
            None    => Color::Black,
            Some(n) => n.color.clone(),
        }
    }

    fn is_red(&self) -> bool { self.color() == Color::Red }

    /// Construct a node (does **not** re-balance).
    fn node(color: Color, key: K, value: V, left: Tree<K, V>, right: Tree<K, V>) -> Self {
        Tree(Some(Arc::new(Node { color, key, value, left, right })))
    }

    /// Paint the root a given color; returns a new tree.
    fn paint(&self, color: Color) -> Self {
        match &self.0 {
            None    => Tree(None),
            Some(n) => Tree::node(color, n.key.clone(), n.value.clone(),
                                  n.left.clone(), n.right.clone()),
        }
    }
}

// ── balance ───────────────────────────────────────────────────────────────────

/// Okasaki-style four-pattern balance for insertions.
///
/// All four cases push a red node upward while keeping the black-height
/// invariant intact.
fn balance<K: Clone, V: Clone>(
    color: Color,
    key:   K,
    value: V,
    left:  Tree<K, V>,
    right: Tree<K, V>,
) -> Tree<K, V> {
    // We destructure up to two levels deep to detect the four red-violation
    // patterns.  Every other case falls through to the plain constructor.

    macro_rules! node {
        ($c:expr, $k:expr, $v:expr, $l:expr, $r:expr) => {
            Tree::node($c, $k, $v, $l, $r)
        };
    }

    // Helper: true if Some(arc) and arc.color == Red
    macro_rules! is_red {
        ($t:expr) => { $t.is_red() };
    }

    match color {
        Color::Black => {
            // ── Case 1: left-left ─────────────────────────────────────────
            if let Some(ll) = &left.0 {
                if ll.color == Color::Red {
                    if let Some(lll) = &ll.left.0 {
                        if lll.color == Color::Red {
                            return node!(
                                Color::Red,
                                ll.key.clone(), ll.value.clone(),
                                node!(Color::Black,
                                      lll.key.clone(), lll.value.clone(),
                                      lll.left.clone(), lll.right.clone()),
                                node!(Color::Black,
                                      key, value,
                                      ll.right.clone(), right)
                            );
                        }
                    }
                    // ── Case 2: left-right ────────────────────────────────
                    if let Some(llr) = &ll.right.0 {
                        if llr.color == Color::Red {
                            return node!(
                                Color::Red,
                                llr.key.clone(), llr.value.clone(),
                                node!(Color::Black,
                                      ll.key.clone(), ll.value.clone(),
                                      ll.left.clone(), llr.left.clone()),
                                node!(Color::Black,
                                      key, value,
                                      llr.right.clone(), right)
                            );
                        }
                    }
                }
            }

            // ── Case 3: right-right ───────────────────────────────────────
            if let Some(rr) = &right.0 {
                if rr.color == Color::Red {
                    if let Some(rrr) = &rr.right.0 {
                        if rrr.color == Color::Red {
                            return node!(
                                Color::Red,
                                rr.key.clone(), rr.value.clone(),
                                node!(Color::Black,
                                      key, value,
                                      left, rr.left.clone()),
                                node!(Color::Black,
                                      rrr.key.clone(), rrr.value.clone(),
                                      rrr.left.clone(), rrr.right.clone())
                            );
                        }
                    }
                    // ── Case 4: right-left ────────────────────────────────
                    if let Some(rrl) = &rr.left.0 {
                        if rrl.color == Color::Red {
                            return node!(
                                Color::Red,
                                rrl.key.clone(), rrl.value.clone(),
                                node!(Color::Black,
                                      key, value,
                                      left, rrl.left.clone()),
                                node!(Color::Black,
                                      rr.key.clone(), rr.value.clone(),
                                      rrl.right.clone(), rr.right.clone())
                            );
                        }
                    }
                }
            }

            // No violation — plain node
            node!(Color::Black, key, value, left, right)
        }

        // Red nodes are never the target of balance in Okasaki's scheme
        Color::Red => node!(Color::Red, key, value, left, right),
    }
}

// ── balance_left / balance_right for deletion ─────────────────────────────────

/// Rebalance after removing from the *left* subtree (which lost a black).
fn balance_left<K: Clone, V: Clone>(
    color: Color,
    key:   K,
    value: V,
    left:  Tree<K, V>,   // short by one black
    right: Tree<K, V>,
) -> Tree<K, V> {
    // left is red → just recolor
    if left.is_red() {
        return Tree::node(color, key, value, left.paint(Color::Black), right);
    }
    // right is black with a red right child  (RR)
    if let Some(r) = &right.0 {
        if r.color == Color::Black {
            if let Some(rr) = &r.right.0 {
                if rr.color == Color::Red {
                    let new_right = Tree::node(
                        Color::Black,
                        rr.key.clone(), rr.value.clone(),
                        rr.left.clone(), rr.right.clone(),
                    );
                    let new_left = Tree::node(
                        Color::Black,
                        key.clone(), value.clone(),
                        left.clone(), r.left.clone(),
                    );
                    return Tree::node(color, r.key.clone(), r.value.clone(),
                                      new_left, new_right);
                }
            }
            // right is black with a red left child  (RL)
            if let Some(rl) = &r.left.0 {
                if rl.color == Color::Red {
                    let new_left = Tree::node(
                        Color::Black,
                        key, value,
                        left, rl.left.clone(),
                    );
                    let new_right = Tree::node(
                        Color::Black,
                        r.key.clone(), r.value.clone(),
                        rl.right.clone(), r.right.clone(),
                    );
                    return Tree::node(color,
                                      rl.key.clone(), rl.value.clone(),
                                      new_left, new_right);
                }
            }
            // right is black, both children black → recolor right red
            let new_right = right.paint(Color::Red);
            let t = Tree::node(Color::Black, key, value, left, new_right);
            return if color == Color::Black { mark_red(t) } else { t };
        }
        // right is red → rotate left, recurse
        if r.color == Color::Red {
            let inner = balance_left(
                Color::Black,
                key, value,
                left,
                r.left.clone(),
            );
            return Tree::node(Color::Black,
                              r.key.clone(), r.value.clone(),
                              inner, r.right.clone());
        }
    }
    unreachable!("balance_left: inconsistent tree")
}

/// Rebalance after removing from the *right* subtree (which lost a black).
fn balance_right<K: Clone, V: Clone>(
    color: Color,
    key:   K,
    value: V,
    left:  Tree<K, V>,
    right: Tree<K, V>,   // short by one black
) -> Tree<K, V> {
    if right.is_red() {
        return Tree::node(color, key, value, left, right.paint(Color::Black));
    }
    if let Some(l) = &left.0 {
        if l.color == Color::Black {
            // LL
            if let Some(ll) = &l.left.0 {
                if ll.color == Color::Red {
                    let new_left = Tree::node(
                        Color::Black,
                        ll.key.clone(), ll.value.clone(),
                        ll.left.clone(), ll.right.clone(),
                    );
                    let new_right = Tree::node(
                        Color::Black,
                        key, value,
                        l.right.clone(), right,
                    );
                    return Tree::node(color,
                                      l.key.clone(), l.value.clone(),
                                      new_left, new_right);
                }
            }
            // LR
            if let Some(lr) = &l.right.0 {
                if lr.color == Color::Red {
                    let new_left = Tree::node(
                        Color::Black,
                        l.key.clone(), l.value.clone(),
                        l.left.clone(), lr.left.clone(),
                    );
                    let new_right = Tree::node(
                        Color::Black,
                        key, value,
                        lr.right.clone(), right,
                    );
                    return Tree::node(color,
                                      lr.key.clone(), lr.value.clone(),
                                      new_left, new_right);
                }
            }
            // recolor
            let new_left = left.paint(Color::Red);
            let t = Tree::node(Color::Black, key, value, new_left, right);
            return if color == Color::Black { mark_red(t) } else { t };
        }
        // left is red → rotate right, recurse
        if l.color == Color::Red {
            let inner = balance_right(
                Color::Black,
                key, value,
                l.right.clone(),
                right,
            );
            return Tree::node(Color::Black,
                              l.key.clone(), l.value.clone(),
                              l.left.clone(), inner);
        }
    }
    unreachable!("balance_right: inconsistent tree")
}

/// Tag a node as "temporarily red" to signal a deficit up the call stack.
fn mark_red<K: Clone, V: Clone>(t: Tree<K, V>) -> Tree<K, V> {
    t.paint(Color::Red)
}

// ── public API ────────────────────────────────────────────────────────────────

impl<K: Ord + Clone, V: Clone> Tree<K, V> {
    /// The empty tree.
    pub fn new() -> Self { Tree(None) }

    // ── lookup ────────────────────────────────────────────────────────────────

    /// Returns `Some(&value)` for `key`, or `None`.
    pub fn get(&self, key: &K) -> Option<&V> {
        let mut current = self;
        loop {
            match &current.0 {
                None => return None,
                Some(n) => {
                    if key < &n.key {
                        current = &n.left;
                    } else if key > &n.key {
                        current = &n.right;
                    } else {
                        return Some(&n.value);
                    }
                }
            }
        }
    }

    /// Returns `true` if `key` is present.
    pub fn contains(&self, key: &K) -> bool { self.get(key).is_some() }

    // ── insert ────────────────────────────────────────────────────────────────

    /// Returns a new tree with `(key, value)` inserted (or updated).
    pub fn insert(&self, key: K, value: V) -> Self {
        let t = self.ins(key, value);
        t.paint(Color::Black)
    }

    fn ins(&self, key: K, value: V) -> Self {
        match &self.0 {
            None => Tree::node(Color::Red, key, value, Tree(None), Tree(None)),
            Some(n) => {
                if key < n.key {
                    balance(n.color.clone(), n.key.clone(), n.value.clone(),
                            n.left.ins(key, value), n.right.clone())
                } else if key > n.key {
                    balance(n.color.clone(), n.key.clone(), n.value.clone(),
                            n.left.clone(), n.right.ins(key, value))
                } else {
                    // update value
                    Tree::node(n.color.clone(), key, value,
                               n.left.clone(), n.right.clone())
                }
            }
        }
    }

    // ── delete ────────────────────────────────────────────────────────────────

    /// Returns a new tree with `key` removed (no-op if absent).
    pub fn delete(&self, key: &K) -> Self {
        let (t, _) = self.del(key);
        t.paint(Color::Black)
    }

    /// Returns `(new_tree, deficit)`.
    /// `deficit = true` means the subtree is one black short.
    fn del(&self, key: &K) -> (Self, bool) {
        match &self.0 {
            None => (Tree(None), false),
            Some(n) => {
                if key < &n.key {
                    let (new_left, deficit) = n.left.del(key);
                    if deficit {
                        let t = balance_left(n.color.clone(),
                                             n.key.clone(), n.value.clone(),
                                             new_left, n.right.clone());
                        // If balance_left painted root red it signals a
                        // remaining deficit
                        let still = t.is_red() && n.color == Color::Black;
                        (t.paint(Color::Black), still)
                    } else {
                        (Tree::node(n.color.clone(),
                                    n.key.clone(), n.value.clone(),
                                    new_left, n.right.clone()), false)
                    }
                } else if key > &n.key {
                    let (new_right, deficit) = n.right.del(key);
                    if deficit {
                        let t = balance_right(n.color.clone(),
                                              n.key.clone(), n.value.clone(),
                                              n.left.clone(), new_right);
                        let still = t.is_red() && n.color == Color::Black;
                        (t.paint(Color::Black), still)
                    } else {
                        (Tree::node(n.color.clone(),
                                    n.key.clone(), n.value.clone(),
                                    n.left.clone(), new_right), false)
                    }
                } else {
                    // Found the node to delete
                    self.delete_node(n)
                }
            }
        }
    }

    fn delete_node(&self, n: &Node<K, V>) -> (Self, bool) {
        match (&n.left.0, &n.right.0) {
            // Leaf
            (None, None) => {
                let deficit = n.color == Color::Black;
                (Tree(None), deficit)
            }
            // Only left child (must be a red leaf by RB invariants)
            (Some(_), None) => {
                (n.left.paint(Color::Black), false)
            }
            // Only right child (must be a red leaf by RB invariants)
            (None, Some(_)) => {
                (n.right.paint(Color::Black), false)
            }
            // Two children: replace with in-order successor (min of right)
            (Some(_), Some(_)) => {
                let (succ_k, succ_v) = n.right.min_node();
                let (new_right, deficit) = n.right.del(&succ_k);
                if deficit {
                    let t = balance_right(n.color.clone(),
                                         succ_k, succ_v,
                                         n.left.clone(), new_right);
                    let still = t.is_red() && n.color == Color::Black;
                    (t.paint(Color::Black), still)
                } else {
                    (Tree::node(n.color.clone(), succ_k, succ_v,
                                n.left.clone(), new_right), false)
                }
            }
        }
    }

    /// Returns the `(key, value)` of the minimum node.
    fn min_node(&self) -> (K, V) {
        let mut cur = self;
        loop {
            match &cur.0 {
                None => panic!("min_node on empty tree"),
                Some(n) => {
                    if n.left.0.is_none() {
                        return (n.key.clone(), n.value.clone());
                    }
                    cur = &n.left;
                }
            }
        }
    }

    // ── min / max ─────────────────────────────────────────────────────────────

    pub fn min(&self) -> Option<(&K, &V)> {
        let mut cur = self;
        let mut result = None;
        loop {
            match &cur.0 {
                None => return result,
                Some(n) => {
                    result = Some((&n.key, &n.value));
                    cur = &n.left;
                }
            }
        }
    }

    pub fn max(&self) -> Option<(&K, &V)> {
        let mut cur = self;
        let mut result = None;
        loop {
            match &cur.0 {
                None => return result,
                Some(n) => {
                    result = Some((&n.key, &n.value));
                    cur = &n.right;
                }
            }
        }
    }

    // ── size / is_empty ───────────────────────────────────────────────────────

    pub fn is_empty(&self) -> bool { self.0.is_none() }

    pub fn size(&self) -> usize {
        match &self.0 {
            None    => 0,
            Some(n) => 1 + n.left.size() + n.right.size(),
        }
    }

    // ── in-order iteration ────────────────────────────────────────────────────

    /// Collect all `(key, value)` pairs in sorted order.
    pub fn to_vec(&self) -> Vec<(&K, &V)> {
        let mut out = Vec::new();
        self.collect(&mut out);
        out
    }

    fn collect<'a>(&'a self, out: &mut Vec<(&'a K, &'a V)>) {
        if let Some(n) = &self.0 {
            n.left.collect(out);
            out.push((&n.key, &n.value));
            n.right.collect(out);
        }
    }

    // ── invariant checker (for tests) ─────────────────────────────────────────

    /// Panics if any red-black invariant is violated.
    /// Returns the black-height of the tree.
    pub fn check_invariants(&self) -> usize {
        match &self.0 {
            None => 1,  // leaves are black, count 1
            Some(n) => {
                // invariant 1: red nodes have black children
                if n.color == Color::Red {
                    assert!(n.left.color()  == Color::Black,
                            "Red node has red left child");
                    assert!(n.right.color() == Color::Black,
                            "Red node has red right child");
                }
                let lh = n.left.check_invariants();
                let rh = n.right.check_invariants();
                assert_eq!(lh, rh,
                    "Black-height mismatch: left={lh}, right={rh} at key");
                lh + if n.color == Color::Black { 1 } else { 0 }
            }
        }
    }
}

// ── Display ───────────────────────────────────────────────────────────────────

impl<K: Debug + Ord + Clone, V: Debug + Clone> Tree<K, V> {
    /// Pretty-print the tree structure.
    pub fn display(&self) {
        self.display_inner("", true);
    }

    fn display_inner(&self, prefix: &str, is_left: bool) {
        if let Some(n) = &self.0 {
            let connector = if is_left { "├── " } else { "└── " };
            let color_char = if n.color == Color::Red { 'R' } else { 'B' };
            println!("{prefix}{connector}[{color_char}] {:?}: {:?}",
                     n.key, n.value);
            let new_prefix = format!("{}{}", prefix,
                                     if is_left { "│   " } else { "    " });
            n.left.display_inner(&new_prefix, true);
            n.right.display_inner(&new_prefix, false);
        }
    }
}

// ── tests ─────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    fn check<K: Ord + Clone + Debug, V: Clone + Debug>(t: &Tree<K, V>) {
        // root must be black
        assert_ne!(t.color(), Color::Red, "root must be black");
        t.check_invariants();
    }

    #[test]
    fn test_empty() {
        let t: Tree<i32, &str> = Tree::new();
        assert!(t.is_empty());
        assert_eq!(t.size(), 0);
        assert_eq!(t.get(&1), None);
        check(&t);
    }

    #[test]
    fn test_single_insert() {
        let t = Tree::new().insert(1, "one");
        assert_eq!(t.get(&1), Some(&"one"));
        assert_eq!(t.size(), 1);
        check(&t);
    }

    #[test]
    fn test_multiple_inserts() {
        let t = Tree::new()
            .insert(5, "five")
            .insert(3, "three")
            .insert(7, "seven")
            .insert(1, "one")
            .insert(4, "four");
        assert_eq!(t.size(), 5);
        assert_eq!(t.get(&3), Some(&"three"));
        assert_eq!(t.get(&7), Some(&"seven"));
        assert_eq!(t.get(&9), None);
        check(&t);
    }

    #[test]
    fn test_update() {
        let t1 = Tree::new().insert(1, "one");
        let t2 = t1.insert(1, "ONE");
        // t1 unchanged
        assert_eq!(t1.get(&1), Some(&"one"));
        assert_eq!(t2.get(&1), Some(&"ONE"));
        assert_eq!(t2.size(), 1);
        check(&t1);
        check(&t2);
    }

    #[test]
    fn test_persistence() {
        let t0: Tree<i32, i32> = Tree::new();
        let t1 = t0.insert(10, 10);
        let t2 = t1.insert(20, 20);
        let t3 = t2.insert(30, 30);

        // All old versions still valid
        assert_eq!(t0.size(), 0);
        assert_eq!(t1.size(), 1);
        assert_eq!(t2.size(), 2);
        assert_eq!(t3.size(), 3);
        check(&t0); check(&t1); check(&t2); check(&t3);
    }

    #[test]
    fn test_sorted_order() {
        let keys = [5, 2, 8, 1, 3, 7, 9, 4, 6];
        let t = keys.iter().fold(Tree::new(), |acc, &k| acc.insert(k, k * 10));
        let pairs = t.to_vec();
        let got: Vec<i32> = pairs.iter().map(|(&k, _)| k).collect();
        let mut expected: Vec<i32> = keys.to_vec();
        expected.sort();
        assert_eq!(got, expected);
        check(&t);
    }

    #[test]
    fn test_delete_leaf() {
        let t = Tree::new().insert(2, 2).insert(1, 1).insert(3, 3);
        check(&t);
        let t2 = t.delete(&1);
        assert_eq!(t2.get(&1), None);
        assert_eq!(t2.size(), 2);
        // original unchanged
        assert_eq!(t.get(&1), Some(&1));
        check(&t2);
    }

    #[test]
    fn test_delete_root() {
        let t = Tree::new().insert(2, 2).insert(1, 1).insert(3, 3);
        let t2 = t.delete(&2);
        assert_eq!(t2.get(&2), None);
        assert_eq!(t2.size(), 2);
        check(&t2);
    }

    #[test]
    fn test_delete_absent() {
        let t = Tree::new().insert(1, 1).insert(2, 2);
        let t2 = t.delete(&99);
        assert_eq!(t2.size(), 2);
        check(&t2);
    }

    #[test]
    fn test_delete_all() {
        let keys = [5, 3, 7, 1, 4, 6, 8];
        let t = keys.iter().fold(Tree::new(), |acc, &k| acc.insert(k, k));
        check(&t);
        let final_t = keys.iter().fold(t, |acc, k| {
            let next = acc.delete(k);
            check(&next);
            next
        });
        assert!(final_t.is_empty());
    }

    #[test]
    fn test_min_max() {
        let t = Tree::new()
            .insert(5, 5).insert(3, 3).insert(8, 8)
            .insert(1, 1).insert(9, 9);
        assert_eq!(t.min(), Some((&1, &1)));
        assert_eq!(t.max(), Some((&9, &9)));
    }

    #[test]
    fn test_large_sequential() {
        let n = 500;
        let t = (0..n).fold(Tree::new(), |acc, i| acc.insert(i, i * 2));
        check(&t);
        assert_eq!(t.size(), n as usize);
        for i in 0..n {
            assert_eq!(t.get(&i), Some(&(i * 2)));
        }
    }

    #[test]
    fn test_large_delete() {
        let n = 200i32;
        let t = (0..n).fold(Tree::new(), |acc, i| acc.insert(i, i));
        // delete even numbers
        let t2 = (0..n).step_by(2).fold(t, |acc, i| {
            let next = acc.delete(&i);
            check(&next);
            next
        });
        assert_eq!(t2.size(), (n / 2) as usize);
        for i in (1..n).step_by(2) { assert_eq!(t2.get(&i), Some(&i)); }
        for i in (0..n).step_by(2) { assert_eq!(t2.get(&i), None); }
    }
}

