fn main() {
    println!("=== Persistent Red-Black Tree Demo ===\n");

    // Build initial tree
    let t0: Tree<&str, i32> = Tree::new();
    let t1 = t0
        .insert("banana",  3)
        .insert("apple",   5)
        .insert("cherry",  1)
        .insert("date",    8)
        .insert("elderberry", 2);

    println!("t1 ({} nodes):", t1.size());
    t1.display();
    println!();

    // Insert into t1 → t2
    let t2 = t1.insert("fig", 7).insert("grape", 4);
    println!("t2 after adding fig & grape ({} nodes):", t2.size());
    t2.display();
    println!();

    // Delete from t2 → t3
    let t3 = t2.delete(&"banana").delete(&"date");
    println!("t3 after deleting banana & date ({} nodes):", t3.size());
    t3.display();
    println!();

    // Show all versions are independent
    println!("--- Persistence check ---");
    println!("t1.get(banana) = {:?}", t1.get(&"banana"));
    println!("t2.get(banana) = {:?}", t2.get(&"banana"));
    println!("t3.get(banana) = {:?}", t3.get(&"banana"));
    println!();

    // Sorted contents
    println!("t2 sorted: {:?}", t2.to_vec());
    println!("t3 sorted: {:?}", t3.to_vec());
    println!();

    // Invariant checks
    t1.check_invariants();
    t2.check_invariants();
    t3.check_invariants();
    println!("All invariants satisfied for t1, t2, t3.");
}
