#[cfg(test)]
mod tests {
    use super::*;

    fn make_linked_list(gc: &mut GarbageCollector, len: usize) -> GcId {
        // Build: head -> node1 -> node2 -> ... (tail has no next)
        let mut prev = gc.allocate(format!("node_{}", len - 1));
        gc.set_field(prev, "value", Value::Int((len - 1) as i64));

        for i in (0..len - 1).rev() {
            let node = gc.allocate(format!("node_{i}"));
            gc.set_field(node, "value", Value::Int(i as i64));
            gc.set_field(node, "next",  Value::Ref(prev));
            prev = node;
        }
        prev // head
    }

    #[test]
    fn test_basic_collection() {
        let mut gc = GarbageCollector::new();

        let a = gc.allocate("A");
        let b = gc.allocate("B");
        let c = gc.allocate("C"); // will be unreachable

        gc.set_field(a, "child", Value::Ref(b));
        gc.add_root(a);

        assert_eq!(gc.heap_size(), 3);

        gc.collect();

        // A and B survive; C is collected
        assert_eq!(gc.heap_size(), 2);
        assert!(gc.heap.contains_key(&a));
        assert!(gc.heap.contains_key(&b));
        assert!(!gc.heap.contains_key(&c));
    }

    #[test]
    fn test_cyclic_garbage() {
        let mut gc = GarbageCollector::new();

        let root = gc.allocate("root");
        gc.add_root(root);

        // cycle: x -> y -> x  (neither is reachable from root)
        let x = gc.allocate("x");
        let y = gc.allocate("y");
        gc.set_field(x, "next", Value::Ref(y));
        gc.set_field(y, "next", Value::Ref(x));

        assert_eq!(gc.heap_size(), 3);

        gc.collect();

        // Only root survives
        assert_eq!(gc.heap_size(), 1);
        assert!(gc.heap.contains_key(&root));
    }

    #[test]
    fn test_root_removal() {
        let mut gc = GarbageCollector::new();

        let a = gc.allocate("A");
        let b = gc.allocate("B");
        gc.add_root(a);
        gc.add_root(b);

        gc.collect();
        assert_eq!(gc.heap_size(), 2);

        gc.remove_root(b);
        gc.collect();

        assert_eq!(gc.heap_size(), 1);
        assert!(gc.heap.contains_key(&a));
    }

    #[test]
    fn test_linked_list_survives() {
        let mut gc = GarbageCollector::new();
        let head = make_linked_list(&mut gc, 5);
        gc.add_root(head);

        gc.collect();

        assert_eq!(gc.heap_size(), 5, "entire linked list should survive");
    }

    #[test]
    fn test_linked_list_collected_after_root_drop() {
        let mut gc = GarbageCollector::new();
        let head = make_linked_list(&mut gc, 5);
        gc.add_root(head);
        gc.collect();
        assert_eq!(gc.heap_size(), 5);

        gc.remove_root(head);
        gc.collect();
        assert_eq!(gc.heap_size(), 0, "entire list should be collected");
    }

    #[test]
    fn test_incremental_collection() {
        let mut gc = GarbageCollector::new();

        let root = gc.allocate("root");
        gc.add_root(root);
        let alive = gc.allocate("alive");
        gc.set_field(root, "ptr", Value::Ref(alive));
        let _dead = gc.allocate("dead"); // not reachable

        gc.incremental_start();

        // Step one object at a time
        loop {
            let done = gc.incremental_step(1);
            if done { break; }
        }

        gc.incremental_finish();

        assert_eq!(gc.heap_size(), 2);
        assert!(gc.heap.contains_key(&root));
        assert!(gc.heap.contains_key(&alive));
    }

    #[test]
    fn test_write_barrier() {
        let mut gc = GarbageCollector::new();

        let root   = gc.allocate("root");
        let object = gc.allocate("object");
        let late   = gc.allocate("late_addition");

        gc.add_root(root);
        gc.set_field(root, "ptr", Value::Ref(object));

        // Start incremental mark
        gc.incremental_start();

        // Partially advance marking so root & object become Black
        while !gc.gray_queue.is_empty() {
            gc.incremental_step(1);
        }

        // Mutator writes a new pointer into an already-Black object.
        // The write barrier must re-gray `object` so `late` is not swept.
        gc.set_field(object, "extra", Value::Ref(late));

        // Finish marking (write barrier drains on next step call)
        gc.incremental_step(usize::MAX);
        gc.incremental_finish();

        assert!(
            gc.heap.contains_key(&late),
            "write barrier must keep `late` alive"
        );
    }

    #[test]
    fn test_multiple_cycles() {
        let mut gc = GarbageCollector::new();
        let root = gc.allocate("root");
        gc.add_root(root);

        for i in 0..10 {
            let tmp = gc.allocate(format!("tmp_{i}"));
            gc.set_field(root, "tmp", Value::Ref(tmp));
            gc.collect();
            // Only root + tmp survive; previous tmp was overwritten
            assert_eq!(gc.heap_size(), 2);
        }

        assert_eq!(gc.stats.cycles, 10);
    }

    #[test]
    fn test_list_value_references() {
        let mut gc = GarbageCollector::new();

        let root = gc.allocate("root");
        let a    = gc.allocate("A");
        let b    = gc.allocate("B");
        let dead = gc.allocate("dead");

        gc.add_root(root);
        // Store multiple refs in a list field
        gc.set_field(root, "children", Value::List(vec![
            Value::Ref(a),
            Value::Ref(b),
            Value::Int(42),
        ]));

        gc.collect();

        assert_eq!(gc.heap_size(), 3);
        assert!(gc.heap.contains_key(&root));
        assert!(gc.heap.contains_key(&a));
        assert!(gc.heap.contains_key(&b));
        assert!(!gc.heap.contains_key(&dead));
    }

    #[test]
    fn test_stats_accumulate() {
        let mut gc = GarbageCollector::new();
        let root = gc.allocate("root");
        gc.add_root(root);
        let _ = gc.allocate("garbage");

        gc.collect();

        assert_eq!(gc.stats.cycles,          1);
        assert_eq!(gc.stats.total_allocated, 2);
        assert_eq!(gc.stats.objects_freed,   1);
        assert_eq!(gc.stats.objects_kept,    1);
    }
}

