# Lamport Timestamps in Rust

## Overview

Lamport timestamps provide a logical clock mechanism for ordering events in distributed systems. The algorithm follows three rules:
1. Increment clock on each local event
2. Increment clock on message send
3. On receive: `clock = max(local, received) + 1`

## Implementation

```rust
use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;
use std::fmt;

// ─────────────────────────────────────────────
// Core Lamport Clock
// ─────────────────────────────────────────────

#[derive(Debug, Clone)]
pub struct LamportClock {
    time: u64,
    process_id: u32,
}

impl LamportClock {
    pub fn new(process_id: u32) -> Self {
        Self { time: 0, process_id }
    }

    /// Rule 1: Tick on a local event
    pub fn tick(&mut self) -> u64 {
        self.time += 1;
        self.time
    }

    /// Rule 2: Stamp a message before sending
    pub fn send(&mut self) -> Timestamp {
        self.time += 1;
        Timestamp {
            time: self.time,
            process_id: self.process_id,
        }
    }

    /// Rule 3: Update on message receive
    pub fn receive(&mut self, incoming: u64) -> u64 {
        self.time = self.time.max(incoming) + 1;
        self.time
    }

    pub fn current(&self) -> u64 {
        self.time
    }
}

// ─────────────────────────────────────────────
// Timestamp (totally ordered via tie-breaking)
// ─────────────────────────────────────────────

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Timestamp {
    pub time: u64,
    pub process_id: u32,
}

impl Timestamp {
    pub fn new(time: u64, process_id: u32) -> Self {
        Self { time, process_id }
    }
}

impl PartialOrd for Timestamp {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Timestamp {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        // Primary: logical time; secondary: process_id (tie-breaker)
        self.time
            .cmp(&other.time)
            .then(self.process_id.cmp(&other.process_id))
    }
}

impl fmt::Display for Timestamp {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "(t={}, pid={})", self.time, self.process_id)
    }
}

// ─────────────────────────────────────────────
// Event
// ─────────────────────────────────────────────

#[derive(Debug, Clone)]
pub enum EventKind {
    Local(String),
    Send { to: u32, payload: String },
    Receive { from: u32, payload: String },
}

#[derive(Debug, Clone)]
pub struct Event {
    pub timestamp: Timestamp,
    pub kind: EventKind,
}

impl Event {
    pub fn new(timestamp: Timestamp, kind: EventKind) -> Self {
        Self { timestamp, kind }
    }
}

impl fmt::Display for Event {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match &self.kind {
            EventKind::Local(msg) => {
                write!(f, "[{}] LOCAL      | {}", self.timestamp, msg)
            }
            EventKind::Send { to, payload } => {
                write!(f, "[{}] SEND → P{} | {}", self.timestamp, to, payload)
            }
            EventKind::Receive { from, payload } => {
                write!(f, "[{}] RECV ← P{} | {}", self.timestamp, from, payload)
            }
        }
    }
}

// ─────────────────────────────────────────────
// Message (sent between processes)
// ─────────────────────────────────────────────

#[derive(Debug, Clone)]
pub struct Message {
    pub sender_id: u32,
    pub timestamp: u64,
    pub payload: String,
}

// ─────────────────────────────────────────────
// Process
// ─────────────────────────────────────────────

pub struct Process {
    pub id: u32,
    clock: LamportClock,
    pub history: Vec<Event>,
    /// Outgoing channels: process_id → shared queue
    channels: HashMap<u32, Arc<Mutex<Vec<Message>>>>,
}

impl Process {
    pub fn new(id: u32) -> Self {
        Self {
            id,
            clock: LamportClock::new(id),
            history: Vec::new(),
            channels: HashMap::new(),
        }
    }

    /// Connect this process to a shared channel toward `target_id`
    pub fn add_channel(&mut self, target_id: u32, queue: Arc<Mutex<Vec<Message>>>) {
        self.channels.insert(target_id, queue);
    }

    /// Perform a local event
    pub fn local_event(&mut self, description: &str) {
        let t = self.clock.tick();
        let ts = Timestamp::new(t, self.id);
        self.history
            .push(Event::new(ts, EventKind::Local(description.to_string())));
        println!("P{} LOCAL      {ts} — {description}", self.id);
    }

    /// Send a message to `target_id`
    pub fn send(&mut self, target_id: u32, payload: &str) {
        let ts = self.clock.send();
        let stamp = Timestamp::new(ts.time, self.id);

        self.history.push(Event::new(
            stamp,
            EventKind::Send {
                to: target_id,
                payload: payload.to_string(),
            },
        ));
        println!("P{} SEND → P{target_id} {stamp} — {payload}", self.id);

        if let Some(queue) = self.channels.get(&target_id) {
            let mut q = queue.lock().unwrap();
            q.push(Message {
                sender_id: self.id,
                timestamp: ts.time,
                payload: payload.to_string(),
            });
        } else {
            eprintln!("P{}: no channel to P{}", self.id, target_id);
        }
    }

    /// Receive all pending messages from the shared incoming queue
    pub fn receive_all(&mut self, queue: &Arc<Mutex<Vec<Message>>>) {
        let messages: Vec<Message> = {
            let mut q = queue.lock().unwrap();
            q.drain(..).collect()
        };

        for msg in messages {
            let t = self.clock.receive(msg.timestamp);
            let ts = Timestamp::new(t, self.id);
            println!(
                "P{} RECV ← P{} {ts} — {}",
                self.id, msg.sender_id, msg.payload
            );
            self.history.push(Event::new(
                ts,
                EventKind::Receive {
                    from: msg.sender_id,
                    payload: msg.payload,
                },
            ));
        }
    }

    pub fn current_time(&self) -> u64 {
        self.clock.current()
    }

    /// Sorted event history (causal order)
    pub fn sorted_history(&self) -> Vec<&Event> {
        let mut events: Vec<&Event> = self.history.iter().collect();
        events.sort_by_key(|e| e.timestamp);
        events
    }
}

// ─────────────────────────────────────────────
// EventLog — global causal ordering across all processes
// ─────────────────────────────────────────────

pub struct EventLog {
    events: Vec<Event>,
}

impl EventLog {
    pub fn new() -> Self {
        Self { events: Vec::new() }
    }

    pub fn merge(&mut self, process: &Process) {
        self.events.extend(process.history.iter().cloned());
    }

    pub fn print_ordered(&mut self) {
        self.events.sort_by_key(|e| e.timestamp);
        println!("\n══════════════════════════════════════════════");
        println!("  Global Event Log (causal order)");
        println!("══════════════════════════════════════════════");
        for (i, event) in self.events.iter().enumerate() {
            println!("  {:>3}. {}", i + 1, event);
        }
        println!("══════════════════════════════════════════════\n");
    }
}

