// Demo Scenarios
// ─────────────────────────────────────────────

fn separator(title: &str) {
    println!("\n{}", "─".repeat(55));
    println!("  Scenario: {title}");
    println!("{}\n", "─".repeat(55));
}

/// Scenario 1: Simple linear chain P0 → P1 → P2
fn scenario_linear_chain() {
    separator("Linear Chain  P0 → P1 → P2");

    let q01: Arc<Mutex<Vec<Message>>> = Arc::new(Mutex::new(Vec::new()));
    let q12: Arc<Mutex<Vec<Message>>> = Arc::new(Mutex::new(Vec::new()));

    let mut p0 = Process::new(0);
    let mut p1 = Process::new(1);
    let mut p2 = Process::new(2);

    p0.add_channel(1, Arc::clone(&q01));
    p1.add_channel(2, Arc::clone(&q12));

    p0.local_event("start computation");
    p0.local_event("prepare data");
    p0.send(1, "data packet");

    p1.local_event("idle");
    p1.receive_all(&q01);
    p1.local_event("process packet");
    p1.send(2, "processed result");

    p2.receive_all(&q12);
    p2.local_event("consume result");

    let mut log = EventLog::new();
    log.merge(&p0);
    log.merge(&p1);
    log.merge(&p2);
    log.print_ordered();
}

/// Scenario 2: Concurrent events + cross-messages
fn scenario_concurrent() {
    separator("Concurrent Events + Cross-Messages");

    let q01: Arc<Mutex<Vec<Message>>> = Arc::new(Mutex::new(Vec::new()));
    let q10: Arc<Mutex<Vec<Message>>> = Arc::new(Mutex::new(Vec::new()));

    let mut p0 = Process::new(0);
    let mut p1 = Process::new(1);

    p0.add_channel(1, Arc::clone(&q01));
    p1.add_channel(0, Arc::clone(&q10));

    // Concurrent starts
    p0.local_event("init A");
    p1.local_event("init B");

    // Cross-send
    p0.send(1, "hello from P0");
    p1.send(0, "hello from P1");

    // Both receive
    p0.receive_all(&q10);
    p1.receive_all(&q01);

    p0.local_event("got P1 greeting");
    p1.local_event("got P0 greeting");

    let mut log = EventLog::new();
    log.merge(&p0);
    log.merge(&p1);
    log.print_ordered();
}

/// Scenario 3: Three-process broadcast
fn scenario_broadcast() {
    separator("Broadcast  P0 → P1, P2");

    let q01: Arc<Mutex<Vec<Message>>> = Arc::new(Mutex::new(Vec::new()));
    let q02: Arc<Mutex<Vec<Message>>> = Arc::new(Mutex::new(Vec::new()));

    let mut p0 = Process::new(0);
    let mut p1 = Process::new(1);
    let mut p2 = Process::new(2);

    p0.add_channel(1, Arc::clone(&q01));
    p0.add_channel(2, Arc::clone(&q02));

    p1.local_event("waiting");
    p2.local_event("waiting");

    p0.local_event("preparing broadcast");
    p0.send(1, "broadcast msg");
    p0.send(2, "broadcast msg");

    p1.receive_all(&q01);
    p2.receive_all(&q02);

    p1.local_event("handled broadcast");
    p2.local_event("handled broadcast");

    let mut log = EventLog::new();
    log.merge(&p0);
    log.merge(&p1);
    log.merge(&p2);
