/// Scenario 4: Demonstrate total ordering with tie-breaking
fn scenario_tie_breaking() {
    separator("Total Order Tie-Breaking");

    let mut timestamps = vec![
        Timestamp::new(5, 2),
        Timestamp::new(3, 0),
        Timestamp::new(5, 1),  // same time as above → ordered by pid
        Timestamp::new(1, 3),
        Timestamp::new(3, 1),
        Timestamp::new(5, 0),  // same time, lower pid → comes first
    ];

    println!("Before sort: {:?}", timestamps);
    timestamps.sort();
    println!("After sort:  {:?}", timestamps);
    println!();
    for ts in &timestamps {
        println!("  {ts}");
    }
}

/// Scenario 5: Threaded simulation
fn scenario_threaded() {
    separator("Threaded Simulation");

    let q01: Arc<Mutex<Vec<Message>>> = Arc::new(Mutex::new(Vec::new()));
    let q10: Arc<Mutex<Vec<Message>>> = Arc::new(Mutex::new(Vec::new()));

    // Wrap processes in Arc<Mutex<>> for sharing across threads
    let p0 = Arc::new(Mutex::new(Process::new(0)));
    let p1 = Arc::new(Mutex::new(Process::new(1)));

    {
        p0.lock().unwrap().add_channel(1, Arc::clone(&q01));
        p1.lock().unwrap().add_channel(0, Arc::clone(&q10));
    }

    let p0_t = Arc::clone(&p0);
    let q10_t = Arc::clone(&q10);
    let t0 = thread::spawn(move || {
        let mut proc = p0_t.lock().unwrap();
        proc.local_event("thread 0 start");
        thread::sleep(Duration::from_millis(10));
        proc.send(1, "ping");
        thread::sleep(Duration::from_millis(30));
        proc.receive_all(&q10_t);
        proc.local_event("thread 0 done");
    });

    let p1_t = Arc::clone(&p1);
    let q01_t = Arc::clone(&q01);
    let t1 = thread::spawn(move || {
        let mut proc = p1_t.lock().unwrap();
        thread::sleep(Duration::from_millis(20));
        proc.local_event("thread 1 start");
        proc.receive_all(&q01_t);
        proc.send(0, "pong");
        proc.local_event("thread 1 done");
    });

    t0.join().unwrap();
    t1.join().unwrap();

    let mut log = EventLog::new();
    log.merge(&p0.lock().unwrap());
    log.merge(&p1.lock().unwrap());
    log.print_ordered();
}

