## Key Design Decisions

| Concern | Choice | Reason |
|---|---|---|
| **Total order** | `(time, process_id)` pair | Breaks ties deterministically |
| **Channel** | `Arc<Mutex<Vec<Message>>>` | Safe shared-memory MPSC queue |
| **Clock mutation** | `&mut self` methods | Enforces single-writer discipline |
| **History** | Per-process `Vec<Event>` | Enables post-hoc causal analysis |
| **Threading** | `Arc<Mutex<Process>>` | Composable with std threads |

## Algorithm Rules Implemented

```
tick()    → time += 1                        (local event)
send()    → time += 1; stamp message         (send event)  
receive() → time = max(local, msg.time) + 1  (receive event)
```

# Skip List Implementation in Rust

A skip list is a probabilistic data structure that allows for efficient search, insertion, and deletion operations with O(log n) average time complexity.

## Complete Implementation

```rust
use std::fmt;
use rand::Rng;

const MAX_LEVEL: usize = 16;
const PROBABILITY: f64 = 0.5;

/// A node in the skip list
struct Node<K, V> {
    key: K,
    value: V,
    forward: Vec<Option<*mut Node<K, V>>>,
}

impl<K, V> Node<K, V> {
    fn new(key: K, value: V, level: usize) -> Box<Self> {
        Box::new(Node {
            key,
            value,
            forward: vec![None; level + 1],
        })
    }
}

/// Header sentinel node with no key/value
struct Header<K, V> {
    forward: Vec<Option<*mut Node<K, V>>>,
}

impl<K, V> Header<K, V> {
    fn new() -> Box<Self> {
        Box::new(Header {
            forward: vec![None; MAX_LEVEL + 1],
        })
    }
}

/// Skip list data structure
pub struct SkipList<K, V> {
    header: Box<Header<K, V>>,
    level: usize,
    length: usize,
}

impl<K: Ord, V> SkipList<K, V> {
    /// Creates a new empty skip list
    pub fn new() -> Self {
        SkipList {
            header: Header::new(),
            level: 0,
            length: 0,
        }
    }

    /// Returns the number of elements in the skip list
    pub fn len(&self) -> usize {
        self.length
    }

    /// Returns true if the skip list is empty
    pub fn is_empty(&self) -> bool {
        self.length == 0
    }

    /// Randomly generates a level for a new node
    fn random_level() -> usize {
        let mut rng = rand::thread_rng();
        let mut level = 0;
        while rng.gen::<f64>() < PROBABILITY && level < MAX_LEVEL {
            level += 1;
        }
        level
    }

    /// Inserts a key-value pair into the skip list.
    /// If the key already exists, updates the value.
    pub fn insert(&mut self, key: K, value: V) {
        // Track the rightmost node at each level that is less than the key
        let mut update: Vec<*mut Option<*mut Node<K, V>>> = vec![std::ptr::null_mut(); MAX_LEVEL + 1];

        // Start from header's forward pointers
        let mut current_forward = &mut self.header.forward as *mut Vec<Option<*mut Node<K, V>>>;

        for i in (0..=self.level).rev() {
            loop {
                let next = unsafe { (*current_forward)[i] };
                match next {
                    Some(node_ptr) => {
                        let node = unsafe { &*node_ptr };
                        if node.key < key {
                            current_forward = &mut unsafe { &mut *node_ptr }.forward
                                as *mut Vec<Option<*mut Node<K, V>>>;
                        } else if node.key == key {
                            // Update existing key
                            unsafe { (*node_ptr).value = value };
                            return;
                        } else {
                            break;
                        }
                    }
                    None => break,
                }
            }
            update[i] = unsafe { &mut (*current_forward)[i] as *mut Option<*mut Node<K, V>> };
        }

        let new_level = Self::random_level();

        // If new level exceeds current, add header pointers for new levels
        if new_level > self.level {
            for i in (self.level + 1)..=new_level {
                update[i] = &mut self.header.forward[i] as *mut Option<*mut Node<K, V>>;
            }
            self.level = new_level;
        }

        let new_node = Box::into_raw(Node::new(key, value, new_level));

        for i in 0..=new_level {
            unsafe {
                (*new_node).forward[i] = *update[i];
                *update[i] = Some(new_node);
            }
        }

        self.length += 1;
    }

    /// Searches for a key and returns a reference to the value if found
    pub fn get(&self, key: &K) -> Option<&V> {
        let mut current_forward = &self.header.forward as *const Vec<Option<*mut Node<K, V>>>;

        for i in (0..=self.level).rev() {
            loop {
                let next = unsafe { (*current_forward)[i] };
                match next {
                    Some(node_ptr) => {
                        let node = unsafe { &*node_ptr };
                        if node.key < *key {
                            current_forward = &node.forward as *const Vec<Option<*mut Node<K, V>>>;
                        } else if node.key == *key {
                            return Some(&node.value);
                        } else {
                            break;
                        }
                    }
                    None => break,
                }
            }
        }

        None
    }

    /// Searches for a key and returns a mutable reference to the value if found
    pub fn get_mut(&mut self, key: &K) -> Option<&mut V> {
        let mut current_forward = &self.header.forward as *const Vec<Option<*mut Node<K, V>>>;

        for i in (0..=self.level).rev() {
            loop {
                let next = unsafe { (*current_forward)[i] };
                match next {
                    Some(node_ptr) => {
                        let node = unsafe { &*node_ptr };
                        if node.key < *key {
                            current_forward = &node.forward as *const Vec<Option<*mut Node<K, V>>>;
                        } else if node.key == *key {
                            return Some(unsafe { &mut (*node_ptr).value });
                        } else {
                            break;
                        }
                    }
                    None => break,
                }
            }
        }

        None
    }

    /// Returns true if the key exists in the skip list
    pub fn contains_key(&self, key: &K) -> bool {
        self.get(key).is_some()
    }

    /// Removes a key from the skip list and returns the value if it existed
    pub fn remove(&mut self, key: &K) -> Option<V> {
        let mut update: Vec<*mut Option<*mut Node<K, V>>> = vec![std::ptr::null_mut(); MAX_LEVEL + 1];
        let mut current_forward = &mut self.header.forward as *mut Vec<Option<*mut Node<K, V>>>;
        let mut target: Option<*mut Node<K, V>> = None;

        for i in (0..=self.level).rev() {
            loop {
                let next = unsafe { (*current_forward)[i] };
                match next {
                    Some(node_ptr) => {
                        let node = unsafe { &*node_ptr };
                        if node.key < *key {
                            current_forward = &mut unsafe { &mut *node_ptr }.forward
                                as *mut Vec<Option<*mut Node<K, V>>>;
                        } else {
                            break;
                        }
                    }
                    None => break,
                }
            }
            update[i] = unsafe { &mut (*current_forward)[i] as *mut Option<*mut Node<K, V>> };
        }

        // Check if the next node at level 0 matches the key
        if let Some(node_ptr) = unsafe { *update[0] } {
            let node = unsafe { &*node_ptr };
            if node.key == *key {
                target = Some(node_ptr);
            }
        }

        match target {
            None => None,
            Some(node_ptr) => {
                let node = unsafe { &*node_ptr };
                for i in 0..=self.level {
                    let update_ptr = unsafe { *update[i] };
                    if update_ptr != Some(node_ptr) {
                        break;
                    }
                    unsafe {
                        *update[i] = node.forward[i];
                    }
                }

                // Lower the level if top levels are now empty
                while self.level > 0 && self.header.forward[self.level].is_none() {
                    self.level -= 1;
                }

                self.length -= 1;

                // Reconstruct the box and drop it, returning the value
                let boxed = unsafe { Box::from_raw(node_ptr) };
                // We need to extract the value without dropping the key
                // Use ManuallyDrop to avoid double-drop
                let node = *boxed;
                Some(node.value)
            }
        }
    }

    /// Returns an iterator over the key-value pairs in sorted order
    pub fn iter(&self) -> Iter<K, V> {
        Iter {
            current: self.header.forward[0],
            _marker: std::marker::PhantomData,
        }
    }
}

/// Iterator for the skip list
pub struct Iter<'a, K, V> {
    current: Option<*mut Node<K, V>>,
    _marker: std::marker::PhantomData<&'a (K, V)>,
}

impl<'a, K, V> Iterator for Iter<'a, K, V> {
    type Item = (&'a K, &'a V);

    fn next(&mut self) -> Option<Self::Item> {
        match self.current {
            None => None,
            Some(node_ptr) => {
                let node = unsafe { &*node_ptr };
                self.current = node.forward[0];
                Some((&node.key, &node.value))
            }
        }
    }
}

impl<K: Ord, V> Default for SkipList<K, V> {
    fn default() -> Self {
        Self::new()
    }
}

impl<K: Ord, V> Drop for SkipList<K, V> {
    fn drop(&mut self) {
        let mut current = self.header.forward[0];
        while let Some(node_ptr) = current {
            let node = unsafe { Box::from_raw(node_ptr) };
            current = node.forward[0];
            // node is dropped here, freeing memory
        }
    }
}

impl<K: Ord + fmt::Debug, V: fmt::Debug> fmt::Debug for SkipList<K, V> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_map().entries(self.iter()).finish()
    }
}

impl<K: Ord + fmt::Display, V: fmt::Display> SkipList<K, V> {
    /// Prints a visual representation of the skip list structure
    pub fn display(&self) {
        println!("Skip List (level={}, len={}):", self.level, self.length);
        for i in (0..=self.level).rev() {
            print!("Level {}: HEAD", i);
            let mut current = self.header.forward[i];
            while let Some(node_ptr) = current {
                let node = unsafe { &*node_ptr };
                print!(" -> ({},{})", node.key, node.value);
                current = node.forward[i];
            }
            println!(" -> NIL");
        }
    }
}

