## Rust Implementation: Sort, Reverse, Median & Standard Deviation

```rust
fn main() {
    let data = vec![3.0_f64, 1.0, 4.0, 1.0, 5.0, 9.0, 2.0, 6.0, 5.0, 3.0, 5.0];

    let (sorted_desc, median, std_dev) = {
        // Single chained expression that does everything
        let mut v = data.clone();
        v.sort_by(|a, b| a.partial_cmp(b).unwrap()); // sort ascending
        v.reverse();                                   // reverse to descending

        let n = v.len() as f64;

        let median = if v.len() % 2 == 0 {
            (v[v.len() / 2 - 1] + v[v.len() / 2]) / 2.0
        } else {
            v[v.len() / 2]
        };

        let mean = v.iter().sum::<f64>() / n;

        let variance = v.iter()
            .map(|&x| (x - mean).powi(2))
            .sum::<f64>()
            / n; // population std dev; use (n - 1.0) for sample

        let std_dev = variance.sqrt();

        (v, median, std_dev)
    };

    println!("Sorted (descending): {:?}", sorted_desc);
    println!("Median:              {:.4}", median);
    println!("Std Deviation:       {:.4}", std_dev);
}
```

