## Cleaner Functional Version (single expression style)

```rust
fn stats(data: &[f64]) -> (Vec<f64>, f64, f64) {
    // Step 1: Sort + Reverse in one expression
    let sorted_desc: Vec<f64> = {
        let mut v = data.to_vec();
        v.sort_by(|a, b| b.partial_cmp(a).unwrap()); // sort descending directly
        v
    };

    // Step 2: Median (single expression)
    let median = match sorted_desc.len() {
        0 => panic!("Empty vector"),
        n if n % 2 == 0 => (sorted_desc[n / 2 - 1] + sorted_desc[n / 2]) / 2.0,
        n               =>  sorted_desc[n / 2],
    };

    // Step 3: Std Dev (single chained expression)
    let std_dev = {
        let n = sorted_desc.len() as f64;
        let mean = sorted_desc.iter().sum::<f64>() / n;
        (sorted_desc.iter()
            .map(|&x| (x - mean).powi(2))
            .sum::<f64>() / n)
            .sqrt()
    };

    (sorted_desc, median, std_dev)
}

fn main() {
    let data = vec![3.0_f64, 1.0, 4.0, 1.0, 5.0, 9.0, 2.0, 6.0, 5.0, 3.0, 5.0];

    let (sorted, median, std_dev) = stats(&data);

