    println!("Sorted (descending): {:?}", sorted);
    println!("Median:              {:.4}", median);
    println!("Std Deviation:       {:.4}", std_dev);

    // Edge case: even-length vector
    let data2 = vec![10.0, 20.0, 30.0, 40.0];
    let (sorted2, median2, std_dev2) = stats(&data2);
    println!("\nEven-length example:");
    println!("Sorted (descending): {:?}", sorted2);
    println!("Median:              {:.4}", median2);
    println!("Std Deviation:       {:.4}", std_dev2);
}
