fn count_vowels(s: &str) -> usize {
    s.chars()
        .filter(|c| matches!(c.to_ascii_lowercase(), 'a' | 'e' | 'i' | 'o' | 'u'))
        .count()
}

fn main() {
    let test_cases = vec![
        ("Hello, World!", 3),
        ("aeiouAEIOU", 10),
        ("rhythm", 0),
        ("", 0),
        ("Rust Programming", 4),
        ("The quick brown fox jumps over the lazy dog", 11),
