    for (input, expected) in &test_cases {
        let result = count_vowels(input);
        let status = if result == *expected { "✓" } else { "✗" };
        println!(
            "{} \"{}\" → {} vowels (expected: {})",
            status, input, result, expected
        );
    }
}
```

