        ("Hello, World!",                  false),
    ];

    println!("\n=== Alphanumeric Palindrome Check ===");
    for (input, expected) in &alphanumeric_cases {
        let result = is_palindrome_alphanumeric(input);
        let status = if result == *expected { "✓" } else { "✗" };
        println!("{} \"{}\" -> {}", status, input, result);
    }
}

