# Fibonacci Numbers in Rust

Here's a complete Rust implementation with multiple approaches:

```rust
fn main() {
    // Test all implementations
    println!("=== Fibonacci Implementations ===\n");

    // Recursive
    println!("Recursive:");
    for i in 0..10 {
        print!("{} ", fibonacci_recursive(i));
    }
    println!();

    // Iterative
    println!("\nIterative:");
    for i in 0..10 {
        print!("{} ", fibonacci_iterative(i));
    }
    println!();

    // Memoized
    println!("\nMemoized:");
    for i in 0..10 {
        print!("{} ", fibonacci_memoized(i));
    }
    println!();

    // Iterator
    println!("\nIterator (first 10 values):");
    let fibs: Vec<u64> = FibIterator::new().take(10).collect();
    println!("{:?}", fibs);

    // Large number example
    println!("\nFib(50) = {}", fibonacci_iterative(50));
}

/// Recursive approach — simple but exponential time complexity O(2^n)
fn fibonacci_recursive(n: u64) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => fibonacci_recursive(n - 1) + fibonacci_recursive(n - 2),
    }
}

/// Iterative approach — O(n) time, O(1) space
fn fibonacci_iterative(n: u64) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => {
            let (mut a, mut b) = (0u64, 1u64);
            for _ in 2..=n {
                let next = a + b;
                a = b;
                b = next;
            }
            b
        }
    }
}

/// Memoized recursive approach — O(n) time, O(n) space
fn fibonacci_memoized(n: u64) -> u64 {
    let mut memo = vec![None; (n + 1) as usize];
    fib_memo_helper(n, &mut memo)
}

fn fib_memo_helper(n: u64, memo: &mut Vec<Option<u64>>) -> u64 {
    if let Some(val) = memo[n as usize] {
        return val;
    }
    let result = match n {
        0 => 0,
        1 => 1,
        _ => fib_memo_helper(n - 1, memo) + fib_memo_helper(n - 2, memo),
    };
    memo[n as usize] = Some(result);
    result
}

/// Fibonacci iterator — lazily generates values
struct FibIterator {
    a: u64,
    b: u64,
}

impl FibIterator {
    fn new() -> Self {
        FibIterator { a: 0, b: 1 }
    }
}

impl Iterator for FibIterator {
    type Item = u64;

    fn next(&mut self) -> Option<Self::Item> {
        let next = self.a;
        self.a = self.b;
        self.b = next + self.b;
        Some(next)
    }
}
```

