## Key Design Decisions

| Aspect | Choice | Reason |
|---|---|---|
| **Format** | Level-order (BFS) | Simple to parse; maps naturally to a queue |
| **Null marker** | `"#"` | Short, unambiguous, can't be confused with integers |
| **Trailing nulls** | Stripped | Keeps output compact (leaf nodes don't need `#,#`) |
| **Error handling** | `Result<_, TreeError>` | Propagates parse errors cleanly |
| **Unsafe** | One small block with raw pointers | Needed to hold queue of `&mut` refs; safety invariant is documented |

# Trie Data Structure in Rust

## Implementation

```rust
use std::collections::HashMap;

/// A node in the Trie
#[derive(Debug, Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
    count: usize, // Number of words passing through this node
}

/// Trie data structure for efficient string storage and retrieval
#[derive(Debug, Default)]
pub struct Trie {
    root: TrieNode,
    word_count: usize,
}

impl Trie {
    /// Creates a new empty Trie
    pub fn new() -> Self {
        Self::default()
    }

    /// Inserts a word into the Trie
    ///
    /// # Examples
    /// ```
    /// let mut trie = Trie::new();
    /// trie.insert("hello");
    /// assert!(trie.search("hello"));
    /// ```
    pub fn insert(&mut self, word: &str) {
        let mut current = &mut self.root;

        for ch in word.chars() {
            let node = current.children.entry(ch).or_insert_with(TrieNode::default);
            node.count += 1;
            current = node;
        }

        if !current.is_end_of_word {
            current.is_end_of_word = true;
            self.word_count += 1;
        }
    }

    /// Searches for an exact word in the Trie
    ///
    /// Returns `true` if the word exists, `false` otherwise
    pub fn search(&self, word: &str) -> bool {
        self.find_node(word)
            .map(|node| node.is_end_of_word)
            .unwrap_or(false)
    }

    /// Checks if any word in the Trie starts with the given prefix
    ///
    /// Returns `true` if the prefix exists, `false` otherwise
    pub fn starts_with(&self, prefix: &str) -> bool {
        self.find_node(prefix).is_some()
    }

    /// Deletes a word from the Trie
    ///
    /// Returns `true` if the word was found and deleted, `false` otherwise
    pub fn delete(&mut self, word: &str) -> bool {
        if !self.search(word) {
            return false;
        }

        self.word_count -= 1;
        Self::delete_recursive(&mut self.root, word, 0)
    }

    /// Recursive helper for deletion
    fn delete_recursive(node: &mut TrieNode, word: &str, depth: usize) -> bool {
        let chars: Vec<char> = word.chars().collect();

        if depth == chars.len() {
            if node.is_end_of_word {
                node.is_end_of_word = false;
                return node.children.is_empty();
            }
            return false;
        }

        let ch = chars[depth];

        if let Some(child) = node.children.get_mut(&ch) {
            child.count -= 1;
            let should_delete = Self::delete_recursive(child, word, depth + 1);

            if should_delete {
                node.children.remove(&ch);
                return !node.is_end_of_word && node.children.is_empty();
            }
        }

        false
    }

    /// Returns all words in the Trie with the given prefix
    pub fn words_with_prefix(&self, prefix: &str) -> Vec<String> {
        let mut results = Vec::new();

        if let Some(node) = self.find_node(prefix) {
            self.collect_words(node, prefix.to_string(), &mut results);
        }

        results
    }

    /// Returns all words stored in the Trie
    pub fn all_words(&self) -> Vec<String> {
        let mut results = Vec::new();
        self.collect_words(&self.root, String::new(), &mut results);
        results
    }

    /// Counts how many words in the Trie share the given prefix
    pub fn count_words_with_prefix(&self, prefix: &str) -> usize {
        self.find_node(prefix)
            .map(|node| node.count)
            .unwrap_or(0)
    }

    /// Returns the total number of unique words in the Trie
    pub fn word_count(&self) -> usize {
        self.word_count
    }

    /// Checks if the Trie is empty
    pub fn is_empty(&self) -> bool {
        self.word_count == 0
    }

    /// Clears all words from the Trie
    pub fn clear(&mut self) {
        self.root = TrieNode::default();
        self.word_count = 0;
    }

    /// Finds the longest common prefix among all words in the Trie
    pub fn longest_common_prefix(&self) -> String {
        let mut prefix = String::new();
        let mut current = &self.root;

        loop {
            // Stop if this node marks end of a word or has multiple children
            if current.is_end_of_word || current.children.len() != 1 {
                break;
            }

            let (ch, child) = current.children.iter().next().unwrap();
            prefix.push(*ch);
            current = child;
        }

        prefix
    }

    /// Traverses the Trie to find the node at the end of the given prefix/word
    fn find_node(&self, prefix: &str) -> Option<&TrieNode> {
        let mut current = &self.root;

        for ch in prefix.chars() {
            match current.children.get(&ch) {
                Some(node) => current = node,
                None => return None,
            }
        }

        Some(current)
    }

    /// Recursively collects all words from a given node
    fn collect_words(&self, node: &TrieNode, current_word: String, results: &mut Vec<String>) {
        if node.is_end_of_word {
            results.push(current_word.clone());
        }

        // Sort children for deterministic output
        let mut children: Vec<(&char, &TrieNode)> = node.children.iter().collect();
        children.sort_by_key(|(ch, _)| *ch);

        for (ch, child) in children {
            let mut next_word = current_word.clone();
            next_word.push(*ch);
            self.collect_words(child, next_word, results);
        }
    }
}

