    println!("search('apple') -> {}", trie.search("apple"));
    println!("search('app')   -> {}", trie.search("app"));
    println!("Total words: {}", trie.word_count());

    // All words
    println!("\n--- All Words ---");
    let mut all = trie.all_words();
    all.sort();
    println!("{:?}", all);
