## Key Design Decisions

| Approach | Time | Space | Best For |
|---|---|---|---|
| `permutations_heap` | O(n·n!) | O(n!) | Collecting all results |
| `permutations_recursive` | O(n·n!) | O(n·n!) | Clarity / readability |
| `PermutationIter` | O(n) per step | O(n) | Large n, early termination |

**Highlights:**
- **Generic over `T: Clone`** — works with integers, strings, or any cloneable type
- **Heap's algorithm** generates permutations with a single swap per step (optimal)
- **Iterator implementation** is lazy and memory-efficient — ideal when you don't need all permutations at once (e.g., searching for the first match)

# Dijkstra's Shortest Path Algorithm in Rust

## Implementation

```rust
use std::collections::{BinaryHeap, HashMap};
use std::cmp::Ordering;

/// Represents an edge in the graph
#[derive(Debug, Clone)]
struct Edge {
    to: usize,
    weight: u64,
}

/// Graph represented as an adjacency list
#[derive(Debug)]
struct Graph {
    adjacency_list: Vec<Vec<Edge>>,
    num_vertices: usize,
}

impl Graph {
    /// Creates a new empty graph with `n` vertices
    fn new(n: usize) -> Self {
        Graph {
            adjacency_list: vec![vec![]; n],
            num_vertices: n,
        }
    }

    /// Adds a directed edge from `from` to `to` with the given `weight`
    fn add_edge(&mut self, from: usize, to: usize, weight: u64) {
        assert!(from < self.num_vertices, "Source vertex out of bounds");
        assert!(to < self.num_vertices, "Destination vertex out of bounds");
        self.adjacency_list[from].push(Edge { to, weight });
    }

    /// Adds an undirected edge between `u` and `v` with the given `weight`
    fn add_undirected_edge(&mut self, u: usize, v: usize, weight: u64) {
        self.add_edge(u, v, weight);
        self.add_edge(v, u, weight);
    }

    /// Runs Dijkstra's algorithm from `source` vertex.
    ///
    /// Returns:
    /// - `distances`: shortest distance from source to each vertex (u64::MAX if unreachable)
    /// - `predecessors`: previous vertex on the shortest path (None if unreachable or source)
    fn dijkstra(&self, source: usize) -> (Vec<u64>, Vec<Option<usize>>) {
        assert!(source < self.num_vertices, "Source vertex out of bounds");

        let mut distances = vec![u64::MAX; self.num_vertices];
        let mut predecessors = vec![None; self.num_vertices];
        let mut heap = BinaryHeap::new();

        distances[source] = 0;
        heap.push(State { cost: 0, vertex: source });

        while let Some(State { cost, vertex }) = heap.pop() {
            // Skip if we already found a better path
            if cost > distances[vertex] {
                continue;
            }

            for edge in &self.adjacency_list[vertex] {
                // Check for overflow before adding
                let next_cost = match distances[vertex].checked_add(edge.weight) {
                    Some(c) => c,
                    None => continue, // Skip on overflow
                };

                if next_cost < distances[edge.to] {
                    distances[edge.to] = next_cost;
                    predecessors[edge.to] = Some(vertex);
                    heap.push(State {
                        cost: next_cost,
                        vertex: edge.to,
                    });
                }
            }
        }

        (distances, predecessors)
    }

    /// Reconstructs the shortest path from `source` to `target`
    fn reconstruct_path(
        predecessors: &[Option<usize>],
        source: usize,
        target: usize,
    ) -> Option<Vec<usize>> {
        if predecessors[target].is_none() && target != source {
            return None; // No path exists
        }

        let mut path = vec![target];
        let mut current = target;

        while current != source {
            match predecessors[current] {
                Some(prev) => {
                    path.push(prev);
                    current = prev;
                }
                None => return None, // Disconnected
            }
        }

        path.reverse();
        Some(path)
    }
}

/// State used in the priority queue
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    cost: u64,
    vertex: usize,
}

/// BinaryHeap is a max-heap, so we reverse the ordering to get min-heap behavior
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        other.cost.cmp(&self.cost)
            .then_with(|| self.vertex.cmp(&other.vertex))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// ── Named-vertex convenience wrapper ─────────────────────────────────────────

/// Dijkstra on a graph whose vertices are identified by string names
struct NamedGraph {
    graph: Graph,
    name_to_id: HashMap<String, usize>,
    id_to_name: Vec<String>,
}

impl NamedGraph {
    fn new() -> Self {
        NamedGraph {
            graph: Graph::new(0),
            name_to_id: HashMap::new(),
            id_to_name: Vec::new(),
        }
    }

    fn add_vertex(&mut self, name: &str) -> usize {
        if let Some(&id) = self.name_to_id.get(name) {
            return id;
        }
        let id = self.id_to_name.len();
        self.name_to_id.insert(name.to_string(), id);
        self.id_to_name.push(name.to_string());
        self.graph.adjacency_list.push(vec![]);
        self.graph.num_vertices += 1;
        id
    }

    fn add_undirected_edge(&mut self, u: &str, v: &str, weight: u64) {
        let uid = self.add_vertex(u);
        let vid = self.add_vertex(v);
        self.graph.add_undirected_edge(uid, vid, weight);
    }

    fn shortest_path(&self, source: &str, target: &str) -> Option<(u64, Vec<String>)> {
        let &src_id = self.name_to_id.get(source)?;
        let &tgt_id = self.name_to_id.get(target)?;

        let (distances, predecessors) = self.graph.dijkstra(src_id);

        if distances[tgt_id] == u64::MAX {
            return None;
        }

        let path_ids = Graph::reconstruct_path(&predecessors, src_id, tgt_id)?;
        let path_names = path_ids
            .iter()
            .map(|&id| self.id_to_name[id].clone())
            .collect();

        Some((distances[tgt_id], path_names))
    }
}

