  Madrid → Kyiv
    Distance : 3270 km
    Path     : Madrid → Paris → Amsterdam → Berlin → Warsaw → Kyiv

  Lisbon → Kyiv
    Distance : 3910 km
    Path     : Lisbon → Madrid → Paris → Amsterdam → Berlin → Warsaw → Kyiv
```

## Key Design Decisions

| Decision | Rationale |
|---|---|
| `BinaryHeap<State>` as min-heap | Achieved by reversing `Ord` — no external crate needed |
| `u64::MAX` sentinel | Clearly signals "unreachable"; `checked_add` prevents overflow |
| Lazy deletion (`cost > distances[vertex]`) | Simpler than a decrease-key operation; still optimal |
| `predecessors` array | Enables O(path length) reconstruction without extra storage |
| `NamedGraph` wrapper | Separates string-mapping concerns from the core algorithm |

## Complexity

- **Time:** O((V + E) log V) — each vertex/edge processed at most once per heap operation  
- **Space:** O(V + E) — adjacency list + distance/predecessor arrays

# Token Bucket Rate Limiter in Rust

## Overview

A token bucket rate limiter allows bursts up to a maximum capacity while maintaining a steady average rate. Tokens are added at a fixed rate, and each request consumes one or more tokens.

## Implementation

```rust
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};
use std::thread;
use std::collections::HashMap;

/// Core token bucket implementation
#[derive(Debug)]
pub struct TokenBucket {
    /// Maximum number of tokens the bucket can hold
    capacity: f64,
    /// Current number of available tokens
    tokens: f64,
    /// Rate at which tokens are added (tokens per second)
    refill_rate: f64,
    /// Last time the bucket was refilled
    last_refill: Instant,
}

impl TokenBucket {
    /// Create a new TokenBucket
    ///
    /// # Arguments
    /// * `capacity` - Maximum tokens the bucket can hold (burst size)
    /// * `refill_rate` - Tokens added per second
    pub fn new(capacity: f64, refill_rate: f64) -> Self {
        assert!(capacity > 0.0, "Capacity must be positive");
        assert!(refill_rate > 0.0, "Refill rate must be positive");

        TokenBucket {
            capacity,
            tokens: capacity, // Start full
            refill_rate,
            last_refill: Instant::now(),
        }
    }

    /// Refill tokens based on elapsed time since last refill
    fn refill(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill).as_secs_f64();
        let new_tokens = elapsed * self.refill_rate;

        self.tokens = (self.tokens + new_tokens).min(self.capacity);
        self.last_refill = now;
    }

    /// Try to consume `count` tokens
    ///
    /// Returns `true` if tokens were available and consumed, `false` otherwise
    pub fn try_consume(&mut self, count: f64) -> bool {
        assert!(count > 0.0, "Token count must be positive");
        self.refill();

        if self.tokens >= count {
            self.tokens -= count;
            true
        } else {
            false
        }
    }

    /// Try to consume 1 token (convenience method)
    pub fn try_acquire(&mut self) -> bool {
        self.try_consume(1.0)
    }

    /// Returns how long to wait before `count` tokens will be available
    pub fn wait_time_for(&mut self, count: f64) -> Duration {
        self.refill();

        if self.tokens >= count {
            Duration::ZERO
        } else {
            let deficit = count - self.tokens;
            let secs = deficit / self.refill_rate;
            Duration::from_secs_f64(secs)
        }
    }

    /// Block until `count` tokens are available, then consume them
    pub fn consume_blocking(&mut self, count: f64) {
        loop {
            let wait = self.wait_time_for(count);
            if wait.is_zero() {
                if self.try_consume(count) {
                    return;
                }
            } else {
                thread::sleep(wait);
            }
        }
    }

    /// Current token count
    pub fn available_tokens(&mut self) -> f64 {
        self.refill();
        self.tokens
    }

    /// Returns the bucket's capacity
    pub fn capacity(&self) -> f64 {
        self.capacity
    }

    /// Returns the refill rate
    pub fn refill_rate(&self) -> f64 {
        self.refill_rate
    }
}

/// Thread-safe rate limiter wrapping a TokenBucket
#[derive(Clone, Debug)]
pub struct RateLimiter {
    bucket: Arc<Mutex<TokenBucket>>,
}

impl RateLimiter {
    /// Create a new RateLimiter
    ///
    /// # Arguments
    /// * `capacity` - Maximum burst size in tokens
    /// * `refill_rate` - Steady-state rate in tokens per second
    pub fn new(capacity: f64, refill_rate: f64) -> Self {
        RateLimiter {
            bucket: Arc::new(Mutex::new(TokenBucket::new(capacity, refill_rate))),
        }
    }

    /// Try to acquire 1 token without blocking
    pub fn try_acquire(&self) -> bool {
        self.bucket.lock().unwrap().try_acquire()
    }

    /// Try to acquire `count` tokens without blocking
    pub fn try_acquire_n(&self, count: f64) -> bool {
        self.bucket.lock().unwrap().try_consume(count)
    }

    /// Block until 1 token is available
    pub fn acquire(&self) {
        self.bucket.lock().unwrap().consume_blocking(1.0);
    }

    /// Block until `count` tokens are available
    pub fn acquire_n(&self, count: f64) {
        self.bucket.lock().unwrap().consume_blocking(count);
    }

    /// How long until `count` tokens are available
    pub fn wait_time_for(&self, count: f64) -> Duration {
        self.bucket.lock().unwrap().wait_time_for(count)
    }

    /// Current available tokens
    pub fn available_tokens(&self) -> f64 {
        self.bucket.lock().unwrap().available_tokens()
    }
}

/// Per-key rate limiter (e.g., per IP address, per user ID)
pub struct KeyedRateLimiter<K> {
    limiters: Mutex<HashMap<K, RateLimiter>>,
    capacity: f64,
    refill_rate: f64,
}

impl<K: std::hash::Hash + Eq + Clone> KeyedRateLimiter<K> {
    /// Create a new KeyedRateLimiter where each key gets its own bucket
    pub fn new(capacity: f64, refill_rate: f64) -> Self {
        KeyedRateLimiter {
            limiters: Mutex::new(HashMap::new()),
            capacity,
            refill_rate,
        }
    }

    /// Try to acquire a token for the given key
    pub fn try_acquire(&self, key: &K) -> bool {
        let mut map = self.limiters.lock().unwrap();
        let limiter = map
            .entry(key.clone())
            .or_insert_with(|| RateLimiter::new(self.capacity, self.refill_rate));
        limiter.try_acquire()
    }

    /// Block until a token is available for the given key
    pub fn acquire(&self, key: &K) {
        // Get or create the limiter for this key
        let limiter = {
            let mut map = self.limiters.lock().unwrap();
            map.entry(key.clone())
                .or_insert_with(|| RateLimiter::new(self.capacity, self.refill_rate))
                .clone()
        };
        limiter.acquire();
    }

    /// Remove stale entries (keys with full buckets, i.e., idle clients)
    pub fn cleanup(&self) {
        let mut map = self.limiters.lock().unwrap();
        map.retain(|_, limiter| {
            let tokens = limiter.available_tokens();
            let capacity = limiter.bucket.lock().unwrap().capacity();
            // Keep only active limiters (not fully refilled)
            tokens < capacity
        });
    }

    /// Number of tracked keys
    pub fn key_count(&self) -> usize {
        self.limiters.lock().unwrap().len()
    }
}

fn main() {
    println!("=== Token Bucket Rate Limiter Demo ===\n");

    // ── Demo 1: Basic usage ───────────────────────────────────────────────────
    println!("── Demo 1: Basic Token Bucket ──");
    {
        // 5 token capacity, refill 2 tokens/sec
        let mut bucket = TokenBucket::new(5.0, 2.0);

        println!("Initial tokens: {:.1}", bucket.available_tokens());

        for i in 1..=7 {
            let ok = bucket.try_acquire();
            println!(
                "  Request {}: {} (tokens remaining: {:.2})",
                i,
                if ok { "ALLOWED ✓" } else { "DENIED  ✗" },
                bucket.available_tokens()
            );
        }
        println!();
    }

    // ── Demo 2: Thread-safe RateLimiter ──────────────────────────────────────
    println!("── Demo 2: Thread-Safe RateLimiter (10 req/s, burst 5) ──");
    {
        let limiter = RateLimiter::new(5.0, 10.0);
        let mut allowed = 0;
        let mut denied = 0;

        // Simulate 10 instant requests (burst)
        for _ in 0..10 {
            if limiter.try_acquire() {
                allowed += 1;
            } else {
                denied += 1;
            }
        }
        println!("  Burst of 10: {allowed} allowed, {denied} denied");

        // Wait 0.5s → should get ~5 new tokens
        thread::sleep(Duration::from_millis(500));
        let tokens_after_wait = limiter.available_tokens();
        println!("  After 500ms wait: {tokens_after_wait:.2} tokens available");
        println!();
    }

    // ── Demo 3: Multi-token consumption ──────────────────────────────────────
    println!("── Demo 3: Multi-Token Consumption ──");
    {
        let limiter = RateLimiter::new(10.0, 5.0);
        println!("  Starting tokens: {:.1}", limiter.available_tokens());

        let cases = [(3.0, "small"), (4.0, "medium"), (5.0, "large")];
        for (cost, label) in &cases {
            let ok = limiter.try_acquire_n(*cost);
            println!(
                "  {label} request ({cost} tokens): {} (remaining: {:.2})",
                if ok { "ALLOWED ✓" } else { "DENIED  ✗" },
                limiter.available_tokens()
            );
        }
        println!();
    }

    // ── Demo 4: Concurrent access ─────────────────────────────────────────────
    println!("── Demo 4: Concurrent Multi-Threaded Access ──");
    {
        let limiter = Arc::new(RateLimiter::new(20.0, 100.0));
        let allowed_count = Arc::new(std::sync::atomic::AtomicU32::new(0));
        let denied_count = Arc::new(std::sync::atomic::AtomicU32::new(0));

        let mut handles = vec![];

        for thread_id in 0..5 {
            let limiter = limiter.clone();
            let allowed = allowed_count.clone();
            let denied = denied_count.clone();

            handles.push(thread::spawn(move || {
                for req in 0..10 {
                    if limiter.try_acquire() {
                        allowed.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                    } else {
                        denied.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                    }
                    // Tiny sleep to interleave threads
                    thread::sleep(Duration::from_micros(100));
                    let _ = (thread_id, req); // suppress warnings
                }
            }));
        }

        for h in handles {
            h.join().unwrap();
        }

        println!(
            "  5 threads × 10 requests = {} total",
            allowed_count.load(std::sync::atomic::Ordering::Relaxed)
                + denied_count.load(std::sync::atomic::Ordering::Relaxed)
        );
        println!(
            "  Allowed: {}, Denied: {}",
            allowed_count.load(std::sync::atomic::Ordering::Relaxed),
            denied_count.load(std::sync::atomic::Ordering::Relaxed)
        );
        println!();
    }

    // ── Demo 5: Per-key (per-IP) rate limiting ────────────────────────────────
    println!("── Demo 5: Per-Key Rate Limiter (per IP) ──");
    {
        // Each IP: 3 burst, 1 req/sec
        let limiter: KeyedRateLimiter<&str> = KeyedRateLimiter::new(3.0, 1.0);

        let requests = [
            "192.168.1.1",
            "192.168.1.1",
            "192.168.1.1",
            "192.168.1.1", // 4th request from same IP → denied
            "10.0.0.2",    // different IP → allowed
            "10.0.0.2",
            "10.0.0.2",
            "10.0.0.2", // 4th from this IP → denied
        ];

        for ip in &requests {
            let ok = limiter.try_acquire(ip);
            println!(
                "  {ip}: {}",
                if ok { "ALLOWED ✓" } else { "DENIED  ✗" }
            );
        }

        println!("  Tracked IPs: {}", limiter.key_count());
        println!();
    }

    // ── Demo 6: Blocking acquire with wait time ───────────────────────────────
    println!("── Demo 6: Wait Time Estimation ──");
    {
        let limiter = RateLimiter::new(3.0, 2.0);

        // Drain the bucket
        for _ in 0..3 {
            limiter.try_acquire();
        }

        let wait = limiter.wait_time_for(1.0);
        println!("  Bucket drained. Wait for 1 token: {wait:?}");

        let wait3 = limiter.wait_time_for(3.0);
        println!("  Wait for 3 tokens: {wait3:?}");
        println!();
    }

    println!("=== Demo Complete ===");
}

