let limiter = RateLimiter::new(200.0, 100.0);

if limiter.try_acquire() {
    // handle request
} else {
    // return 429 Too Many Requests
}

// Per-user limiter
let limiter: KeyedRateLimiter<String> = KeyedRateLimiter::new(10.0, 5.0);
if limiter.try_acquire(&user_id) {
    // handle request
}
```

# Bounded Blocking Queue in Rust

A thread-safe bounded blocking queue where:
- **`push`** blocks when the queue is full
- **`pop`** blocks when the queue is empty

## Implementation

```rust
use std::collections::VecDeque;
use std::sync::{Arc, Condvar, Mutex};

/// A thread-safe bounded blocking queue.
pub struct BoundedBlockingQueue<T> {
    inner: Arc<Inner<T>>,
}

struct Inner<T> {
    data: Mutex<VecDeque<T>>,
    not_full: Condvar,  // signaled when an item is removed (space available)
    not_empty: Condvar, // signaled when an item is added (data available)
    capacity: usize,
}

impl<T> BoundedBlockingQueue<T> {
    /// Creates a new queue with the given capacity.
    ///
    /// # Panics
    /// Panics if `capacity` is 0.
    pub fn new(capacity: usize) -> Self {
        assert!(capacity > 0, "capacity must be greater than 0");
        Self {
            inner: Arc::new(Inner {
                data: Mutex::new(VecDeque::with_capacity(capacity)),
                not_full: Condvar::new(),
                not_empty: Condvar::new(),
                capacity,
            }),
        }
    }

    /// Pushes an item onto the queue.
    ///
    /// Blocks the calling thread until space is available.
    pub fn push(&self, item: T) {
        let mut guard = self.inner.data.lock().unwrap();

        // Wait while the queue is full.
        guard = self
            .inner
            .not_full
            .wait_while(guard, |q| q.len() == self.inner.capacity)
            .unwrap();

        guard.push_back(item);

        // Notify one waiting consumer that data is available.
        self.inner.not_empty.notify_one();
    }

    /// Pops an item from the queue.
    ///
    /// Blocks the calling thread until an item is available.
    pub fn pop(&self) -> T {
        let mut guard = self.inner.data.lock().unwrap();

        // Wait while the queue is empty.
        guard = self
            .inner
            .not_empty
            .wait_while(guard, |q| q.is_empty())
            .unwrap();

        // SAFETY: wait_while guarantees the queue is non-empty here.
        let item = guard.pop_front().unwrap();

        // Notify one waiting producer that space is available.
        self.inner.not_full.notify_one();

        item
    }

    /// Tries to push an item without blocking.
    ///
    /// Returns `Err(item)` if the queue is full.
    pub fn try_push(&self, item: T) -> Result<(), T> {
        let mut guard = self.inner.data.lock().unwrap();
        if guard.len() == self.inner.capacity {
            return Err(item);
        }
        guard.push_back(item);
        self.inner.not_empty.notify_one();
        Ok(())
    }

    /// Tries to pop an item without blocking.
    ///
    /// Returns `None` if the queue is empty.
    pub fn try_pop(&self) -> Option<T> {
        let mut guard = self.inner.data.lock().unwrap();
        let item = guard.pop_front()?;
        self.inner.not_full.notify_one();
        Some(item)
    }

    /// Returns the current number of items in the queue.
    pub fn len(&self) -> usize {
        self.inner.data.lock().unwrap().len()
    }

    /// Returns `true` if the queue is empty.
    pub fn is_empty(&self) -> bool {
        self.inner.data.lock().unwrap().is_empty()
    }

    /// Returns the maximum capacity of the queue.
    pub fn capacity(&self) -> usize {
        self.inner.capacity
    }
}

/// Allow cheap cloning so the queue can be shared across threads.
impl<T> Clone for BoundedBlockingQueue<T> {
    fn clone(&self) -> Self {
        Self {
            inner: Arc::clone(&self.inner),
        }
    }
}

// SAFETY: The Mutex ensures exclusive access; the Arc handles shared ownership.
unsafe impl<T: Send> Send for BoundedBlockingQueue<T> {}
unsafe impl<T: Send> Sync for BoundedBlockingQueue<T> {}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;
    use std::thread;
    use std::time::{Duration, Instant};

    #[test]
    #[should_panic(expected = "capacity must be greater than 0")]
    fn zero_capacity_panics() {
        BoundedBlockingQueue::<i32>::new(0);
    }

    #[test]
    fn basic_push_pop() {
        let q = BoundedBlockingQueue::new(3);
        q.push(1);
        q.push(2);
        q.push(3);
        assert_eq!(q.len(), 3);
        assert_eq!(q.pop(), 1);
        assert_eq!(q.pop(), 2);
        assert_eq!(q.pop(), 3);
        assert!(q.is_empty());
    }

    #[test]
    fn fifo_ordering() {
        let q = BoundedBlockingQueue::new(5);
        for i in 0..5 {
            q.push(i);
        }
        for i in 0..5 {
            assert_eq!(q.pop(), i);
        }
    }

    #[test]
    fn try_push_full() {
        let q = BoundedBlockingQueue::new(2);
        assert!(q.try_push(1).is_ok());
        assert!(q.try_push(2).is_ok());
        assert_eq!(q.try_push(3), Err(3)); // full
    }

    #[test]
    fn try_pop_empty() {
        let q = BoundedBlockingQueue::<i32>::new(2);
        assert_eq!(q.try_pop(), None);
    }

    #[test]
    fn producer_blocks_when_full() {
        let q = BoundedBlockingQueue::new(1);
        q.push(42); // fill the queue

        let q2 = q.clone();
        let handle = thread::spawn(move || {
            let start = Instant::now();
            q2.push(99); // should block until consumer pops
            start.elapsed()
        });

        // Give the producer time to block.
        thread::sleep(Duration::from_millis(100));

        // Unblock the producer.
        assert_eq!(q.pop(), 42);

        let blocked_for = handle.join().unwrap();
        assert!(
            blocked_for >= Duration::from_millis(80),
            "producer should have blocked for ~100ms, got {blocked_for:?}"
        );
        assert_eq!(q.pop(), 99);
    }

    #[test]
    fn consumer_blocks_when_empty() {
        let q: BoundedBlockingQueue<i32> = BoundedBlockingQueue::new(4);

        let q2 = q.clone();
        let handle = thread::spawn(move || {
            let start = Instant::now();
            let val = q2.pop(); // should block until producer pushes
            (val, start.elapsed())
        });

        // Give the consumer time to block.
        thread::sleep(Duration::from_millis(100));
        q.push(7);

        let (val, blocked_for) = handle.join().unwrap();
        assert_eq!(val, 7);
        assert!(
            blocked_for >= Duration::from_millis(80),
            "consumer should have blocked for ~100ms, got {blocked_for:?}"
        );
    }

    #[test]
    fn multiple_producers_consumers() {
        const CAPACITY: usize = 4;
        const MESSAGES: usize = 100;
        const PRODUCERS: usize = 4;
        const CONSUMERS: usize = 4;

        let q = BoundedBlockingQueue::new(CAPACITY);
        let mut handles = vec![];

        // Spawn producers.
        for p in 0..PRODUCERS {
            let q = q.clone();
            handles.push(thread::spawn(move || {
                for i in 0..MESSAGES {
                    q.push(p * MESSAGES + i);
                }
            }));
        }

        // Collect results from consumers.
        let results = Arc::new(Mutex::new(Vec::new()));
        for _ in 0..CONSUMERS {
            let q = q.clone();
            let results = Arc::clone(&results);
            handles.push(thread::spawn(move || {
                // Each consumer picks up its share of messages.
                let share = (PRODUCERS * MESSAGES) / CONSUMERS;
                for _ in 0..share {
                    let val = q.pop();
                    results.lock().unwrap().push(val);
                }
            }));
        }

        for h in handles {
            h.join().unwrap();
        }

        let mut collected = results.lock().unwrap().clone();
        collected.sort_unstable();

        // Every value 0..PRODUCERS*MESSAGES should appear exactly once.
        let expected: Vec<usize> = (0..PRODUCERS * MESSAGES).collect();
        assert_eq!(collected, expected);
    }
}

fn main() {
    use std::thread;

    let queue = BoundedBlockingQueue::new(3);

    // Producer thread
    let q_producer = queue.clone();
    let producer = thread::spawn(move || {
        for i in 0..6 {
            println!("Producing: {i}");
            q_producer.push(i);
        }
    });

    // Consumer thread
    let q_consumer = queue.clone();
    let consumer = thread::spawn(move || {
        for _ in 0..6 {
            let val = q_consumer.pop();
            println!("Consumed:  {val}");
        }
    });

    producer.join().unwrap();
    consumer.join().unwrap();
}
```

## How It Works

### Core Data Structures

| Component | Role |
|-----------|------|
| `Mutex<VecDeque<T>>` | Guards the queue data; provides mutual exclusion |
| `not_full: Condvar` | Producers wait here when the queue is at capacity |
| `not_empty: Condvar` | Consumers wait here when the queue is empty |
| `Arc<Inner<T>>` | Allows cheap, reference-counted cloning across threads |

### Operation Flow

```
push()                          pop()
──────                          ─────
lock mutex                      lock mutex
while len == capacity:          while is_empty():
  wait on not_full                wait on not_empty
push_back(item)                 pop_front()
notify_one(not_empty)           notify_one(not_full)
unlock mutex                    unlock mutex
```

### Key Design Decisions

1. **`wait_while`** – Uses `Condvar::wait_while` which re-checks the predicate after every wakeup, correctly handling **spurious wakeups**.
2. **Two condition variables** – Separating `not_full` and `not_empty` avoids unnecessary wakeups (vs. a single `Condvar` that would wake both producers and consumers).
3. **`notify_one` vs `notify_all`** – `notify_one` is sufficient because adding one item creates space/data for exactly one waiter.
4. **`Arc` + `Clone`** – The queue handle is cheaply clonable, making it ergonomic to share across threads without `Arc<BoundedBlockingQueue<T>>` at the call site.

# Arithmetic Expression Evaluator in Rust

This implementation supports:
- Basic operations: `+`, `-`, `*`, `/`, `%`
- Exponentiation: `^`
- Unary minus/plus
- Parentheses
- Integer and floating-point numbers

The evaluator uses a **recursive descent parser** with proper operator precedence.

---

## Complete Implementation

```rust
use std::fmt;
use std::iter::Peekable;
use std::str::Chars;

// ── Tokens ────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq)]
enum Token {
    Number(f64),
    Plus,
    Minus,
    Star,
    Slash,
    Percent,
    Caret,
    LParen,
    RParen,
    Eof,
}

// ── Lexer errors / Eval errors ────────────────────────────────────────────────

#[derive(Debug, PartialEq)]
enum CalcError {
    UnexpectedChar(char),
    UnexpectedToken(Token),
    UnexpectedEof,
    DivisionByZero,
    MismatchedParentheses,
}

impl fmt::Display for CalcError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            CalcError::UnexpectedChar(c)  => write!(f, "Unexpected character: '{c}'"),
            CalcError::UnexpectedToken(t) => write!(f, "Unexpected token: {t:?}"),
            CalcError::UnexpectedEof      => write!(f, "Unexpected end of input"),
            CalcError::DivisionByZero     => write!(f, "Division by zero"),
            CalcError::MismatchedParentheses => write!(f, "Mismatched parentheses"),
        }
    }
}

// ── Lexer ─────────────────────────────────────────────────────────────────────

struct Lexer<'a> {
    chars: Peekable<Chars<'a>>,
}

impl<'a> Lexer<'a> {
    fn new(input: &'a str) -> Self {
        Lexer { chars: input.chars().peekable() }
    }

    fn skip_whitespace(&mut self) {
        while self.chars.peek().map_or(false, |c| c.is_whitespace()) {
            self.chars.next();
        }
    }

    fn read_number(&mut self, first: char) -> Result<Token, CalcError> {
        let mut s = String::from(first);

        while let Some(&c) = self.chars.peek() {
            if c.is_ascii_digit() || c == '.' {
                s.push(c);
                self.chars.next();
            } else {
                break;
            }
        }

        // Optional exponent: e / E
        if let Some(&c) = self.chars.peek() {
            if c == 'e' || c == 'E' {
                s.push(c);
                self.chars.next();

                if let Some(&sign) = self.chars.peek() {
                    if sign == '+' || sign == '-' {
                        s.push(sign);
                        self.chars.next();
                    }
                }

                while let Some(&d) = self.chars.peek() {
                    if d.is_ascii_digit() {
                        s.push(d);
                        self.chars.next();
                    } else {
                        break;
                    }
                }
            }
        }

        s.parse::<f64>()
            .map(Token::Number)
            .map_err(|_| CalcError::UnexpectedChar(s.chars().next().unwrap()))
    }

    /// Tokenise the entire input up-front.
    fn tokenize(&mut self) -> Result<Vec<Token>, CalcError> {
        let mut tokens = Vec::new();

        loop {
            self.skip_whitespace();

            match self.chars.peek().copied() {
                None => {
                    tokens.push(Token::Eof);
                    break;
                }
                Some(c) => {
                    self.chars.next();
                    let tok = match c {
                        '+' => Token::Plus,
                        '-' => Token::Minus,
                        '*' => Token::Star,
                        '/' => Token::Slash,
                        '%' => Token::Percent,
                        '^' => Token::Caret,
                        '(' => Token::LParen,
                        ')' => Token::RParen,
                        '0'..='9' | '.' => self.read_number(c)?,
                        other => return Err(CalcError::UnexpectedChar(other)),
                    };
                    tokens.push(tok);
                }
            }
        }

        Ok(tokens)
    }
}

// ── Parser / Evaluator ────────────────────────────────────────────────────────
//
// Grammar (highest precedence at the bottom):
//
//   expr        → addition
//   addition    → multiplication  ( ('+' | '-') multiplication )*
//   multiplication → exponent     ( ('*' | '/' | '%') exponent )*
//   exponent    → unary           ( '^' exponent )*          ← right-associative
//   unary       → ('-' | '+') unary  |  primary
//   primary     → NUMBER  |  '(' expr ')'
//

struct Parser {
    tokens: Vec<Token>,
    pos: usize,
}

impl Parser {
    fn new(tokens: Vec<Token>) -> Self {
        Parser { tokens, pos: 0 }
    }

    // ── Token navigation ──────────────────────────────────────────────────────

    fn peek(&self) -> &Token {
        &self.tokens[self.pos]
    }

    fn advance(&mut self) -> &Token {
        let tok = &self.tokens[self.pos];
        if self.pos + 1 < self.tokens.len() {
            self.pos += 1;
        }
        tok
    }

    fn expect(&mut self, expected: &Token) -> Result<(), CalcError> {
        let tok = self.advance().clone();
        if &tok == expected {
            Ok(())
        } else {
            Err(CalcError::UnexpectedToken(tok))
        }
    }

    // ── Grammar rules ─────────────────────────────────────────────────────────

    fn parse_expr(&mut self) -> Result<f64, CalcError> {
        self.parse_addition()
    }

    fn parse_addition(&mut self) -> Result<f64, CalcError> {
        let mut left = self.parse_multiplication()?;

        loop {
            match self.peek() {
                Token::Plus => {
                    self.advance();
                    left += self.parse_multiplication()?;
                }
                Token::Minus => {
                    self.advance();
                    left -= self.parse_multiplication()?;
                }
                _ => break,
            }
        }

        Ok(left)
    }

    fn parse_multiplication(&mut self) -> Result<f64, CalcError> {
        let mut left = self.parse_exponent()?;

        loop {
            match self.peek() {
                Token::Star => {
                    self.advance();
                    left *= self.parse_exponent()?;
                }
                Token::Slash => {
                    self.advance();
                    let right = self.parse_exponent()?;
                    if right == 0.0 {
                        return Err(CalcError::DivisionByZero);
                    }
                    left /= right;
                }
                Token::Percent => {
                    self.advance();
                    let right = self.parse_exponent()?;
                    if right == 0.0 {
                        return Err(CalcError::DivisionByZero);
                    }
                    left %= right;
                }
                _ => break,
            }
        }

        Ok(left)
    }

    /// Right-associative: `2 ^ 3 ^ 2` = `2 ^ (3 ^ 2)` = 512
    fn parse_exponent(&mut self) -> Result<f64, CalcError> {
        let base = self.parse_unary()?;

        if let Token::Caret = self.peek() {
            self.advance();
            let exp = self.parse_exponent()?; // recurse for right-associativity
            Ok(base.powf(exp))
        } else {
            Ok(base)
        }
    }

    fn parse_unary(&mut self) -> Result<f64, CalcError> {
        match self.peek().clone() {
            Token::Minus => {
                self.advance();
                Ok(-self.parse_unary()?)
            }
            Token::Plus => {
                self.advance();
                self.parse_unary()
            }
            _ => self.parse_primary(),
        }
    }

    fn parse_primary(&mut self) -> Result<f64, CalcError> {
        match self.advance().clone() {
            Token::Number(n) => Ok(n),
            Token::LParen => {
                let val = self.parse_expr()?;
                match self.advance().clone() {
                    Token::RParen => Ok(val),
                    Token::Eof    => Err(CalcError::MismatchedParentheses),
                    tok           => Err(CalcError::UnexpectedToken(tok)),
                }
            }
            Token::Eof => Err(CalcError::UnexpectedEof),
            tok        => Err(CalcError::UnexpectedToken(tok)),
        }
    }
}

// ── Public API ────────────────────────────────────────────────────────────────

pub fn evaluate(input: &str) -> Result<f64, CalcError> {
    let tokens = Lexer::new(input).tokenize()?;
    let mut parser = Parser::new(tokens);
    let result = parser.parse_expr()?;

    // Make sure we consumed everything
    if parser.peek() != &Token::Eof {
        return Err(CalcError::UnexpectedToken(parser.peek().clone()));
    }

    Ok(result)
}

// ── Tests ─────────────────────────────────────────────────────────────────────

