# Basic Regex Matcher in Rust

I'll implement a regex engine supporting these patterns:
- `.` — matches any single character
- `*` — matches zero or more of the preceding element
- `+` — matches one or more of the preceding element
- `?` — matches zero or one of the preceding element
- `^` — anchors match to start of string
- `$` — anchors match to end of string
- `[abc]` — character classes (with optional `^` negation and `-` ranges)
- `\d`, `\w`, `\s` — escape sequences
- `(...)` — grouping (for quantifier scope)
- `|` — alternation

## Implementation

```rust
use std::fmt;

// ── Token / AST ──────────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq)]
enum Atom {
    Literal(char),
    AnyChar,           // .
    Digit(bool),       // \d (true) / \D (false)
    Word(bool),        // \w / \W
    Space(bool),       // \s / \S
    Class(CharClass),  // [...]
    Group(Vec<Node>),  // (...)
    Alternation(Vec<Vec<Node>>), // a|b|c
}

#[derive(Debug, Clone, PartialEq)]
struct CharClass {
    negated: bool,
    items: Vec<ClassItem>,
}

#[derive(Debug, Clone, PartialEq)]
enum ClassItem {
    Single(char),
    Range(char, char),
}

#[derive(Debug, Clone, PartialEq)]
enum Quantifier {
    One,
    ZeroOrMore, // *
    OneOrMore,  // +
    ZeroOrOne,  // ?
}

#[derive(Debug, Clone, PartialEq)]
struct Node {
    atom: Atom,
    quantifier: Quantifier,
    greedy: bool, // true = greedy, false = lazy (quantifier followed by ?)
}

#[derive(Debug, Clone, PartialEq)]
struct Pattern {
    nodes: Vec<Node>,
    anchored_start: bool,
    anchored_end: bool,
}

// ── Error ─────────────────────────────────────────────────────────────────────

#[derive(Debug, PartialEq)]
pub struct RegexError(String);

impl fmt::Display for RegexError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "RegexError: {}", self.0)
    }
}

// ── Parser ───────────────────────────────────────────────────────────────────

struct Parser {
    chars: Vec<char>,
    pos: usize,
}

impl Parser {
    fn new(pattern: &str) -> Self {
        Parser {
            chars: pattern.chars().collect(),
            pos: 0,
        }
    }

    fn peek(&self) -> Option<char> {
        self.chars.get(self.pos).copied()
    }

    fn advance(&mut self) -> Option<char> {
        let ch = self.chars.get(self.pos).copied();
        self.pos += 1;
        ch
    }

    fn parse(&mut self) -> Result<Pattern, RegexError> {
        // Handle leading anchor
        let anchored_start = if self.peek() == Some('^') {
            self.advance();
            true
        } else {
            false
        };

        // Parse alternation at the top level
        let branches = self.parse_alternation()?;

        // Handle trailing anchor (outside groups only)
        let anchored_end = if self.peek() == Some('$') {
            self.advance();
            true
        } else {
            false
        };

        if self.pos < self.chars.len() {
            return Err(RegexError(format!(
                "Unexpected character '{}' at position {}",
                self.chars[self.pos], self.pos
            )));
        }

        let nodes = if branches.len() == 1 {
            branches.into_iter().next().unwrap()
        } else {
            vec![Node {
                atom: Atom::Alternation(branches),
                quantifier: Quantifier::One,
                greedy: true,
            }]
        };

        Ok(Pattern {
            nodes,
            anchored_start,
            anchored_end,
        })
    }

    /// Parse a sequence of alternatives separated by `|`.
    fn parse_alternation(&mut self) -> Result<Vec<Vec<Node>>, RegexError> {
        let mut branches = vec![self.parse_sequence()?];
        while self.peek() == Some('|') {
            self.advance(); // consume '|'
            branches.push(self.parse_sequence()?);
        }
        Ok(branches)
    }

    /// Parse nodes until we hit `|`, `)`, `$`, or end-of-input.
    fn parse_sequence(&mut self) -> Result<Vec<Node>, RegexError> {
        let mut nodes = Vec::new();
        loop {
            match self.peek() {
                None | Some(')') | Some('|') | Some('$') => break,
                _ => {
                    if let Some(node) = self.parse_node()? {
                        nodes.push(node);
                    }
                }
            }
        }
        Ok(nodes)
    }

    fn parse_node(&mut self) -> Result<Option<Node>, RegexError> {
        let atom = match self.peek() {
            Some('(') => {
                self.advance(); // consume '('
                let branches = self.parse_alternation()?;
                if self.advance() != Some(')') {
                    return Err(RegexError("Unclosed '('".into()));
                }
                if branches.len() == 1 {
                    Atom::Group(branches.into_iter().next().unwrap())
                } else {
                    Atom::Alternation(branches)
                }
            }
            Some('[') => Atom::Class(self.parse_class()?),
            Some('\\') => {
                self.advance(); // consume '\'
                match self.advance() {
                    Some('d') => Atom::Digit(true),
                    Some('D') => Atom::Digit(false),
                    Some('w') => Atom::Word(true),
                    Some('W') => Atom::Word(false),
                    Some('s') => Atom::Space(true),
                    Some('S') => Atom::Space(false),
                    Some(c) => Atom::Literal(c), // \. \* etc.
                    None => return Err(RegexError("Trailing backslash".into())),
                }
            }
            Some('.') => {
                self.advance();
                Atom::AnyChar
            }
            Some(c) if "^$*+?)|".contains(c) => {
                // These are not atoms in sequence context
                if c == '*' || c == '+' || c == '?' {
                    return Err(RegexError(format!("Unexpected quantifier '{c}'")));
                }
                return Ok(None);
            }
            Some(c) => {
                self.advance();
                Atom::Literal(c)
            }
            None => return Ok(None),
        };

        // Parse optional quantifier
        let quantifier = match self.peek() {
            Some('*') => {
                self.advance();
                Quantifier::ZeroOrMore
            }
            Some('+') => {
                self.advance();
                Quantifier::OneOrMore
            }
            Some('?') => {
                self.advance();
                Quantifier::ZeroOrOne
            }
            _ => Quantifier::One,
        };

        // Lazy modifier
        let greedy = if quantifier != Quantifier::One && self.peek() == Some('?') {
            self.advance();
            false
        } else {
            true
        };

        Ok(Some(Node {
            atom,
            quantifier,
            greedy,
        }))
    }

    fn parse_class(&mut self) -> Result<CharClass, RegexError> {
        self.advance(); // consume '['
        let negated = if self.peek() == Some('^') {
            self.advance();
            true
        } else {
            false
        };

        let mut items = Vec::new();
        // Allow ']' as first char inside class
        let mut first = true;
        loop {
            match self.peek() {
                None => return Err(RegexError("Unclosed '['".into())),
                Some(']') if !first => {
                    self.advance();
                    break;
                }
                Some('\\') => {
                    self.advance();
                    let c = self.advance().ok_or_else(|| RegexError("Trailing backslash".into()))?;
                    let unescaped = match c {
                        'n' => '\n',
                        't' => '\t',
                        'r' => '\r',
                        other => other,
                    };
                    items.push(ClassItem::Single(unescaped));
                }
                Some(c) => {
                    self.advance();
                    // Check for range  a-z
                    if self.peek() == Some('-') {
                        // Peek two ahead
                        if self.pos + 1 < self.chars.len() && self.chars[self.pos + 1] != ']' {
                            self.advance(); // consume '-'
                            let end = self.advance().ok_or_else(|| RegexError("Unexpected end in range".into()))?;
                            items.push(ClassItem::Range(c, end));
                        } else {
                            items.push(ClassItem::Single(c));
                        }
                    } else {
                        items.push(ClassItem::Single(c));
                    }
                }
            }
            first = false;
        }
        Ok(CharClass { negated, items })
    }
}

// ── Matcher ───────────────────────────────────────────────────────────────────

fn match_atom(atom: &Atom, ch: char) -> bool {
    match atom {
        Atom::Literal(c) => *c == ch,
        Atom::AnyChar => ch != '\n',
        Atom::Digit(pos) => ch.is_ascii_digit() == *pos,
        Atom::Word(pos) => (ch.is_alphanumeric() || ch == '_') == *pos,
        Atom::Space(pos) => ch.is_whitespace() == *pos,
        Atom::Class(cls) => {
            let matched = cls.items.iter().any(|item| match item {
                ClassItem::Single(c) => *c == ch,
                ClassItem::Range(lo, hi) => ch >= *lo && ch <= *hi,
            });
            matched != cls.negated
        }
        Atom::Group(_) | Atom::Alternation(_) => {
            // Handled separately via recursive match
            unreachable!("Group/Alternation cannot be matched as a single char atom")
        }
    }
}

fn is_single_char_atom(atom: &Atom) -> bool {
    !matches!(atom, Atom::Group(_) | Atom::Alternation(_))
}

/// Try to match `nodes[node_idx..]` against `text[pos..]`.
/// Returns `Some(end_pos)` on success.
fn match_nodes(nodes: &[Node], node_idx: usize, text: &[char], pos: usize) -> Option<usize> {
    if node_idx == nodes.len() {
        return Some(pos);
    }

    let node = &nodes[node_idx];

    match &node.quantifier {
        Quantifier::One => match_one(node, nodes, node_idx, text, pos),
        Quantifier::ZeroOrOne => {
            if node.greedy {
                // Try with one match first, then zero
                match_one(node, nodes, node_idx, text, pos)
                    .or_else(|| match_nodes(nodes, node_idx + 1, text, pos))
            } else {
                // Lazy: try zero first, then one
                match_nodes(nodes, node_idx + 1, text, pos)
                    .or_else(|| match_one(node, nodes, node_idx, text, pos))
            }
        }
        Quantifier::ZeroOrMore => {
            if node.greedy {
                match_repeat_greedy(node, nodes, node_idx, text, pos, 0)
            } else {
                match_repeat_lazy(node, nodes, node_idx, text, pos, 0)
            }
        }
        Quantifier::OneOrMore => {
            if node.greedy {
                match_repeat_greedy(node, nodes, node_idx, text, pos, 1)
            } else {
                match_repeat_lazy(node, nodes, node_idx, text, pos, 1)
            }
        }
    }
}

/// Match exactly one occurrence of node and then continue.
fn match_one(
    node: &Node,
    nodes: &[Node],
    node_idx: usize,
    text: &[char],
    pos: usize,
) -> Option<usize> {
    match &node.atom {
        Atom::Group(inner) => {
            // Match the inner nodes, then continue with the outer sequence
            match_nodes(inner, 0, text, pos).and_then(|end| {
                match_nodes(nodes, node_idx + 1, text, end)
            })
        }
        Atom::Alternation(branches) => {
            // Try each branch, then continue with the rest of the outer sequence
            for branch in branches {
                if let Some(end) = match_nodes(branch, 0, text, pos) {
                    if let Some(final_end) = match_nodes(nodes, node_idx + 1, text, end) {
                        return Some(final_end);
                    }
                }
            }
            None
        }
        atom => {
            if pos < text.len() && match_atom(atom, text[pos]) {
                match_nodes(nodes, node_idx + 1, text, pos + 1)
            } else {
                None
            }
        }
    }
}

/// Greedy: consume as many matches as possible, then backtrack.
fn match_repeat_greedy(
    node: &Node,
    nodes: &[Node],
    node_idx: usize,
    text: &[char],
    pos: usize,
    min: usize,
) -> Option<usize> {
    // Collect all possible end positions for this repeated atom
    let positions = collect_positions(node, text, pos);

    if positions.len() < min {
        return None;
    }

    // Try from longest to shortest
    for &end in positions.iter().skip(min).rev().chain(
        if min == 0 { std::slice::from_ref(&pos) } else { &[] }
    ) {
        if let Some(result) = match_nodes(nodes, node_idx + 1, text, end) {
            return Some(result);
        }
    }

    // If min == 0 and we haven't tried pos yet (it wasn't in the skip chain)
    // Actually handled above, but let's be safe:
    None
}

/// Collect all sequential match positions for a repeating node starting at `pos`.
fn collect_positions(node: &Node, text: &[char], start: usize) -> Vec<usize> {
    let mut positions = Vec::new();
    let mut cur = start;

    loop {
        let next = match_single_atom_at(&node.atom, text, cur);
        match next {
            Some(end) => {
                positions.push(end);
                if end == cur {
                    // Zero-width match — avoid infinite loop
                    break;
                }
                cur = end;
            }
            None => break,
        }
    }
    positions
}

/// Match a single atom at `pos`, returning the new position (or None).
fn match_single_atom_at(atom: &Atom, text: &[char], pos: usize) -> Option<usize> {
    match atom {
        Atom::Group(inner) => match_nodes(inner, 0, text, pos),
        Atom::Alternation(branches) => {
            for branch in branches {
                if let Some(end) = match_nodes(branch, 0, text, pos) {
                    return Some(end);
                }
            }
            None
        }
        a => {
            if pos < text.len() && match_atom(a, text[pos]) {
                Some(pos + 1)
            } else {
                None
            }
        }
    }
}

/// Lazy: try the minimum first, then expand.
fn match_repeat_lazy(
    node: &Node,
    nodes: &[Node],
    node_idx: usize,
    text: &[char],
    pos: usize,
    min: usize,
) -> Option<usize> {
    let positions = collect_positions(node, text, pos);

    // Build the list of end positions to try in lazy order
    let all: Vec<usize> = if min == 0 {
        std::iter::once(pos)
            .chain(positions.iter().copied())
            .collect()
    } else {
        positions.iter().copied().collect()
    };

    for &end in all.iter().skip(min.saturating_sub(if min == 0 { 0 } else { 0 })) {
        if let Some(result) = match_nodes(nodes, node_idx + 1, text, end) {
            return Some(result);
        }
    }
    None
}

// ── Public API ────────────────────────────────────────────────────────────────

pub struct Regex {
    pattern: Pattern,
    source: String,
}

impl Regex {
    pub fn new(pattern: &str) -> Result<Self, RegexError> {
        let mut parser = Parser::new(pattern);
        let parsed = parser.parse()?;
        Ok(Regex {
            pattern: parsed,
            source: pattern.to_string(),
        })
    }

    /// Returns true if the pattern matches anywhere in `text`.
    pub fn is_match(&self, text: &str) -> bool {
        self.find(text).is_some()
    }

    /// Returns the byte range of the first match, if any.
    pub fn find(&self, text: &str) -> Option<(usize, usize)> {
        let chars: Vec<char> = text.chars().collect();
        let n = chars.len();

        // Build char-to-byte index
        let byte_offsets: Vec<usize> = text
            .char_indices()
            .map(|(i, _)| i)
            .chain(std::iter::once(text.len()))
            .collect();

        let start_range = if self.pattern.anchored_start { 0..1 } else { 0..n + 1 };

        for start in start_range {
            if let Some(end) = match_nodes(&self.pattern.nodes, 0, &chars, start) {
                // If anchored at end, end must be n
                if self.pattern.anchored_end && end != n {
                    continue;
                }
                let byte_start = byte_offsets[start];
                let byte_end = byte_offsets[end];
                return Some((byte_start, byte_end));
            }
        }
        None
    }

    /// Returns all non-overlapping matches as `&str` slices.
    pub fn find_all<'t>(&self, text: &'t str) -> Vec<&'t str> {
        let chars: Vec<char> = text.chars().collect();
        let n = chars.len();
        let byte_offsets: Vec<usize> = text
            .char_indices()
            .map(|(i, _)| i)
            .chain(std::iter::once(text.len()))
            .collect();

        let mut results = Vec::new();
        let mut pos = 0;

        while pos <= n {
            if let Some(end) = match_nodes(&self.pattern.nodes, 0, &chars, pos) {
                if self.pattern.anchored_end && end != n {
                    break;
                }
                results.push(&text[byte_offsets[pos]..byte_offsets[end]]);
                if end == pos {
                    pos += 1; // avoid infinite loop on zero-width match
                } else {
                    pos = end;
                }
            } else {
                if self.pattern.anchored_start {
                    break;
                }
                pos += 1;
            }
        }
        results
    }

    pub fn source(&self) -> &str {
        &self.source
    }
}

impl fmt::Debug for Regex {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Regex({})", self.source)
    }
}

