    let examples = vec![
        ("\\d+",      "Phone: 555-1234",     true),
        ("^hello$",   "hello",               true),
        ("^hello$",   "hello world",         false),
        ("colou?r",   "color",               true),
        ("colou?r",   "colour",              true),
        ("(ab)+",     "ababab",              true),
        ("cat|dog",   "I have a dog",        true),
        ("cat|dog",   "I have a fish",       false),
        ("[A-Z]\\w+", "Hello World",         true),
        ("a.*?b",     "aXbXb",              true),
    ];

    println!("{:<25} {:<20} {:>8}   {}", "Pattern", "Text", "Expected", "Got");
    println!("{}", "-".repeat(75));

    for (pat, text, expected) in &examples {
        let re = Regex::new(pat).expect("valid pattern");
        let got = re.is_match(text);
        let status = if got == *expected { "✓" } else { "✗ FAIL" };
        println!(
            "{:<25} {:<20} {:>8}   {} {}",
            pat, text, expected, got, status
        );
    }

    println!("\n--- find_all examples ---");
    let re = Regex::new("\\d+").unwrap();
    let text = "order 1: 42 items, order 2: 7 items";
    println!("find_all('\\d+', {:?}) = {:?}", text, re.find_all(text));

    let re = Regex::new("\\w+").unwrap();
    let text = "the quick brown fox";
    println!("find_all('\\w+', {:?}) = {:?}", text, re.find_all(text));
}
