    fn test_single_insert_and_get() {
        let mut tree = BTree::new(2);
        tree.insert(42, "hello");
        assert_eq!(tree.get(&42), Some(&"hello"));
        assert_eq!(tree.len(), 1);
    }

    #[test]
    fn test_insert_updates_existing() {
        let mut tree = BTree::new(2);
        let old = tree.insert(1, "first");
        assert_eq!(old, None);
        let old = tree.insert(1, "second");
        assert_eq!(old, Some("first"));
        assert_eq!(tree.get(&1), Some(&"second"));
        assert_eq!(tree.len(), 1);
    }

