    fn test_sorted_order() {
        let keys = [5, 3, 7, 1, 4, 6, 8, 2];
        let mut tree = BTree::new(2);
        for k in &keys {
            tree.insert(*k, k * 10);
        }
        let sorted: Vec<i32> = tree.iter().map(|(k, _)| *k).collect();
        assert_eq!(sorted, vec![1, 2, 3, 4, 5, 6, 7, 8]);
        tree.validate().unwrap();
    }

