    fn test_many_insertions_t2() {
        let mut tree = BTree::new(2);
        for i in 0..100 {
            tree.insert(i, i * 2);
        }
        assert_eq!(tree.len(), 100);
        for i in 0..100 {
            assert_eq!(tree.get(&i), Some(&(i * 2)));
        }
        let sorted: Vec<i32> = tree.iter().map(|(k, _)| *k).collect();
        let expected: Vec<i32> = (0..100).collect();
        assert_eq!(sorted, expected);
        tree.validate().unwrap();
    }

    #[test]
    fn test_many_insertions_t5() {
        let mut tree = BTree::new(5);
        for i in (0..200).rev() {
            tree.insert(i, i);
        }
        assert_eq!(tree.len(), 200);
        for i in 0..200 {
            assert_eq!(tree.get(&i), Some(&i));
        }
        tree.validate().unwrap();
    }

    #[test]
    fn test_delete_from_leaf() {
        let mut tree = make_tree(2, &[(1, "a"), (2, "b"), (3, "c")]);
        assert_eq!(tree.remove(&2), Some("b".to_string()));
        assert_eq!(tree.get(&2), None);
        assert_eq!(tree.len(), 2);
        tree.validate().unwrap();
    }

    #[test]
    fn test_delete_nonexistent() {
        let mut tree = make_tree(2, &[(1, "a"), (2, "b")]);
        assert_eq!(tree.remove(&99), None);
        assert_eq!(tree.len(), 2);
    }

