    fn test_delete_all() {
        let mut tree = BTree::new(2);
        let n = 50;
        for i in 0..n {
            tree.insert(i, i);
        }
        for i in 0..n {
            assert!(tree.remove(&i).is_some(), "Failed to remove {}", i);
            assert_eq!(tree.get(&i), None);
        }
        assert_eq!(tree.len(), 0);
        assert!(tree.is_empty());
    }

