        assert!(tree.contains_key(&"apple"));
        assert!(tree.contains_key(&"banana"));
        assert!(!tree.contains_key(&"cherry"));
    }

    #[test]
    fn test_get_mut() {
        let mut tree = BTree::new(2);
        tree.insert(1, 10);
        if let Some(v) = tree.get_mut(&1) {
            *v = 99;
        }
        assert_eq!(tree.get(&1), Some(&99));
    }

    #[test]
    fn test_height_grows_logarithmically() {
