    }

    #[test]
    fn test_large_t() {
        let mut tree = BTree::new(50);
        for i in 0..500 {
            tree.insert(i, i);
        }
        assert_eq!(tree.len(), 500);
        // With t=50, the tree should be very flat.
        assert!(tree.height() <= 3);
        tree.validate().unwrap();
    }

    #[test]
    fn test_reverse_insert_order() {
        let mut tree = BTree::new(3);
        for i in (0..100).rev() {
            tree.insert(i, i);
        }
        let sorted: Vec<i32> = tree.iter().map(|(k, _)| *k).collect();
        let expected: Vec<i32> = (0..100).collect();
        assert_eq!(sorted, expected);
        tree.validate().unwrap();
    }

    #[test]
    fn test_interleaved_insert_delete() {
        let mut tree = BTree::new(3);
        for i in 0..50 {
            tree.insert(i, i);
        }
        for i in 0..25 {
            tree.remove(&i);
        }
        for i in 50..75 {
            tree.insert(i, i);
        }
        tree.validate().unwrap();
        assert_eq!(tree.len(), 50);
        let sorted: Vec<i32> = tree.iter().map(|(k, _)| *k).collect();
        let expected: Vec<i32> = (25..75).collect();
        assert_eq!(sorted, expected);
    }

    #[test]
    #[should_panic]
    fn test_t_less_than_2_panics() {
        let _tree: BTree<i32, i32> = BTree::new(1);
    }
