use serde::{Deserialize, Serialize};

/// Unique identifier for a Raft node
pub type NodeId = u64;

/// Raft term number
pub type Term = u64;

/// RPC message types exchanged between nodes
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum Message {
    /// Sent by candidates to gather votes
    RequestVote(RequestVoteArgs),
    /// Response to RequestVote
    RequestVoteReply(RequestVoteReply),
    /// Sent by leader to maintain authority / replicate log
    AppendEntries(AppendEntriesArgs),
    /// Response to AppendEntries
    AppendEntriesReply(AppendEntriesReply),
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RequestVoteArgs {
    /// Candidate's term
    pub term: Term,
    /// Candidate requesting vote
    pub candidate_id: NodeId,
    /// Index of candidate's last log entry
    pub last_log_index: u64,
    /// Term of candidate's last log entry
    pub last_log_term: Term,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RequestVoteReply {
    /// Current term, for candidate to update itself
    pub term: Term,
    /// True means candidate received vote
    pub vote_granted: bool,
    /// Who sent the reply
    pub from: NodeId,
}

/// Used as heartbeat when entries is empty
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AppendEntriesArgs {
    /// Leader's term
    pub term: Term,
    /// Leader's id so followers can redirect clients
    pub leader_id: NodeId,
    /// Index of log entry immediately preceding new ones
    pub prev_log_index: u64,
    /// Term of prev_log_index entry
    pub prev_log_term: Term,
    /// Log entries to store (empty for heartbeat)
    pub entries: Vec<LogEntry>,
    /// Leader's commit index
    pub leader_commit: u64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AppendEntriesReply {
    /// Current term, for leader to update itself
    pub term: Term,
    /// True if follower contained entry matching prev_log_index/term
    pub success: bool,
    /// Who sent the reply
    pub from: NodeId,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LogEntry {
    pub term: Term,
    pub index: u64,
    pub command: String,
}

/// Internal timer events
#[derive(Debug)]
pub enum TimerEvent {
    ElectionTimeout,
    HeartbeatTimeout,
}

/// Envelope wrapping a message with routing information
#[derive(Debug, Clone)]
pub struct Envelope {
    pub from: NodeId,
    pub to: NodeId,
    pub message: Message,
}
