use rand::Rng;
use std::time::Duration;
use tokio::time::{sleep, Instant};

pub const HEARTBEAT_INTERVAL_MS: u64 = 50;
pub const ELECTION_TIMEOUT_MIN_MS: u64 = 150;
pub const ELECTION_TIMEOUT_MAX_MS: u64 = 300;

/// Returns a randomized election timeout duration.
/// Randomization helps avoid split votes.
pub fn random_election_timeout() -> Duration {
    let ms = rand::thread_rng()
        .gen_range(ELECTION_TIMEOUT_MIN_MS..=ELECTION_TIMEOUT_MAX_MS);
    Duration::from_millis(ms)
}

pub fn heartbeat_interval() -> Duration {
    Duration::from_millis(HEARTBEAT_INTERVAL_MS)
}

/// A resettable timer
pub struct Timer {
    deadline: Instant,
    duration: Duration,
}

impl Timer {
    pub fn new(duration: Duration) -> Self {
        Self {
            deadline: Instant::now() + duration,
            duration,
        }
    }

    pub fn reset(&mut self) {
        self.deadline = Instant::now() + self.duration;
    }

    pub fn reset_with_duration(&mut self, duration: Duration) {
        self.duration = duration;
        self.deadline = Instant::now() + duration;
    }

    pub fn is_expired(&self) -> bool {
        Instant::now() >= self.deadline
    }

    pub async fn wait(&self) {
        let now = Instant::now();
        if self.deadline > now {
            sleep(self.deadline - now).await;
        }
    }

    pub fn remaining(&self) -> Duration {
        let now = Instant::now();
        if self.deadline > now {
            self.deadline - now
        } else {
            Duration::ZERO
        }
    }
}
