use crate::messages::{Envelope, NodeId};
use std::collections::HashMap;
use tokio::sync::mpsc::{self, Receiver, Sender};

const CHANNEL_BUFFER: usize = 256;

/// Simulated in-process network for testing.
/// In production this would be replaced by TCP/gRPC transport.
pub struct Network {
    /// Sender end for each node
    senders: HashMap<NodeId, Sender<Envelope>>,
}

impl Network {
    pub fn new() -> Self {
        Self {
            senders: HashMap::new(),
        }
    }

    /// Register a node and return its receiver channel
    pub fn register(&mut self, id: NodeId) -> Receiver<Envelope> {
        let (tx, rx) = mpsc::channel(CHANNEL_BUFFER);
        self.senders.insert(id, tx);
        rx
    }

    /// Get a clone of all senders (so nodes can send messages)
    pub fn get_transport(&self) -> Transport {
        Transport {
            senders: self.senders.clone(),
        }
    }
}

/// Cloneable handle for sending messages on the network
#[derive(Clone)]
pub struct Transport {
    senders: HashMap<NodeId, Sender<Envelope>>,
}

impl Transport {
    /// Send a message to a specific node (non-blocking, best-effort)
    pub async fn send(&self, envelope: Envelope) {
        if let Some(tx) = self.senders.get(&envelope.to) {
            // Ignore send errors (node may have crashed)
            let _ = tx.send(envelope).await;
        }
    }

    /// Broadcast a message to all nodes except the sender
    pub async fn broadcast(&self, from: crate::messages::NodeId, message: crate::messages::Message) {
        for (&id, tx) in &self.senders {
            if id != from {
                let envelope = Envelope {
                    from,
                    to: id,
                    message: message.clone(),
                };
                let _ = tx.send(envelope).await;
            }
        }
    }

    pub fn peer_ids(&self, exclude: NodeId) -> Vec<NodeId> {
        self.senders.keys().filter(|&&id| id != exclude).cloned().collect()
    }
}
