```rust
use crate::{
    messages::*,
    network::Transport,
    timer::{heartbeat_interval, random_election_timeout, Timer},
};
use std::collections::HashSet;
use tokio::{
    sync::mpsc::Receiver,
    time::timeout,
};
use tracing::{debug, info, warn};

/// The three possible states of a Raft node
#[derive(Debug, Clone, PartialEq)]
pub enum NodeState {
    Follower,
    Candidate,
    Leader,
}

impl std::fmt::Display for NodeState {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            NodeState::Follower => write!(f, "Follower"),
            NodeState::Candidate => write!(f, "Candidate"),
            NodeState::Leader => write!(f, "Leader"),
        }
    }
}

/// Persistent state (would be written to stable storage in production)
#[derive(Debug)]
struct PersistentState {
    /// Latest term node has seen
    current_term: Term,
    /// CandidateId that received vote in current term (None if none)
    voted_for: Option<NodeId>,
    /// Log entries
    log: Vec<LogEntry>,
}

impl PersistentState {
    fn new() -> Self {
        Self {
            current_term: 0,
            voted_for: None,
            log: Vec::new(),
        }
    }

    fn last_log_index(&self) -> u64 {
        self.log.last().map(|e| e.index).unwrap_or(0)
    }

    fn last_log_term(&self) -> Term {
        self.log.last().map(|e| e.term).unwrap_or(0)
    }
}

/// A single Raft cluster node
pub struct Node {
    /// This node's unique ID
    id: NodeId,
    /// All peer IDs in the cluster
    peers: Vec<NodeId>,
    /// Current role
    state: NodeState,
    /// Persistent Raft state
    persistent: PersistentState,
    /// Current known leader (for client redirection)
    leader_id: Option<NodeId>,
    /// Votes received as candidate
    votes_received: HashSet<NodeId>,
    /// Network transport
    transport: Transport,
    /// Inbound message receiver
    inbox: Receiver<Envelope>,
}

impl Node {
    pub fn new(id: NodeId, peers: Vec<NodeId>, transport: Transport, inbox: Receiver<Envelope>) -> Self {
        Self {
            id,
            peers,
            state: NodeState::Follower,
            persistent: PersistentState::new(),
            leader_id: None,
            votes_received: HashSet::new(),
            transport,
            inbox,
        }
    }

    /// Main event loop for the node
    pub async fn run(mut self) {
        info!("Node {} starting as Follower", self.id);

        loop {
            match self.state {
                NodeState::Follower => self.run_follower().await,
                NodeState::Candidate => self.run_candidate().await,
                NodeState::Leader => self.run_leader().await,
            }
        }
    }

    // ─────────────────────────────────────────
    //  State machine: Follower
    // ─────────────────────────────────────────

    async fn run_follower(&mut self) {
        let election_timeout = random_election_timeout();
        info!(
            "Node {} [Follower] term={} timeout={:?}",
            self.id, self.persistent.current_term, election_timeout
        );

        match timeout(election_timeout, self.inbox.recv()).await {
            // Timed out — start an election
            Err(_) => {
                info!(
                    "Node {} election timeout expired, converting to Candidate",
                    self.id
                );
                self.become_candidate();
            }

            // Received a message before timeout
            Ok(Some(envelope)) => {
                self.handle_message_as_follower(envelope).await;
            }

            Ok(None) => {
                warn!("Node {} inbox closed", self.id);
            }
        }
    }

    async fn handle_message_as_follower(&mut self, envelope: Envelope) {
        match envelope.message {
            Message::RequestVote(args) => {
                let reply = self.handle_request_vote(args);
                self.transport
                    .send(Envelope {
                        from: self.id,
                        to: envelope.from,
                        message: Message::RequestVoteReply(reply),
                    })
                    .await;
            }

            Message::AppendEntries(args) => {
                let reply = self.handle_append_entries(args);
                self.transport
                    .send(Envelope {
                        from: self.id,
                        to: envelope.from,
                        message: Message::AppendEntriesReply(reply),
                    })
                    .await;
            }

            // Followers ignore vote replies and AE replies
            Message::RequestVoteReply(_) | Message::AppendEntriesReply(_) => {}
        }
    }

    // ─────────────────────────────────────────
    //  State machine: Candidate
    // ─────────────────────────────────────────

    async fn run_candidate(&mut self) {
        // Send RequestVote to all peers
        self.broadcast_request_vote().await;

        let election_timeout = random_election_timeout();
        let timer = Timer::new(election_timeout);

        info!(
            "Node {} [Candidate] term={} waiting for votes (need {}) timeout={:?}",
            self.id,
            self.persistent.current_term,
            self.quorum(),
            election_timeout
        );

        loop {
            // Wait for a message or election timeout
            let remaining = timer.remaining();
            match timeout(remaining, self.inbox.recv()).await {
                // Election timed out — restart election
                Err(_) => {
                    info!("Node {} election timed out, starting new election", self.id);
                    self.become_candidate(); // increments term
                    return;
                }

                Ok(Some(envelope)) => {
                    if self.handle_message_as_candidate(envelope).await {
                        // State changed — exit loop
                        return;
                    }
                }

                Ok(None) => {
                    warn!("Node {} inbox closed", self.id);
                    return;
                }
            }
        }
    }

    /// Returns true if the state has changed (won election or stepped down)
    async fn handle_message_as_candidate(&mut self, envelope: Envelope) -> bool {
        match envelope.message {
            Message::RequestVoteReply(reply) => {
                debug!(
                    "Node {} received vote reply from {} granted={}",
                    self.id, reply.from, reply.vote_granted
                );

                // If we see a higher term, step down
                if reply.term > self.persistent.current_term {
                    info!(
                        "Node {} sees higher term {} from {}, stepping down",
                        self.id, reply.term, reply.from
                    );
                    self.become_follower(reply.term, None);
                    return true;
                }

                // Only count votes for our current term
                if reply.term == self.persistent.current_term && reply.vote_granted {
                    self.votes_received.insert(reply.from);
                    info!(
                        "Node {} has {}/{} votes",
                        self.id,
                        self.votes_received.len(),
                        self.cluster_size()
                    );

                    if self.votes_received.len() >= self.quorum() {
                        self.become_leader();
                        return true;
                    }
                }
                false
            }

            Message::RequestVote(args) => {
                let reply = self.handle_request_vote(args);
                self.transport
                    .send(Envelope {
                        from: self.id,
                        to: envelope.from,
                        message: Message::RequestVoteReply(reply),
                    })
                    .await;
                // If we granted a vote, we stepped down in handle_request_vote
                self.state != NodeState::Candidate
            }

            Message::AppendEntries(args) => {
                // If we receive AppendEntries from a valid leader, step down
                if args.term >= self.persistent.current_term {
                    info!(
                        "Node {} received AppendEntries from leader {} in term {}, stepping down",
                        self.id, args.leader_id, args.term
                    );
                    self.become_follower(args.term, Some(args.leader_id));
                    let reply = self.handle_append_entries(args);
                    self.transport
                        .send(Envelope {
                            from: self.id,
                            to: envelope.from,
                            message: Message::AppendEntriesReply(reply),
                        })
                        .await;
                    return true;
                }
                let reply = self.handle_append_entries(args);
                self.transport
                    .send(Envelope {
                        from: self.id,
                        to: envelope.from,
                        message: Message::AppendEntriesReply(reply),
                    })
                    .await;
                false
            }

            Message::AppendEntriesReply(_) => false,
        }
    }

    // ─────────────────────────────────────────
    //  State machine: Leader
    // ─────────────────────────────────────────

    async fn run_leader(&mut self) {
        info!(
            "Node {} [Leader] term={} — sending initial heartbeat",
            self.id, self.persistent.current_term
        );

        // Send immediate heartbeat on becoming leader
        self.send_heartbeats().await;

        let heartbeat_interval = heartbeat_interval();
        let mut timer = Timer::new(heartbeat_interval);

        loop {
            let remaining = timer.remaining();
            match timeout(remaining, self.inbox.recv()).await {
                // Heartbeat interval elapsed — send heartbeats
                Err(_) => {
                    self.send_heartbeats().await;
                    timer.reset_with_duration(heartbeat_interval);
                }

                Ok(Some(envelope)) => {
                    if self.handle_message_as_leader(envelope).await {
                        return; // No longer leader
                    }
                }

                Ok(None) => {
                    warn!("Node {} inbox closed", self.id);
                    return;
                }
            }
        }
    }

    async fn handle_message_as_leader(&mut self, envelope: Envelope) -> bool {
        match envelope.message {
            Message::AppendEntriesReply(reply) => {
                // Step down if we see a higher term
                if reply.term > self.persistent.current_term {
                    info!(
                        "Node {} (Leader) sees higher term {}, stepping down",
                        self.id, reply.term
                    );
                    self.become_follower(reply.term, None);
                    return true;
                }
                false
            }

            Message::RequestVote(args) => {
                let reply = self.handle_request_vote(args);
                let stepped_down = self.state != NodeState::Leader;
                self.transport
                    .send(Envelope {
                        from: self.id,
                        to: envelope.from,
                        message: Message::RequestVoteReply(reply),
                    })
                    .await;
                stepped_down
            }

            Message::AppendEntries(args) => {
                // Another leader with equal/higher term — step down
                if args.term >= self.persistent.current_term {
                    info!(
                        "Node {} (Leader) sees AppendEntries from newer leader {}, stepping down",
                        self.id, args.leader_id
                    );
                    self.become_follower(args.term, Some(args.leader_id));
                    let reply = self.handle_append_entries(args);
                    self.transport
                        .send(Envelope {
                            from: self.id,
                            to: envelope.from,
                            message: Message::AppendEntriesReply(reply),
                        })
                        .await;
                    return true;
                }
                false
            }

            Message::RequestVoteReply(_) => false,
        }
    }

    // ─────────────────────────────────────────
    //  Core RPC handlers
    // ─────────────────────────────────────────

    /// §5.2: RequestVote RPC handler
    fn handle_request_vote(&mut self, args: RequestVoteArgs) -> RequestVoteReply {
        debug!(
            "Node {} received RequestVote from {} for term {}",
            self.id, args.candidate_id, args.term
        );

        // Rule: if we see a higher term, update and convert to follower
        if args.term > self.persistent.current_term {
            self.become_follower(args.term, None);
        }

        let vote_granted = self.should_grant_vote(&args);

        if vote_granted {
            info!(
                "Node {} granting vote to {} for term {}",
                self.id, args.candidate_id, args.term
            );
            self.persistent.voted_for = Some(args.candidate_id);
        } else {
            debug!(
                "Node {} denying vote to {} for term {}",
                self.id, args.candidate_id, args.term
            );
        }

        RequestVoteReply {
            term: self.persistent.current_term,
            vote_granted,
            from: self.id,
        }
    }

    /// Determine whether to grant a vote per §5.2 and §5.4 (log up-to-date check)
    fn should_grant_vote(&self, args: &RequestVoteArgs) -> bool {
        // Reject if candidate has a stale term
        if args.term < self.persistent.current_term {
            return false;
        }

        // Check if we've already voted for someone else this term
        let vote_ok = match self.persistent.voted_for {
            None => true,
            Some(voted_for) => voted_for == args.candidate_id,
        };

        if !vote_ok {
            return false;
        }

        // §5.4.1: Log up-to-date check
        // Candidate's log is at least as up-to-date as ours
        let our_last_term = self.persistent.last_log_term();
        let our_last_index = self.persistent.last_log_index();

        if args.last_log_term != our_last_term {
            args.last_log_term > our_last_term
        } else {
            args.last_log_index >= our_last_index
        }
    }

    /// §5.1 / §5.3: AppendEntries RPC handler (also serves as heartbeat)
    fn handle_append_entries(&mut self, args: AppendEntriesArgs) -> AppendEntriesReply {
        // Reject if leader has stale term
        if args.term < self.persistent.current_term {
            return AppendEntriesReply {
                term: self.persistent.current_term,
                success: false,
                from: self.id,
            };
        }

        // Valid heartbeat/AE — update term and leader
        if args.term > self.persistent.current_term {
            self.persistent.current_term = args.term;
            self.persistent.voted_for = None;
        }

        self.leader_id = Some(args.leader_id);

        // For a full implementation, log consistency check would go here.
        // For election-only purposes, we accept the heartbeat.

        AppendEntriesReply {
            term: self.persistent.current_term,
            success: true,
            from: self.id,
        }
    }

    // ─────────────────────────────────────────
    //  State transitions
    // ─────────────────────────────────────────

    fn become_follower(&mut self, term: Term, leader_id: Option<NodeId>) {
        info!(
            "Node {} → Follower (term {} → {})",
            self.id, self.persistent.current_term, term
        );
        self.persistent.current_term = term;
        self.persistent.voted_for = None;
        self.state = NodeState::Follower;
        self.leader_id = leader_id;
        self.votes_received.clear();
    }

    fn become_candidate(&mut self) {
        self.persistent.current_term += 1;
        self.state = NodeState::Candidate;
        // Vote for self
        self.persistent.voted_for = Some(self.id);
        self.votes_received.clear();
        self.votes_received.insert(self.id);
        self.leader_id = None;
        info!(
            "Node {} → Candidate (term {})",
            self.id, self.persistent.current_term
        );
    }

    fn become_leader(&mut self) {
        info!(
            "Node {} → LEADER (term {})",
            self.id, self.persistent.current_term
        );
        self.state = NodeState::Leader;
        self.leader_id = Some(self.id);
    }

    // ─────────────────────────────────────────
    //  Helper methods
    // ─────────────────────────────────────────

    async fn broadcast_request_vote(&self) {
        let args = RequestVoteArgs {
            term: self.persistent.current_term,
            candidate_id: self.id,
            last_log_index: self.persistent.last_log_index(),
            last_log_term: self.persistent.last_log_term(),
        };
        info!(
            "Node {} broadcasting RequestVote for term {}",
            self.id, args.term
        );
        self.transport
            .broadcast(self.id, Message::RequestVote(args))
            .await;
    }

    async fn send_heartbeats(&self) {
        let args = AppendEntriesArgs {
            term: self.persistent.current_term,
            leader_id: self.id,
            prev_log_index: self.persistent.last_log_index(),
            prev_log_term: self.persistent.last_log_term(),
            entries: vec![], // Empty = heartbeat
            leader_commit: 0,
        };
        debug!("Node {} sending heartbeats for term {}", self.id, args.term);
        self.transport
            .broadcast(self.id, Message::AppendEntries(args))
            .await;
    }

    /// Number of votes needed to win (majority)
    fn quorum(&self) -> usize {
        self.cluster_size() / 2 + 1
    }

    fn cluster_size(&self) -> usize {
        self.peers.len() + 1 // peers + self
    }
}
