mod messages;
mod network;
mod node;
mod timer;

use network::Network;
use node::Node;
use tokio::time::{sleep, Duration};
use tracing::info;
use tracing_subscriber::{fmt, EnvFilter};

#[tokio::main]
async fn main() {
    // Initialize structured logging
    // Set RUST_LOG=debug for verbose output, or info for high-level events
    fmt()
        .with_env_filter(
            EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")),
        )
        .with_target(false)
        .with_thread_ids(true)
        .init();

    info!("Starting Raft leader election simulation with 5 nodes");

    let node_ids: Vec<u64> = vec![1, 2, 3, 4, 5];
    let mut network = Network::new();

    // Register all nodes and collect receivers
    let mut receivers = Vec::new();
    for &id in &node_ids {
        let rx = network.register(id);
        receivers.push((id, rx));
    }

    let transport = network.get_transport();

    // Spawn each node as an independent Tokio task
    let mut handles = Vec::new();
    for (id, rx) in receivers {
        let peers: Vec<u64> = node_ids.iter().filter(|&&p| p != id).cloned().collect();
        let t = transport.clone();

        let handle = tokio::spawn(async move {
            let node = Node::new(id, peers, t, rx);
            node.run().await;
        });

        handles.push(handle);
    }

    // Let the simulation run for 10 seconds
    info!("Simulation running for 10 seconds...");
    sleep(Duration::from_secs(10)).await;

    info!("Simulation complete.");
    // In a real system you'd implement graceful shutdown
    // For this demo we just exit
    std::process::exit(0);
}
