# Persistent Red-Black Tree in Rust

A persistent (immutable/functional) red-black tree where every operation creates a new version while sharing structure with the previous version.

## Implementation

```rust
use std::sync::Arc;
use std::fmt;

// ─── Color ────────────────────────────────────────────────────────────────────

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Color {
    Red,
    Black,
}

// ─── Node ─────────────────────────────────────────────────────────────────────

/// An inner node.  We use `Arc` so that subtrees can be shared between
/// old and new versions of the tree (structural sharing).
#[derive(Clone, Debug)]
struct Node<K, V> {
    color: Color,
    key:   K,
    value: V,
    left:  Tree<K, V>,
    right: Tree<K, V>,
}

/// A tree is either empty or a shared pointer to a node.
type Tree<K, V> = Option<Arc<Node<K, V>>>;

// ─── Public handle ────────────────────────────────────────────────────────────

/// A persistent red-black tree map.
///
/// All mutating operations (`insert`, `delete`) return a **new** `RBTree`
/// while the original remains unchanged.  Cloning a `RBTree` is O(1)
/// because the underlying nodes are reference-counted and shared.
#[derive(Clone, Debug)]
pub struct RBTree<K, V> {
    root: Tree<K, V>,
    len:  usize,
}

// ─── Helper constructors ──────────────────────────────────────────────────────

fn node<K: Clone, V: Clone>(
    color: Color,
    key:   K,
    value: V,
    left:  Tree<K, V>,
    right: Tree<K, V>,
) -> Tree<K, V> {
    Some(Arc::new(Node { color, key, value, left, right }))
}

fn color_of<K, V>(t: &Tree<K, V>) -> Color {
    t.as_ref().map_or(Color::Black, |n| n.color)
}

fn blacken<K: Clone, V: Clone>(t: Tree<K, V>) -> Tree<K, V> {
    match t {
        Some(ref n) if n.color == Color::Red => {
            node(Color::Black, n.key.clone(), n.value.clone(),
                 n.left.clone(), n.right.clone())
        }
        other => other,
    }
}

fn redden<K: Clone, V: Clone>(t: Tree<K, V>) -> Tree<K, V> {
    match t {
        Some(ref n) if n.color == Color::Black => {
            node(Color::Red, n.key.clone(), n.value.clone(),
                 n.left.clone(), n.right.clone())
        }
        other => other,
    }
}

// ─── Balancing (Okasaki-style) ────────────────────────────────────────────────

/// Re-balance after an insertion that may have created a red-red violation.
///
/// The four cases are symmetric; we handle all of them here so that
/// callers never have to think about rotation direction.
fn balance<K: Clone, V: Clone>(
    color: Color,
    key:   K,
    value: V,
    left:  Tree<K, V>,
    right: Tree<K, V>,
) -> Tree<K, V> {
    // Only black nodes need re-balancing.
    if color == Color::Red {
        return node(Color::Red, key, value, left, right);
    }

    //  Case 1 – left-left red-red:
    //       B(z)                 R(y)
    //      /    \               /    \
    //   R(y)    d      →     B(x)   B(z)
    //   /  \                 / \    / \
    //  R(x)  c              a   b  c   d
    //  / \
    // a   b
    if let Some(ref l) = left {
        if l.color == Color::Red {
            if let Some(ref ll) = l.left {
                if ll.color == Color::Red {
                    return node(
                        Color::Red,
                        l.key.clone(), l.value.clone(),
                        node(Color::Black,
                             ll.key.clone(), ll.value.clone(),
                             ll.left.clone(), ll.right.clone()),
                        node(Color::Black,
                             key, value,
                             l.right.clone(), right),
                    );
                }
            }
            //  Case 2 – left-right red-red:
            //       B(z)               R(y)
            //      /    \             /    \
            //   R(x)     d    →    B(x)   B(z)
            //   /  \               / \    / \
            //  a   R(y)           a   b  c   d
            //      / \
            //     b   c
            if let Some(ref lr) = l.right {
                if lr.color == Color::Red {
                    return node(
                        Color::Red,
                        lr.key.clone(), lr.value.clone(),
                        node(Color::Black,
                             l.key.clone(), l.value.clone(),
                             l.left.clone(), lr.left.clone()),
                        node(Color::Black,
                             key, value,
                             lr.right.clone(), right),
                    );
                }
            }
        }
    }

    //  Case 3 – right-left red-red (mirror of case 2):
    if let Some(ref r) = right {
        if r.color == Color::Red {
            if let Some(ref rl) = r.left {
                if rl.color == Color::Red {
                    return node(
                        Color::Red,
                        rl.key.clone(), rl.value.clone(),
                        node(Color::Black,
                             key, value,
                             left, rl.left.clone()),
                        node(Color::Black,
                             r.key.clone(), r.value.clone(),
                             rl.right.clone(), r.right.clone()),
                    );
                }
            }
            //  Case 4 – right-right red-red (mirror of case 1):
            if let Some(ref rr) = r.right {
                if rr.color == Color::Red {
                    return node(
                        Color::Red,
                        r.key.clone(), r.value.clone(),
                        node(Color::Black,
                             key, value,
                             left, r.left.clone()),
                        node(Color::Black,
                             rr.key.clone(), rr.value.clone(),
                             rr.left.clone(), rr.right.clone()),
                    );
                }
            }
        }
    }

    node(Color::Black, key, value, left, right)
}

// ─── Insertion ────────────────────────────────────────────────────────────────

/// Returns `(new_tree, did_insert_new_key)`.
fn ins<K, V>(t: &Tree<K, V>, key: K, value: V) -> (Tree<K, V>, bool)
where
    K: Ord + Clone,
    V: Clone,
{
    match t {
        None => (node(Color::Red, key, value, None, None), true),
        Some(n) => {
            use std::cmp::Ordering::*;
            match key.cmp(&n.key) {
                Less => {
                    let (new_left, inserted) = ins(&n.left, key, value);
                    (balance(n.color, n.key.clone(), n.value.clone(),
                             new_left, n.right.clone()), inserted)
                }
                Greater => {
                    let (new_right, inserted) = ins(&n.right, key, value);
                    (balance(n.color, n.key.clone(), n.value.clone(),
                             n.left.clone(), new_right), inserted)
                }
                Equal => {
                    // Update in place (same structure, new value).
                    (node(n.color, n.key.clone(), value,
                          n.left.clone(), n.right.clone()), false)
                }
            }
        }
    }
}

// ─── Deletion helpers (Germane & Might 2014) ──────────────────────────────────

/// A "double-black" sentinel used only during deletion.
/// We keep it in the tree type with a wrapper so we don't litter the
/// main Node with extra state.
#[derive(Clone, Debug, PartialEq, Eq)]
enum ExtColor { Red, Black, DoubleBlack }

/// Extended node used only during the deletion phase.
#[derive(Clone, Debug)]
struct ENode<K, V> {
    color: ExtColor,
    key:   K,
    value: V,
    left:  ETree<K, V>,
    right: ETree<K, V>,
}

/// Extended tree: None = Black-leaf, DoubleBlack sentinel = double-black leaf.
#[derive(Clone, Debug)]
enum ETree<K, V> {
    Empty,                          // Black leaf
    DoubleBlackEmpty,               // Double-black leaf (temporary)
    Node(Arc<ENode<K, V>>),
}

impl<K: Clone, V: Clone> ETree<K, V> {
    fn enode(color: ExtColor, key: K, value: V,
             left: ETree<K, V>, right: ETree<K, V>) -> Self {
        ETree::Node(Arc::new(ENode { color, key, value, left, right }))
    }

    fn is_double_black(&self) -> bool {
        matches!(self, ETree::DoubleBlackEmpty)
            || matches!(self, ETree::Node(n) if n.color == ExtColor::DoubleBlack)
    }

    fn make_black(&self) -> Self {
        match self {
            ETree::DoubleBlackEmpty => ETree::Empty,
            ETree::Node(n) if n.color == ExtColor::DoubleBlack =>
                ETree::enode(ExtColor::Black,
                             n.key.clone(), n.value.clone(),
                             n.left.clone(), n.right.clone()),
            other => other.clone(),
        }
    }

    fn make_double_black(&self) -> Self {
        match self {
            ETree::Empty => ETree::DoubleBlackEmpty,
            ETree::Node(n) if n.color == ExtColor::Black =>
                ETree::enode(ExtColor::DoubleBlack,
                             n.key.clone(), n.value.clone(),
                             n.left.clone(), n.right.clone()),
            other => other.clone(),
        }
    }
}

/// Convert a normal Tree into an ETree.
fn to_etree<K: Clone, V: Clone>(t: &Tree<K, V>) -> ETree<K, V> {
    match t {
        None => ETree::Empty,
        Some(n) => ETree::enode(
            match n.color { Color::Red => ExtColor::Red,
                            Color::Black => ExtColor::Black },
            n.key.clone(), n.value.clone(),
            to_etree(&n.left),
            to_etree(&n.right),
        ),
    }
}

/// Convert an ETree back to a normal Tree (must not contain DoubleBlack).
fn from_etree<K: Clone, V: Clone>(t: &ETree<K, V>) -> Tree<K, V> {
    match t {
        ETree::Empty => None,
        ETree::DoubleBlackEmpty => panic!("double-black leaf survived deletion"),
        ETree::Node(n) => {
            let color = match n.color {
                ExtColor::Red   => Color::Red,
                ExtColor::Black => Color::Black,
                ExtColor::DoubleBlack => panic!("double-black node survived"),
            };
            node(color, n.key.clone(), n.value.clone(),
                 from_etree(&n.left), from_etree(&n.right))
        }
    }
}

/// Remove the minimum key from an ETree; returns (min_key, min_val, new_tree).
fn remove_min<K: Clone, V: Clone>(t: &ETree<K, V>)
    -> (K, V, ETree<K, V>)
{
    match t {
        ETree::Node(n) => {
            match &n.left {
                ETree::Empty => {
                    // This is the minimum; replace with right child bubbled up.
                    let replacement = match n.color {
                        ExtColor::Red   => n.right.clone(),
                        ExtColor::Black => n.right.make_double_black(),
                        ExtColor::DoubleBlack => unreachable!(),
                    };
                    (n.key.clone(), n.value.clone(), replacement)
                }
                left => {
                    let (mk, mv, new_left) = remove_min(left);
                    let rebuilt = ETree::enode(
                        n.color.clone(), n.key.clone(), n.value.clone(),
                        new_left, n.right.clone(),
                    );
                    (mk, mv, bubble(rebuilt))
                }
            }
        }
        _ => unreachable!("remove_min on empty / double-black-empty"),
    }
}

/// The four rotation cases that eliminate a double-black node (Germane & Might).
fn balance_del<K: Clone, V: Clone>(t: ETree<K, V>) -> ETree<K, V> {
    match &t {
        ETree::Node(n) => {
            // ── (BB or DBB) left child + red right sibling → rotate ──────
            //  Case: black root, double-black left, red right
            if n.color == ExtColor::Black && n.left.is_double_black() {
                if let ETree::Node(r) = &n.right {
                    if r.color == ExtColor::Red {
                        // Rotate left, then fix up the double-black on the left
                        let inner = ETree::enode(
                            ExtColor::Black,
                            n.key.clone(), n.value.clone(),
                            n.left.make_black(),   // was double-black
                            r.left.clone(),
                        );
                        let fixed_inner = balance_del(inner);
                        return ETree::enode(
                            ExtColor::Black,
                            r.key.clone(), r.value.clone(),
                            fixed_inner,
                            r.right.clone(),
                        );
                    }
                }
            }
            // Symmetric: black root, double-black right, red left
            if n.color == ExtColor::Black && n.right.is_double_black() {
                if let ETree::Node(l) = &n.left {
                    if l.color == ExtColor::Red {
                        let inner = ETree::enode(
                            ExtColor::Black,
                            n.key.clone(), n.value.clone(),
                            l.right.clone(),
                            n.right.make_black(),
                        );
                        let fixed_inner = balance_del(inner);
                        return ETree::enode(
                            ExtColor::Black,
                            l.key.clone(), l.value.clone(),
                            l.left.clone(),
                            fixed_inner,
                        );
                    }
                }
            }

            // ── Double-black left + black right with black children → recolor
            if n.left.is_double_black() {
                if let ETree::Node(r) = &n.right {
                    if r.color == ExtColor::Black
                        && color_ext(&r.left)  == ExtColor::Black
                        && color_ext(&r.right) == ExtColor::Black
                    {
                        let new_root_color = if n.color == ExtColor::Red {
                            ExtColor::Black
                        } else {
                            ExtColor::DoubleBlack
                        };
                        return ETree::enode(
                            new_root_color,
                            n.key.clone(), n.value.clone(),
                            n.left.make_black(),
                            ETree::enode(ExtColor::Red,
                                         r.key.clone(), r.value.clone(),
                                         r.left.clone(), r.right.clone()),
                        );
                    }
                    // Black right sibling with red left child
                    if r.color == ExtColor::Black {
                        if let ETree::Node(rl) = &r.left {
                            if rl.color == ExtColor::Red
                                && color_ext(&r.right) == ExtColor::Black
                            {
                                return ETree::enode(
                                    n.color.clone(),
                                    rl.key.clone(), rl.value.clone(),
                                    ETree::enode(ExtColor::Black,
                                                 n.key.clone(), n.value.clone(),
                                                 n.left.make_black(),
                                                 rl.left.clone()),
                                    ETree::enode(ExtColor::Black,
                                                 r.key.clone(), r.value.clone(),
                                                 rl.right.clone(),
                                                 r.right.clone()),
                                );
                            }
                        }
                        // Black right sibling with red right child
                        if let ETree::Node(rr) = &r.right {
                            if rr.color == ExtColor::Red {
                                return ETree::enode(
                                    n.color.clone(),
                                    r.key.clone(), r.value.clone(),
                                    ETree::enode(ExtColor::Black,
                                                 n.key.clone(), n.value.clone(),
                                                 n.left.make_black(),
                                                 r.left.clone()),
                                    ETree::enode(ExtColor::Black,
                                                 rr.key.clone(), rr.value.clone(),
                                                 rr.left.clone(), rr.right.clone()),
                                );
                            }
                        }
                    }
                }
            }

            // Symmetric: double-black right
            if n.right.is_double_black() {
                if let ETree::Node(l) = &n.left {
                    if l.color == ExtColor::Black
                        && color_ext(&l.left)  == ExtColor::Black
                        && color_ext(&l.right) == ExtColor::Black
                    {
                        let new_root_color = if n.color == ExtColor::Red {
                            ExtColor::Black
                        } else {
                            ExtColor::DoubleBlack
                        };
                        return ETree::enode(
                            new_root_color,
                            n.key.clone(), n.value.clone(),
                            ETree::enode(ExtColor::Red,
                                         l.key.clone(), l.value.clone(),
                                         l.left.clone(), l.right.clone()),
                            n.right.make_black(),
                        );
                    }
                    if l.color == ExtColor::Black {
                        // Black left sibling with red right child
                        if let ETree::Node(lr) = &l.right {
                            if lr.color == ExtColor::Red
                                && color_ext(&l.left) == ExtColor::Black
                            {
                                return ETree::enode(
                                    n.color.clone(),
                                    lr.key.clone(), lr.value.clone(),
                                    ETree::enode(ExtColor::Black,
                                                 l.key.clone(), l.value.clone(),
                                                 l.left.clone(),
                                                 lr.left.clone()),
                                    ETree::enode(ExtColor::Black,
                                                 n.key.clone(), n.value.clone(),
                                                 lr.right.clone(),
                                                 n.right.make_black()),
                                );
                            }
                        }
                        // Black left sibling with red left child
                        if let ETree::Node(ll) = &l.left {
                            if ll.color == ExtColor::Red {
                                return ETree::enode(
                                    n.color.clone(),
                                    l.key.clone(), l.value.clone(),
                                    ETree::enode(ExtColor::Black,
                                                 ll.key.clone(), ll.value.clone(),
                                                 ll.left.clone(), ll.right.clone()),
                                    ETree::enode(ExtColor::Black,
                                                 n.key.clone(), n.value.clone(),
                                                 l.right.clone(),
                                                 n.right.make_black()),
                                );
                            }
                        }
                    }
                }
            }

            t
        }
        _ => t,
    }
}

fn color_ext<K, V>(t: &ETree<K, V>) -> ExtColor {
    match t {
        ETree::Empty => ExtColor::Black,
        ETree::DoubleBlackEmpty => ExtColor::DoubleBlack,
        ETree::Node(n) => n.color.clone(),
    }
}

/// Propagate double-black upward.
fn bubble<K: Clone, V: Clone>(t: ETree<K, V>) -> ETree<K, V> {
    match &t {
        ETree::Node(n) if n.left.is_double_black() || n.right.is_double_black() => {
            balance_del(t)
        }
        _ => t,
    }
}

/// Delete `key` from an ETree; returns `(new_tree, deleted)`.
fn del<K, V>(t: &ETree<K, V>, key: &K) -> (ETree<K, V>, bool)
where
    K: Ord + Clone,
    V: Clone,
{
    match t {
        ETree::Empty | ETree::DoubleBlackEmpty => (t.clone(), false),
        ETree::Node(n) => {
            use std::cmp::Ordering::*;
            match key.cmp(&n.key) {
                Less => {
                    let (new_left, deleted) = del(&n.left, key);
                    let rebuilt = ETree::enode(
                        n.color.clone(), n.key.clone(), n.value.clone(),
                        new_left, n.right.clone(),
                    );
                    (bubble(rebuilt), deleted)
                }
                Greater => {
                    let (new_right, deleted) = del(&n.right, key);
                    let rebuilt = ETree::enode(
                        n.color.clone(), n.key.clone(), n.value.clone(),
                        n.left.clone(), new_right,
                    );
                    (bubble(rebuilt), deleted)
                }
                Equal => {
                    // Found the node to delete.
                    match (&n.left, &n.right) {
                        // Leaf cases
                        (ETree::Empty, ETree::Empty) => {
                            let replacement = if n.color == ExtColor::Red {
                                ETree::Empty
                            } else {
                                ETree::DoubleBlackEmpty
                            };
                            (replacement, true)
                        }
                        (ETree::Empty, right) => {
                            // Must be a black node with a single red child.
                            (right.make_black(), true)
                        }
                        (left, ETree::Empty) => {
                            (left.make_black(), true)
                        }
                        // Two children: replace with in-order successor.
                        (_left, right) => {
                            let (sk, sv, new_right) = remove_min(right);
                            let rebuilt = ETree::enode(
                                n.color.clone(), sk, sv,
                                n.left.clone(), new_right,
                            );
                            (bubble(rebuilt), true)
                        }
                    }
                }
            }
        }
    }
}

// ─── RBTree impl ──────────────────────────────────────────────────────────────

impl<K, V> RBTree<K, V>
where
    K: Ord + Clone,
    V: Clone,
{
    /// Create an empty tree.
    pub fn new() -> Self {
        RBTree { root: None, len: 0 }
    }

    /// Number of key-value pairs in the tree.
    pub fn len(&self) -> usize {
        self.len
    }

    /// Whether the tree is empty.
    pub fn is_empty(&self) -> bool {
        self.len == 0
    }

    /// Look up `key`.  O(log n).
    pub fn get(&self, key: &K) -> Option<&V> {
        let mut current = &self.root;
        loop {
            match current {
                None => return None,
                Some(n) => match key.cmp(&n.key) {
                    std::cmp::Ordering::Less    => current = &n.left,
                    std::cmp::Ordering::Greater => current = &n.right,
                    std::cmp::Ordering::Equal   => return Some(&n.value),
                },
            }
        }
    }

    /// Whether `key` is in the tree.
    pub fn contains_key(&self, key: &K) -> bool {
        self.get(key).is_some()
    }

    /// Return a **new** tree with `(key, value)` inserted (or updated).
    /// O(log n) time and space.
    pub fn insert(&self, key: K, value: V) -> Self {
        let (new_root, inserted) = ins(&self.root, key, value);
        RBTree {
            root: blacken(new_root),
            len:  if inserted { self.len + 1 } else { self.len },
        }
    }

    /// Return a **new** tree with `key` removed.
    /// O(log n) time and space.
    pub fn delete(&self, key: &K) -> Self {
        let etree = to_etree(&self.root);
        let (new_etree, deleted) = del(&etree, key);
        RBTree {
            root: blacken(from_etree(&new_etree)),
            len:  if deleted { self.len - 1 } else { self.len },
        }
    }

    /// Minimum (key, value) pair, or `None` if empty.
    pub fn min(&self) -> Option<(&K, &V)> {
        let mut cur = &self.root;
        let mut result = None;
        while let Some(n) = cur {
            result = Some((&n.key, &n.value));
            cur = &n.left;
        }
        result
    }

    /// Maximum (key, value) pair, or `None` if empty.
    pub fn max(&self) -> Option<(&K, &V)> {
        let mut cur = &self.root;
        let mut result = None;
        while let Some(n) = cur {
            result = Some((&n.key, &n.value));
            cur = &n.right;
        }
        result
    }

    /// In-order iterator over `(key, value)` pairs.
    pub fn iter(&self) -> Iter<K, V> {
        let mut stack = Vec::new();
        push_left(&self.root, &mut stack);
        Iter { stack }
    }

    /// Collect all (key, value) pairs in sorted order.
    pub fn to_vec(&self) -> Vec<(&K, &V)> {
        self.iter().collect()
    }
}

fn push_left<'a, K, V>(mut t: &'a Tree<K, V>, stack: &mut Vec<&'a Node<K, V>>) {
    while let Some(n) = t {
        stack.push(n);
        t = &n.left;
    }
}

/// In-order iterator.
pub struct Iter<'a, K, V> {
    stack: Vec<&'a Node<K, V>>,
}

impl<'a, K, V> Iterator for Iter<'a, K, V> {
    type Item = (&'a K, &'a V);

    fn next(&mut self) -> Option<Self::Item> {
        let n = self.stack.pop()?;
        push_left(&n.right, &mut self.stack);
        Some((&n.key, &n.value))
    }
}

// ─── Default ──────────────────────────────────────────────────────────────────

impl<K: Ord + Clone, V: Clone> Default for RBTree<K, V> {
    fn default() -> Self { Self::new() }
}

// ─── Display ─────────────────────────────────────────────────────────────────

impl<K: fmt::Display + Ord + Clone, V: fmt::Display + Clone> fmt::Display
    for RBTree<K, V>
{
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{{")?;
        let mut first = true;
        for (k, v) in self.iter() {
            if !first { write!(f, ", ")?; }
            write!(f, "{k}: {v}")?;
            first = false;
        }
        write!(f, "}}")
    }
}

// ─── Verification (for testing) ───────────────────────────────────────────────

impl<K: Ord + Clone, V: Clone> RBTree<K, V> {
    /// Verify red-black invariants.  Returns the black-height on success or
    /// panics with a descriptive message.
    #[cfg(test)]
    fn check_invariants(&self) -> usize {
        check_node(&self.root, None, true)
    }
}

#[cfg(test)]
fn check_node<K: Ord, V>(
    t: &Tree<K, V>,
    parent_key: Option<&K>,
    is_left: bool,
) -> usize {
    match t {
        None => 1, // black leaf contributes 1 to black-height
        Some(n) => {
            // BST order
            if let Some(pk) = parent_key {
                if is_left  { assert!(n.key < *pk,  "BST left violation"); }
                else        { assert!(n.key > *pk,  "BST right violation"); }
            }
            // Red node must not have red children
            if n.color == Color::Red {
                assert_ne!(color_of(&n.left),  Color::Red, "red-red left");
                assert_ne!(color_of(&n.right), Color::Red, "red-red right");
            }
            let lbh = check_node(&n.left,  Some(&n.key), true);
            let rbh = check_node(&n.right, Some(&n.key), false);
            assert_eq!(lbh, rbh, "black-height mismatch at key");
            lbh + if n.color == Color::Black { 1 } else { 0 }
        }
    }
}

