#[cfg(test)]
mod tests {
    use super::*;

    /// Helper: build a simple graph
    ///   root → A → B
    ///              → C (also root)
    ///   D (unreachable)
    fn build_basic_heap(gc: &mut TriColorGc) -> (ObjectId, ObjectId, ObjectId, ObjectId, ObjectId) {
        let root = gc.allocate("root");
        let a    = gc.allocate("A");
        let b    = gc.allocate("B");
        let c    = gc.allocate("C");
        let d    = gc.allocate("D"); // unreachable

        gc.set_field(root, "child", Value::Ref(a)).unwrap();
        gc.set_field(a, "left",  Value::Ref(b)).unwrap();
        gc.set_field(a, "right", Value::Ref(c)).unwrap();

        gc.add_root(root);
        gc.add_root(c);

        (root, a, b, c, d)
    }

    #[test]
    fn test_unreachable_collected() {
        let mut gc = TriColorGc::new();
        let (_root, _a, _b, _c, d) = build_basic_heap(&mut gc);

        assert_eq!(gc.heap_size(), 5);

        let freed = gc.collect();

        assert_eq!(gc.heap_size(), 4, "D should have been collected");
        assert!(freed.contains(&d), "D must appear in freed list");
        assert!(gc.get_object(d).is_none(), "D should not be on heap");
    }

    #[test]
    fn test_reachable_objects_survive() {
        let mut gc = TriColorGc::new();
        let (root, a, b, c, _d) = build_basic_heap(&mut gc);

        gc.collect();

        for &id in &[root, a, b, c] {
            assert!(gc.get_object(id).is_some(), "{} should survive", id);
        }
    }

    #[test]
    fn test_empty_heap() {
        let mut gc = TriColorGc::new();
        let freed = gc.collect();
        assert!(freed.is_empty());
        assert_eq!(gc.heap_size(), 0);
    }

    #[test]
    fn test_all_roots_survive() {
        let mut gc = TriColorGc::new();
        let a = gc.allocate("A");
        let b = gc.allocate("B");
        gc.add_root(a);
        gc.add_root(b);

        let freed = gc.collect();
        assert!(freed.is_empty());
    }

    #[test]
    fn test_cycle_does_not_prevent_collection() {
        let mut gc = TriColorGc::new();

        // Isolated cycle: X → Y → X (no root)
        let x = gc.allocate("X");
        let y = gc.allocate("Y");
        gc.set_field(x, "next", Value::Ref(y)).unwrap();
        gc.set_field(y, "next", Value::Ref(x)).unwrap();

        // Reachable object
        let root = gc.allocate("root");
        gc.add_root(root);

        let freed = gc.collect();

        assert!(freed.contains(&x) && freed.contains(&y),
                "Cyclic unreachable objects must be collected");
        assert!(gc.get_object(root).is_some());
    }

    #[test]
    fn test_multiple_cycles() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate("root");
        gc.add_root(root);

        // First cycle: some garbage
        let garbage1 = gc.allocate("garbage1");
        let freed1 = gc.collect();
        assert!(freed1.contains(&garbage1));

        // Second cycle: more garbage
        let garbage2 = gc.allocate("garbage2");
        let freed2 = gc.collect();
        assert!(freed2.contains(&garbage2));

        assert_eq!(gc.heap_size(), 1); // only root remains
    }

    #[test]
    fn test_remove_root_causes_collection() {
        let mut gc = TriColorGc::new();
        let a = gc.allocate("A");
        gc.add_root(a);

        gc.collect(); // A survives
        assert!(gc.get_object(a).is_some());

        gc.remove_root(a);
        gc.collect(); // A should now be collected
        assert!(gc.get_object(a).is_none());
    }

    #[test]
    fn test_write_barrier_prevents_loss() {
        let mut gc = TriColorGc::new();

        // root → obj1; obj2 is unreferenced initially
        let root = gc.allocate("root");
        let obj1 = gc.allocate("obj1");
        let obj2 = gc.allocate("obj2");

        gc.set_field(root, "a", Value::Ref(obj1)).unwrap();
        gc.add_root(root);

        // Start an incremental mark — root and obj1 will be shaded
        gc.incremental_begin();
        gc.incremental_step(1); // Process root → obj1 becomes gray
        gc.incremental_step(1); // Process obj1 → obj1 becomes black

        // Now mutate: obj1 (Black) references obj2 (White)
        // The write barrier must shade obj2 gray
        gc.set_field(obj1, "b", Value::Ref(obj2)).unwrap();

        // Verify invariant holds after write barrier
        gc.verify_invariant().expect("Invariant should hold after write barrier");

        // Finish the cycle — obj2 must survive
        let freed = gc.incremental_finish();
        assert!(!freed.contains(&obj2), "obj2 should survive due to write barrier");
    }

    #[test]
    fn test_verify_invariant_clean() {
        let mut gc = TriColorGc::new();
        let root = gc.allocate("root");
        gc.add_root(root);
        gc.collect();
        gc.verify_invariant().expect("Invariant should hold after collection");
    }

    #[test]
    fn test_incremental_gc() {
        let mut gc = TriColorGc::new();

        let root    = gc.allocate("root");
        let child   = gc.allocate("child");
        let garbage = gc.allocate("garbage");

        gc.set_field(root, "child", Value::Ref(child)).unwrap();
        gc.add_root(root);

        gc.incremental_begin();
        while !gc.incremental_step(1) {}
        let freed = gc.incremental_finish();

        assert!(freed.contains(&garbage));
        assert!(gc.get_object(root).is_some());
        assert!(gc.get_object(child).is_some());
    }

    #[test]
    fn test_deep_chain() {
        let mut gc = TriColorGc::new();

        let root  = gc.allocate("root");
        let mut prev = root;
        const DEPTH: usize = 100;

        for i in 0..DEPTH {
            let next = gc.allocate(format!("node_{}", i));
            gc.set_field(prev, "next", Value::Ref(next)).unwrap();
            prev = next;
        }

        gc.add_root(root);
        let freed = gc.collect();

        assert!(freed.is_empty(), "All chained nodes should survive");
        assert_eq!(gc.heap_size(), DEPTH + 1);
    }
}

