}

#[derive(Debug, PartialEq, Clone)]
pub enum Operator {
    Eq,
    NotEq,
    Lt,
    Gt,
    Lte,
    Gte,
    Like,
}

#[derive(Debug, PartialEq, Clone)]
pub enum Condition {
    Comparison { left: Value, op: Operator, right: Value },
    IsNull { value: Value, negated: bool },
    And(Box<Condition>, Box<Condition>),
    Or(Box<Condition>, Box<Condition>),
    Not(Box<Condition>),
}

#[derive(Debug, PartialEq, Clone)]
pub struct OrderByClause {
