// ── Parser ─────────────────────────────────────────────────────────────────────

pub struct Parser {
    tokens: Vec<Token>,
    pos: usize,
}

impl Parser {
    pub fn new(tokens: Vec<Token>) -> Self {
        Self { tokens, pos: 0 }
    }

    fn peek(&self) -> &Token {
        self.tokens.get(self.pos).unwrap_or(&Token::Eof)
    }

    fn advance(&mut self) -> &Token {
        let tok = self.tokens.get(self.pos).unwrap_or(&Token::Eof);
        self.pos += 1;
        tok
    }

    fn expect_keyword(&mut self, kw: &str) -> Result<(), String> {
        match self.advance() {
            Token::Keyword(k) if k == kw => Ok(()),
            tok => Err(format!("Expected keyword '{kw}', got {tok:?}")),
        }
    }

    fn expect_identifier(&mut self) -> Result<String, String> {
        match self.advance().clone() {
            Token::Identifier(name) => Ok(name),
            tok => Err(format!("Expected identifier, got {tok:?}")),
        }
    }

    fn is_keyword(&self, kw: &str) -> bool {
        matches!(self.peek(), Token::Keyword(k) if k == kw)
    }

    // ── Top-level ─────────────────────────────────────────────────────────────

    pub fn parse_select(&mut self) -> Result<SelectStatement, String> {
        self.expect_keyword("SELECT")?;

        let columns = self.parse_columns()?;

        let from = if self.is_keyword("FROM") {
            self.advance();
            Some(self.expect_identifier()?)
        } else {
            None
        };

        let where_clause = if self.is_keyword("WHERE") {
            self.advance();
            Some(self.parse_condition()?)
        } else {
            None
        };

        let order_by = if self.is_keyword("ORDER") {
            self.advance();
            self.expect_keyword("BY")?;
            self.parse_order_by()?
        } else {
            vec![]
        };

        let limit = if self.is_keyword("LIMIT") {
            self.advance();
            match self.advance().clone() {
                Token::NumberLiteral(n) => {
                    Some(n.parse::<u64>().map_err(|e| e.to_string())?)
                }
                tok => return Err(format!("Expected number after LIMIT, got {tok:?}")),
            }
        } else {
            None
        };

        // Consume optional trailing semicolon
        if matches!(self.peek(), Token::Semicolon) {
            self.advance();
        }

        if !matches!(self.peek(), Token::Eof) {
            return Err(format!("Unexpected token after statement: {:?}", self.peek()));
        }

        Ok(SelectStatement { columns, from, where_clause, order_by, limit })
    }

    // ── Columns ───────────────────────────────────────────────────────────────

    fn parse_columns(&mut self) -> Result<Vec<ColumnExpr>, String> {
        let mut cols = vec![self.parse_single_column()?];
        while matches!(self.peek(), Token::Comma) {
            self.advance();
            cols.push(self.parse_single_column()?);
        }
        Ok(cols)
    }

    fn parse_single_column(&mut self) -> Result<ColumnExpr, String> {
        if matches!(self.peek(), Token::Star) {
            self.advance();
            return Ok(ColumnExpr::Wildcard);
        }

        let name = self.expect_identifier()?;

        // Check for table.column syntax
        let (table, col_name) = if matches!(self.peek(), Token::Dot) {
            self.advance();
            let col = self.expect_identifier()?;
            (Some(name), col)
        } else {
            (None, name)
        };

        // Optional alias: AS <identifier>
        let alias = if self.is_keyword("AS") {
            self.advance();
            Some(self.expect_identifier()?)
        } else {
            None
        };

        Ok(ColumnExpr::Column { table, name: col_name, alias })
    }

    // ── WHERE conditions ──────────────────────────────────────────────────────

    fn parse_condition(&mut self) -> Result<Condition, String> {
        self.parse_or()
    }

    fn parse_or(&mut self) -> Result<Condition, String> {
        let mut left = self.parse_and()?;
        while self.is_keyword("OR") {
            self.advance();
            let right = self.parse_and()?;
            left = Condition::Or(Box::new(left), Box::new(right));
        }
        Ok(left)
    }

    fn parse_and(&mut self) -> Result<Condition, String> {
        let mut left = self.parse_not()?;
        while self.is_keyword("AND") {
            self.advance();
            let right = self.parse_not()?;
            left = Condition::And(Box::new(left), Box::new(right));
        }
        Ok(left)
    }

    fn parse_not(&mut self) -> Result<Condition, String> {
        if self.is_keyword("NOT") {
            self.advance();
            let inner = self.parse_primary_condition()?;
            return Ok(Condition::Not(Box::new(inner)));
        }
        self.parse_primary_condition()
    }

    fn parse_primary_condition(&mut self) -> Result<Condition, String> {
        // Parenthesised sub-expression
        if matches!(self.peek(), Token::LeftParen) {
            self.advance();
            let cond = self.parse_condition()?;
            match self.advance() {
                Token::RightParen => return Ok(cond),
                tok => return Err(format!("Expected ')', got {tok:?}")),
            }
        }

        let left = self.parse_value()?;

        // IS [NOT] NULL
        if self.is_keyword("IS") {
            self.advance();
            let negated = if self.is_keyword("NOT") { self.advance(); true } else { false };
            self.expect_keyword("NULL")?;
            return Ok(Condition::IsNull { value: left, negated });
        }

        let op = self.parse_operator()?;
        let right = self.parse_value()?;

        Ok(Condition::Comparison { left, op, right })
    }

    fn parse_operator(&mut self) -> Result<Operator, String> {
        let op = match self.advance() {
            Token::Equals                => Operator::Eq,
            Token::NotEquals             => Operator::NotEq,
            Token::LessThan              => Operator::Lt,
            Token::GreaterThan           => Operator::Gt,
            Token::LessThanOrEqual       => Operator::Lte,
            Token::GreaterThanOrEqual    => Operator::Gte,
            Token::Keyword(k) if k == "LIKE" => Operator::Like,
            tok => return Err(format!("Expected operator, got {tok:?}")),
        };
        Ok(op)
    }

    fn parse_value(&mut self) -> Result<Value, String> {
        match self.advance().clone() {
            Token::StringLiteral(s) => Ok(Value::String(s)),
            Token::NumberLiteral(n) => Ok(Value::Number(n)),
            Token::Keyword(k) if k == "NULL" => Ok(Value::Null),
            Token::Identifier(name) => Ok(Value::Identifier(name)),
            tok => Err(format!("Expected value, got {tok:?}")),
        }
    }

    // ── ORDER BY ──────────────────────────────────────────────────────────────

    fn parse_order_by(&mut self) -> Result<Vec<OrderByClause>, String> {
        let mut clauses = vec![self.parse_order_by_item()?];
        while matches!(self.peek(), Token::Comma) {
            self.advance();
            clauses.push(self.parse_order_by_item()?);
        }
        Ok(clauses)
    }

    fn parse_order_by_item(&mut self) -> Result<OrderByClause, String> {
        let column = self.expect_identifier()?;
        let direction = if self.is_keyword("DESC") {
            self.advance();
            OrderDirection::Desc
        } else {
            if self.is_keyword("ASC") { self.advance(); }
            OrderDirection::Asc
        };
        Ok(OrderByClause { column, direction })
    }
}

// ── Public entry point ─────────────────────────────────────────────────────────

pub fn parse_select(sql: &str) -> Result<SelectStatement, String> {
    let mut lexer = Lexer::new(sql);
    let tokens = lexer.tokenize()?;
    let mut parser = Parser::new(tokens);
    parser.parse_select()
}

