## Key Design Decisions

| Concept | Implementation |
|---|---|
| **Tick rule** | Every local/send event increments by 1 |
| **Receive rule** | `max(local, received) + 1` ensures causal ordering |
| **Total ordering** | Ties broken by `process_id` for determinism |
| **Thread safety** | `Arc<Mutex<>>` wraps shared state |
| **Message queues** | Per-process `Arc<Mutex<Vec<Message>>>` simulates channels |

## Algorithm Properties

- **Consistency**: If `A → B` (A causally precedes B), then `ts(A) < ts(B)`
- **Limitation**: Converse is not guaranteed — concurrent events may have any relative timestamps
- **Extension**: Vector clocks (one counter per process) capture the full partial order

# Skip List Implementation in Rust

A skip list is a probabilistic data structure that allows for fast search, insertion, and deletion with O(log n) average time complexity.

## Implementation

```rust
use std::fmt;
use rand::Rng;

const MAX_LEVEL: usize = 16;
const PROBABILITY: f64 = 0.5;

/// A node in the skip list
struct Node<K, V> {
    key: Option<K>,
    value: Option<V>,
    forward: Vec<Option<*mut Node<K, V>>>,
}

impl<K, V> Node<K, V> {
    fn new(key: Option<K>, value: Option<V>, level: usize) -> *mut Self {
        let node = Box::new(Node {
            key,
            value,
            forward: vec![None; level],
        });
        Box::into_raw(node)
    }
}

/// A skip list data structure supporting O(log n) average operations
pub struct SkipList<K, V> {
    head: *mut Node<K, V>,
    level: usize,
    len: usize,
}

impl<K: Ord + fmt::Debug, V: fmt::Debug> SkipList<K, V> {
    /// Creates a new empty skip list
    pub fn new() -> Self {
        let head = Node::new(None, None, MAX_LEVEL);
        SkipList {
            head,
            level: 1,
            len: 0,
        }
    }

    /// Returns the number of elements in the skip list
    pub fn len(&self) -> usize {
        self.len
    }

    /// Returns true if the skip list is empty
    pub fn is_empty(&self) -> bool {
        self.len == 0
    }

    /// Randomly generates a level for a new node
    fn random_level() -> usize {
        let mut rng = rand::thread_rng();
        let mut level = 1;
        while rng.gen::<f64>() < PROBABILITY && level < MAX_LEVEL {
            level += 1;
        }
        level
    }

    /// Inserts a key-value pair into the skip list.
    /// If the key already exists, updates the value.
    pub fn insert(&mut self, key: K, value: V) {
        let mut update: Vec<*mut Node<K, V>> = vec![self.head; MAX_LEVEL];
        let mut current = self.head;

        // Find the update nodes at each level
        for i in (0..self.level).rev() {
            unsafe {
                while let Some(next) = (*current).forward[i] {
                    match (*next).key.as_ref().unwrap().cmp(&key) {
                        std::cmp::Ordering::Less => current = next,
                        _ => break,
                    }
                }
            }
            update[i] = current;
        }

        // Check if key already exists at level 0
        unsafe {
            if let Some(next) = (*update[0]).forward[0] {
                if (*next).key.as_ref().unwrap() == &key {
                    (*next).value = Some(value);
                    return;
                }
            }
        }

        // Generate a random level for the new node
        let new_level = Self::random_level();

        // If new level is greater than current max, update
        if new_level > self.level {
            for i in self.level..new_level {
                update[i] = self.head;
            }
            self.level = new_level;
        }

        // Create new node and splice into list
        let new_node = Node::new(Some(key), Some(value), new_level);
        unsafe {
            for i in 0..new_level {
                (*new_node).forward[i] = (*update[i]).forward[i];
                (*update[i]).forward[i] = Some(new_node);
            }
        }

        self.len += 1;
    }

    /// Searches for a key and returns a reference to its value if found
    pub fn get(&self, key: &K) -> Option<&V> {
        let mut current = self.head;

        unsafe {
            for i in (0..self.level).rev() {
                while let Some(next) = (*current).forward[i] {
                    match (*next).key.as_ref().unwrap().cmp(key) {
                        std::cmp::Ordering::Less => current = next,
                        _ => break,
                    }
                }
            }

            // Check the node at level 0
            if let Some(next) = (*current).forward[0] {
                if (*next).key.as_ref().unwrap() == key {
                    return (*next).value.as_ref();
                }
            }
        }

        None
    }

    /// Searches for a key and returns a mutable reference to its value if found
    pub fn get_mut(&mut self, key: &K) -> Option<&mut V> {
        let mut current = self.head;

        unsafe {
            for i in (0..self.level).rev() {
                while let Some(next) = (*current).forward[i] {
                    match (*next).key.as_ref().unwrap().cmp(key) {
                        std::cmp::Ordering::Less => current = next,
                        _ => break,
                    }
                }
            }

            if let Some(next) = (*current).forward[0] {
                if (*next).key.as_ref().unwrap() == key {
                    return (*next).value.as_mut();
                }
            }
        }

        None
    }

    /// Returns true if the key exists in the skip list
    pub fn contains_key(&self, key: &K) -> bool {
        self.get(key).is_some()
    }

    /// Removes a key from the skip list, returning the value if it existed
    pub fn remove(&mut self, key: &K) -> Option<V> {
        let mut update: Vec<*mut Node<K, V>> = vec![self.head; MAX_LEVEL];
        let mut current = self.head;

        unsafe {
            for i in (0..self.level).rev() {
                while let Some(next) = (*current).forward[i] {
                    match (*next).key.as_ref().unwrap().cmp(key) {
                        std::cmp::Ordering::Less => current = next,
                        _ => break,
                    }
                }
                update[i] = current;
            }

            // Check if the key exists
            let target = (*update[0]).forward[0]?;
            if (*target).key.as_ref().unwrap() != key {
                return None;
            }

            // Remove node from each level
            for i in 0..self.level {
                if (*update[i]).forward[i] != Some(target) {
                    break;
                }
                (*update[i]).forward[i] = (*target).forward[i];
            }

            // Reclaim memory
            let target_box = Box::from_raw(target);
            let value = target_box.value;

            // Update level
            while self.level > 1 && (*self.head).forward[self.level - 1].is_none() {
                self.level -= 1;
            }

            self.len -= 1;
            value
        }
    }

    /// Returns an iterator over key-value pairs in ascending key order
    pub fn iter(&self) -> SkipListIter<K, V> {
        unsafe {
            SkipListIter {
                current: (*self.head).forward[0],
                _marker: std::marker::PhantomData,
            }
        }
    }

    /// Returns the minimum key-value pair if the list is non-empty
    pub fn min(&self) -> Option<(&K, &V)> {
        unsafe {
            let first = (*self.head).forward[0]?;
            Some((
                (*first).key.as_ref().unwrap(),
                (*first).value.as_ref().unwrap(),
            ))
        }
    }

    /// Returns the maximum key-value pair if the list is non-empty
    pub fn max(&self) -> Option<(&K, &V)> {
        let mut current = self.head;
        unsafe {
            for i in (0..self.level).rev() {
                while let Some(next) = (*current).forward[i] {
                    current = next;
                }
            }
            if current == self.head {
                return None;
            }
            Some((
                (*current).key.as_ref().unwrap(),
                (*current).value.as_ref().unwrap(),
            ))
        }
    }

    /// Clears all elements from the skip list
    pub fn clear(&mut self) {
        unsafe {
            let mut current = (*self.head).forward[0];
            while let Some(node) = current {
                let next = (*node).forward[0];
                drop(Box::from_raw(node));
                current = next;
            }
            // Reset head forward pointers
            for i in 0..MAX_LEVEL {
                (*self.head).forward[i] = None;
            }
        }
        self.level = 1;
        self.len = 0;
    }
}

impl<K: Ord + fmt::Debug, V: fmt::Debug> Default for SkipList<K, V> {
    fn default() -> Self {
        Self::new()
    }
}

/// Iterator over skip list elements
pub struct SkipListIter<'a, K, V> {
    current: Option<*mut Node<K, V>>,
    _marker: std::marker::PhantomData<&'a Node<K, V>>,
}

impl<'a, K: Ord + fmt::Debug, V: fmt::Debug> Iterator for SkipListIter<'a, K, V> {
    type Item = (&'a K, &'a V);

    fn next(&mut self) -> Option<Self::Item> {
        unsafe {
            let node = self.current?;
            self.current = (*node).forward[0];
            Some((
                (*node).key.as_ref().unwrap(),
                (*node).value.as_ref().unwrap(),
            ))
        }
    }
}

impl<K: Ord + fmt::Debug, V: fmt::Debug> fmt::Display for SkipList<K, V> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        writeln!(f, "SkipList (len={}, levels={}):", self.len, self.level)?;
        for level in (0..self.level).rev() {
            write!(f, "Level {}: HEAD", level)?;
            let mut current = self.head;
            unsafe {
                while let Some(next) = (*current).forward[level] {
                    write!(f, " -> {:?}", (*next).key.as_ref().unwrap())?;
                    current = next;
                }
            }
            writeln!(f, " -> NIL")?;
        }
        Ok(())
    }
}

impl<K: Ord + fmt::Debug, V: fmt::Debug> Drop for SkipList<K, V> {
    fn drop(&mut self) {
        self.clear();
        // Free the head sentinel node
        unsafe {
            drop(Box::from_raw(self.head));
        }
    }
}

