}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic_string() {
        assert_eq!(reverse_string("Hello"), "olleH");
    }

    #[test]
    fn test_empty_string() {
        assert_eq!(reverse_string(""), "");
    }

    #[test]
    fn test_single_char() {
        assert_eq!(reverse_string("a"), "a");
    }

    #[test]
    fn test_palindrome() {
        assert_eq!(reverse_string("racecar"), "racecar");
    }

    #[test]
    fn test_with_spaces() {
        assert_eq!(reverse_string("Hello, World!"), "!dlroW ,olleH");
    }

    #[test]
    fn test_unicode() {
        assert_eq!(reverse_string("Hello, 世界"), "界世 ,olleH");
    }

    #[test]
    fn test_emoji() {
        assert_eq!(reverse_string("🦀🔥💻"), "💻🔥🦀");
    }
}
```

## How It Works

| Step | Description |
|------|-------------|
| `.chars()` | Iterates over Unicode scalar values (not bytes) |
| `.rev()` | Reverses the iterator |
| `.collect()` | Collects chars back into a `String` |

## Why `.chars()` Instead of `.bytes()`?

```rust
// ❌ Wrong: Reversing bytes breaks multi-byte Unicode characters
fn reverse_bytes(s: &str) -> String {
    // This would produce invalid UTF-8 for non-ASCII characters
    // String::from_utf8(s.bytes().rev().collect()).unwrap_or_default()
    todo!("Don't do this!")
}

// ✅ Correct: Reversing Unicode scalar values (chars)
fn reverse_string(s: &str) -> String {
    s.chars().rev().collect()
}
```

- **Strings in Rust are UTF-8 encoded** — characters can be 1–4 bytes
- Using `.bytes().rev()` would corrupt multi-byte characters (e.g., `世界` → garbage)
- Using `.chars().rev()` correctly handles all Unicode scalar values

## Alternative: In-Place Reversal

```rust
fn reverse_string_in_place(s: &mut String) {
    let reversed: String = s.chars().rev().collect();
    s.clear();
    s.push_str(&reversed);
}

fn main() {
    let mut s = String::from("Hello, 🦀!");
    reverse_string_in_place(&mut s);
    println!("{}", s); // !🦀 ,olleH
}
```

## Key Takeaways

- **Use `.chars()`** to properly handle Unicode — never reverse raw bytes
- The functional approach (`chars().rev().collect()`) is idiomatic Rust
- Rust's `String` type is always valid UTF-8, so correctness matters

# Prime Number Checker in Rust

## Implementation

```rust
fn is_prime(n: u64) -> bool {
    if n < 2 {
        return false;
    }
    if n == 2 {
        return true;
    }
    if n % 2 == 0 {
        return false;
    }
    if n == 3 {
        return true;
    }
    if n % 3 == 0 {
        return false;
    }

    // Check divisors of the form 6k ± 1 up to √n
    let mut i = 5u64;
    while i * i <= n {
        if n % i == 0 || n % (i + 2) == 0 {
            return false;
        }
        i += 6;
    }

    true
}

fn main() {
    let test_cases = vec![
        0, 1, 2, 3, 4, 5, 10, 13, 17, 20, 97, 100, 7919, 7920,
    ];

    println!("{:<10} {}", "Number", "Prime?");
    println!("{}", "-".repeat(20));

    for &n in &test_cases {
        println!("{:<10} {}", n, is_prime(n));
    }
}
```

## Output

```
Number     Prime?
--------------------
0          false
1          false
2          true
3          true
4          false
5          true
10         false
13         true
17         true
20         false
97         true
100        false
7919       true
7920       false
```

## How It Works

The algorithm uses several optimizations:

| Step | Optimization | Why |
|------|-------------|-----|
| `n < 2` | Early return `false` | Primes are defined for n ≥ 2 |
| `n == 2` or `n == 3` | Early return `true` | Handle small primes explicitly |
| `n % 2 == 0` | Early return `false` | Eliminates all even numbers |
| `n % 3 == 0` | Early return `false` | Eliminates multiples of 3 |
| `6k ± 1` loop | Only check `i` and `i+2` | All primes > 3 have the form 6k ± 1 |
| `i * i <= n` | Loop to √n only | If n has a factor > √n, it must also have one < √n |

